INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_131529','До Святого Миколая','(Ой, хто, хто Миколая любить). Українська народна пісня. Виконує: Жайворонок, невідомий виконавець','uk','ukraine_before_1917',NULL,NULL,'1. Нам пора для України жить: Шкільний співаник.- Дрогобич: Відродження, 1991.- 128 с.','Класичний варіант подано за джерелом 1 без змін. Сучасний спрощений варіант подано за джерелом 2 з виправленнями. Зустрічаються й інші варіанти тексту пісні.','Класичний варіант:

Ой, хто, хто Миколая любить,
Ой, хто, хто Миколаю служить,
Тому святий Миколай,       |
На всякий час помагай,     |(x2)
Миколай!                   |

Ой, хто, хто к ньому прибігає,
На поміч його призиває,
Той все з горя вийде ціло, |
Охоронить душу й тіло,     |(x2)
Миколай!                   |

Ой, хто, хто спішить в Твої двори,
Сего Ти на землі і в морі
Все хорониш від напасти,   |
Не даєш му в гріхи впасти, |(x2)
Миколай!                   |

Миколай, молися за нами,
Благаєм Тебе зі сльозами.
Ми Тя будем вихваляти,     |
Ім''я Твоє величати,        |(x2)
На віки.                   |

Сучасний спрощений варіант:

Ой, хто, хто Миколая любить,
Ой, хто, хто Миколаю служить,
Тому святий Миколай      |
На всякий час помагай,   |(x2)
Миколаю.                 |

Ой, хто, хто спішить в Твої двори,
Того Ти на землі і в морі
Все хорониш від напасти, |
Не даєш йому пропасти,   |(x2)
Миколаю.                 |

Миколаю, молися за нами,
Благаєм Тебе зі сльозами.
Будем Тебе величати,     |
Ім''я Твоє величати,      |(x2)
Миколаю.                 |','["pisni.org.ua", "cat:christian", "cat:narodni", "cat:svyatyy-mykolay", "Пісні на християнську тематику", "Народні пісні", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_131529'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_131529','До Святого Миколая','Класичний варіант:

