INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1304828','Доброта Миколая','Музика: Єва Новіцька, Евеліна Горяк','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Розступилась дрімота,
Ходить світом доброта.
Ані смутку, ні журби не знає.
Де природа золота,
Сіє спокій доброта,
А де люди, там серця єднає...

Приспів:
Доброта, доброта
Добротою день і ніч обіймає,
Доброта, доброта,
Ходить світом доброта Миколая.
Доброта, доброта
Добротою день і ніч обіймає
Доброта, доброта,
Ходить світом доброта Миколая...

Розступилась дрімота,
Ходить світом доброта.
Не минає ні води, ні суші.
Усміхніться доброті всі,
Хто є на цій землі,
Хай зігріє вам серця і душі...

Приспів.

Ходить світом доброта Миколая...','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1304828'), datetime('now')),datetime('now'));
