INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1328505','Урвалася струна','Українська народна пісня. Виконує: Rock-H (Рокаш)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Урвалася струна, што май файно гула,
Оддалася тота дівка, што май файна була.
Загудеме, загудеме тай дружбовий таниць,
Бо її дівоцтву ниська вичур кониць.

Дівка була дівка, не було юй пари,
Так за ньов йшли хлопці, ги дождьові хмари.
Айбо тоті хмари не мож полічити,
Айбо ту паранну дівку не мож не любити.

Вчора бола дівка, а типирь жона,
Вчора мала коси, а типирь нема!
Вчора бола дівка, а типирь жона,
Вчора мала коси, а типирь нема!

Дівка була ружа, личко рум''яноє,
Ізводила хлопцям життя молодоє.
Дівка бола дівка, не боло юй пари,
Так за ньов йшли хлопці, як дождьові хмари.','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1328505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1328505','Урвалася струна','Урвалася струна, што май файно гула,
Оддалася тота дівка, што май файна була.
Загудеме, загудеме тай дружбовий таниць,
Бо її дівоцтву ниська вичур кониць.

Дівка була дівка, не було юй пари,
Так за ньов йшли хлопці, ги дождьові хмари.
Айбо тоті хмари не мож полічити,
Айбо ту паранну дівку не мож не любити.

Вчора бола дівка, а типирь жона,
Вчора мала коси, а типирь нема!
Вчора бола дівка, а типирь жона,
Вчора мала коси, а типирь нема!

Дівка була ружа, личко рум''яноє,
Ізводила хлопцям життя молодоє.
Дівка бола дівка, не боло юй пари,
Так за ньов йшли хлопці, як дождьові хмари.');
