INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_132101','Через Річеньку через Болото','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Еротика: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Правой ручкою обняла ще й поцілувала. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні.','Через Річеньку через Болото
Подай рученьку Моє Золото
Подай рученьку подай другую
Подай личенько я й поцілую

Через Річеньку через Місточок
Подай рученьку на голосочок
І при Сонечку і серед Ночі
Подай устоньки покажи очі

Ой ти Дівчино деньочки губиш
Сама не знаєш кого Ти любиш
Ой знаю-знаю кого кохаю
Тільки не знаю з ким жити маю','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_132101'), datetime('now')),datetime('now'));
