INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_131828','Ой вийду я за Ворота - Грушка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво „Павутинонька“, Нью Йорк – Львів – Київ – Харків – Москва, 2002','Пара — любощі: Ворота-Грушка. Еротика, жарти, забави: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... Там Мою Грушечку час трясти. Читати листки, де є згадка з приводу цієї Пісні: Еротичні містерії, Катерини 7.12 — Передріздвяний Святочний час. Еротичні містерії, Калета 13.12 — Передріздвяний Святочний час. Стежки до інших листків про Українські пісні. Ой вийду я за Ворота – Грушка -->','Гурт Дівчат співаючи стає півколом.
Одна Дівчина-Грушечка стає окремо і рухами показує слова Гаївки.
Як садять дерево — копає, як його поливають, як воно росте — підносить руки вгору,
як цвіте та родить — робить кола над головою, як його трусять, як приносять грушки Милому.

Ой вийду я за Ворота
Свою Грушку посаджу-посаджу Буде Гай !

Ой вийду я за Ворота
Свою Грушку піділлю-піділлю Буде Гай !

Ой вийду я за Ворота
Моя Грушка вироста вироста Буде Гай !

Ой вийду я за Ворота
Моя Грушка вже цвіте вже цвіте Буде Гай !

Ой вийду я за Ворота
Моя Грушка зродила-зродила Буде Гай !

Ой вийду я за Ворота
Свою Грушку обтрясу-обтрясу Шумить Гай !

Ой вийду я за Ворота
Грушку Милому несу Шумить Гай !','["pisni.org.ua", "cat:vesnyanky-hayivky", "Веснянки та гаївки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_131828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_131828','Ой вийду я за Ворота - Грушка','Гурт Дівчат співаючи стає півколом.
