INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1324303','Дядько Йосип','Музика: Олександр Смик Слова: Олександр Смик. Виконує: Володимир Вермінський','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Весілля з вечора до ранку,
Ще наші звичаї живі
Заграли хлопці музиканти,
Готуй весільні маршові!

Приспів:
А дядько Йосип, горілку носить,
Старий весільний тамада,
Підняти келихи попросить
Вся Україна молода!

На веселковім рушникові
Порозі спільного життя
Батьки зустрінуть добрим словом,
Дадуть поради до путя!

Приспів.

Підносять хліб та сіль, по тому
І молодята ділять хліб,
Хто головою буде в домі,
Ну, а кому дітей глядіть!

Приспів.

Хмільні слова гостям на радість
І поцілунки без кінця,
Така проста весільна правда,
Коли єднаються серця.

Приспів.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1324303'), datetime('now')),datetime('now'));
