INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_132426','Ішов Миколай','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Журнал „Зернятко”, число 10 (45) 2004',NULL,'Ішов Миколай лужком-бережком.
Святий Миколай із повним мішком.
Приспів:
Від хати до хати біленьким сніжком |
A              D         D7      |(x2)
ішов Миколай із повним мішком.     |
Святий Миколай до діток ходив.
Всміхався, вітався, в дзвіночок дзвонив.
Приспів.
Тяжкий і великий у нього мішок.
А в ньому дарунки для чемних діток.
Приспів.
Ішов, усміхався крізь темну пітьму.
А зіроньки з неба світили йому.
Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:svyatyy-mykolay", "Дитячі пісні", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_132426'), datetime('now')),datetime('now'));
