INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_13323','Ой там зажурились стрільці січовії','Музика: Роман Купчинський Слова: Роман Купчинський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'1. Як з Бережан до Кадри. Стірлецькі пісні Романа Купчинського. Упор. В.Подуфалий. Тернопіль, 1990','* варіант: впаде вража міць лукава','Ой там зажурились стрільці січовії,
Як Збруч-річку проходили,
Що стільки народу впало за свободу,  |
Встояти не було сили.                | (2)

Ой там зажурились стрільці січовії,
Стали дрібні сльози лити.
Буде ворог клятий батьками орати,   |
Матерями волочити.                   | (2)

Ой не тішся, враже, що по Збруч, то наше,
Ще живе стрілецька слава.
Вернуться ще тії стрільці січовії,   |
Задрижить Москва й Варшава. *        | (2)','["pisni.org.ua", "cat:strilecki", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_13323'), datetime('now')),datetime('now'));
