INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1331505','Гей, озовись, трембіто! (інший варіант)','Музика: Леопольд Ященко Слова: Леопольд Ященко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Гей, озовись, трембіто!
Гей, зашуми, смереко!
Знову доріженька
Попід зелен гай
Нас поведе далеко!

Гей, прощавайте, гори,
Сині мої Карпати!
Гей, як я поїду
В дальню сторону,
Хто ж буде вам співати?

Гей, заспіває мила
Та, що мене любила.
Гей, як я поїду
В дальню сторону,
Буде слізоньки лила...

Гей, не гнівись, козаче,
Бо не буду, не буду.
Гей, як ти поїдеш
В дальню сторону,
Я за тебе забуду!

Гей, а коли згадаю,
То не скажу нікому.
Гей, тоді пізнаєш,
Мій милесенький,
Як повернеш додому.','["pisni.org.ua", "cat:manrivni", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1331505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1331505','Гей, озовись, трембіто! (інший варіант)','Гей, озовись, трембіто!
Гей, зашуми, смереко!
Знову доріженька
