INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1331529','В далеку дорогу рушати час',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис','Мелодія з англійської народної пісні "When Johnny Comes Marching Home".','В далеку дорогу рушати час - пора! Пора!
І знову пригоди чекають нас - ура! Ура!
Гей, гей, товариство, збираймо всіх,
Візьмемо пісень із собою міх -
І нехай дорога стелиться нам до ніг!

Як насупиться хмара,
Ударить грім - дарма, дарма!
Хоч місця сховатися нам усім нема, нема,
Та нас не злякає ні дощ, ні сніг,
Бо наше тепло - то веселий сміх,
І нехай дорога стелиться нам до ніг!

Як не стане харчів - не біда,
Проживем чи так, чи сяк.
Зголоднієш - терпи,
Бо на те ж ти таки козак, козак!
Як знайдем на дорозі один горіх,
То розділим його по шматку на всіх -
І нехай дорога стелиться нам до ніг!

А як знову колись
Надокучать нам діла, діла,
І як стане нам вулиця
Тут і там мала, мала,
То підемо шукати доріг нових,
І нас знову не спинить ні дощ, ні сніг,
І нехай дороги стеляться нам до ніг!','["pisni.org.ua", "cat:manrivni", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1331529'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1331529','В далеку дорогу рушати час','В далеку дорогу рушати час - пора! Пора!
І знову пригоди чекають нас - ура! Ура!
Гей, гей, товариство, збираймо всіх,
Візьмемо пісень із собою міх -
І нехай дорога стелиться нам до ніг!

Як насупиться хмара,
Ударить грім - дарма, дарма!
Хоч місця сховатися нам усім нема, нема,
Та нас не злякає ні дощ, ні сніг,
Бо наше тепло - то веселий сміх,
І нехай дорога стелиться нам до ніг!

Як не стане харчів - не біда,
Проживем чи так, чи сяк.
Зголоднієш - терпи,
Бо на те ж ти таки козак, козак!
Як знайдем на дорозі один горіх,
То розділим його по шматку на всіх -
І нехай дорога стелиться нам до ніг!

А як знову колись
Надокучать нам діла, діла,
І як стане нам вулиця
Тут і там мала, мала,
То підемо шукати доріг нових,
І нас знову не спинить ні дощ, ні сніг,
І нехай дороги стеляться нам до ніг!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1337808','Йде весна!','Музика: Ярослава Притула (Slavia) Слова: Ярослава Притула (Slavia). Виконує: Ярослава Притула','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Покотились води з горів,
Зашуміли річки в долі,
Журавлі летять додому,
Земле, оживай.
Ліс ожив зазеленівся,
Соловейко пробудився,
Та й виводить свої трелі -
Це моя весна!

Ой, мамо, мамо, мамо, мамо, |
Йде весна!..                | (4)

Дівка квітів назбирала,
У віночок посплітала,
Милому подарувала
Цвіт красу весни.
Набирайся земле сили
Щщоби ми ще краще жили,
Нене моя, Україно -
Мій тобі уклін!

Ой, мамо, мамо, мамо, мамо, |
