INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1337808','Йде весна!','Покотились води з горів,
Зашуміли річки в долі,
Журавлі летять додому,
Земле, оживай.
Ліс ожив зазеленівся,
Соловейко пробудився,
Та й виводить свої трелі -
Це моя весна!

Ой, мамо, мамо, мамо, мамо, |
Йде весна!..                | (4)

Дівка квітів назбирала,
У віночок посплітала,
Милому подарувала
Цвіт красу весни.
Набирайся земле сили
Щщоби ми ще краще жили,
Нене моя, Україно -
Мій тобі уклін!

Ой, мамо, мамо, мамо, мамо, |
Йде весна!..                | (6)');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1337808_l1','pisniua_1337808','YouTube','https://www.youtube.com/watch?v=sKDlnaaDutw','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1333909','Повір у казку','Музика: Сергій Родько Слова: Алла Бінцаровська. Виконує: Ірина Новомлинська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Щось шепоче вогонь в каміні
І потріскує жартома,
За вікном білий-білий іній -
Це чарує сама зима!
Промінь зоряно палахкоче,
Цілий світ він від сну збудив,
Знаю я, що цієї ночі
Кожне серце чекає див!

Приспів:
А казка поряд, - її побачиш
У срібних зорях,
В очах дитячих!
Така щаслива зимова казка!
Повір у диво!
Повір, будь ласка!

Місяць стразами вишиває
Дивний килим небесний свій,
В наші долі немов вплітає
Він перлини нових надій!
А сніжинки летять поволі,
Тихо танучи між вогнів,
Залишали, щоб мимоволі,
Нас образи минулих днів!

Приспів. (2)

Повір у казку!..','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1333909'), datetime('now')),datetime('now'));
