INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1335404','Родина','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Найбільше щастя для дитини -
Щаслива, дружняя родина!
Коли зі мною мама й тато
Мені від щастя хочеться співати!

Приспів:
Дякую, мамо, дякую, тато,
За вашу любов,
На яку ви багаті!
Дякую щиро вам за добро,
Вашого серця тепло!

За сонце в небі голубому,
За стежку, що веде додому,
Вклонюся низько, щоб сказати,
Як я люблю вас, мамо й тато!

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:pro-batkiv", "Дитячі пісні", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1335404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1335404','Родина','Найбільше щастя для дитини -
Щаслива, дружняя родина!
