INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_133909','Коляд Коляд Колядниця (3)','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Тексти ймовірно літературного походження, під впливом західно-європейських традицій (римські карнавали). Короткі "Дитячі колядки" з наведеним найпростішим наспівом, або виконані говіркою, зустрічаються майже в кожному селі на Слобожанщині. Радуйся Земле Коляда іде! Листки з приводу цієї Пісні: Співаймо Світові-Дитині: Колядки, Щедрівки, Колискові... Що означає ім''я "Коляда"? Українське Різдво Світа: Співаймо Колядки й Щедрівки на Щастя-Здоров''я! (Стародавні Колядки й Щедрівки з нотами і звуковими зразками — Мереживний Збірник) Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (: Свят-Вечір – Коляда) ― Святий Збір () ― Щедрий Вечір (Свято Місяця й Прадіда: ― Святі Водорщі) ―: Дівич-Вечір...... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива.... Доба мистецьких і наукових містифікацій? "Вертеп", що це таке? Замінювали народні пісні схоластичними віршами школи. "Отрадный результат нашего движения к коммунистическому обществу".','Коляд-коляд-колядниця !
Добра з Медом Паляниця
А без Меду не така

Дайте Дядьку П''ятака
А ви Тітко Гривну
А то в Хаті гримну !

Коляд-коляд-колядин
Я у Батька один
Мене Батько послав
Щоб я грошей дістав
Рукавички потіряв
Чорненький Кожушок
Дайте Тьотю Шеляжок !

Коляд-коляд-колядниця
Добра з Маком Паляниця
А пісна не така
Дайте Дядьку П''ятака
Як не дасте П''ятака
Візьму Вола за Рога
А Кобилу за Чуприну
Дай виведу на Могилу
Тпру-тпру на Баси
Дайте Дядьку Ковбаси
Сіни й Хату рознесу
Соломкою притрушу
Камінчиком придавлю !','["pisni.org.ua", "cat:dytyachi", "cat:narodni", "cat:zhartivlyvi", "Дитячі пісні", "Народні пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_133909'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_133909','Коляд Коляд Колядниця (3)','Коляд-коляд-колядниця !
