INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_133909_l1','pisniua_133909','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1338404','Я прикрию!','Музика: Христина Панасюк Слова: Христина Панасюк. Виконує: Христина Панасюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я прикрию, брате! Чуєш, я прикрию!
Я не дам занапастити свій народ!
Бо Україна вільна - наша світла мрія,
На шляху до мрій не буде перешкод!
Я прикрию, брате! Чуєш, не здавайся!
Неможливе зробим за життя твоє,
Як по рації почуєш: "Пригинайся!"
Знай, твій брат не забуває, що ти є!

Приспів:
Потрійний залп реве метал,
Вогонь здіймається у вись,
А в серці: "Так тебе люблю!
Додому швидше повернись!"
Я повернусь, лише чекай
І міцно маму обіймай.
Знов артадбій, гуде земля,
Твоя земля, свята земля.

Десь різьбу стирають втомлені снаряди,
Десь крізь сон лунає триста тридцять три,
А земля пропахла порохом і димом,
Та не спинять ні морози, ні вітри.
Не здавайся! Чуєш, я прикрию, брате!
Я з тобою, чуєш! Рук не опусти!
В нас одна з тобою Україна-мати
І ми тут, щоб її волю зберегти!

Приспів.','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1338404'), datetime('now')),datetime('now'));
