INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_134505','Го-го-го Коза го-го Сірая го-го Білая','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Де Коза ходить, там Жито родить! © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Еротика, жарти, забави, загадки: Катерини – Калета – Андрія... Зелені Свята... Гаївки-Великдень... Весілля... – Щедровечірнє й Новорічне: Маланка й Василь. Коза. Кіт... Українська Святочна установа Колядників походить з далеко старших часів, чим Римські та інші маскаради, які всі суть орієнтовані на культ Сонця і належать до пізнішого, вторинного, культурно-історичного округа. Українські ходження з Козою є зовсім іншого типу — і в них " Берези " нема. Вони належать передовсім до обрядів Новорічних і Щедровечірніх та лиш через перемішання з Різдвяними увійшли в Різдвяний час і мають свою власну мітологійну орієнтацію й характеристику. Де Коза ходить там Жито родить! Го-го-го Коза го-го Сірая го-го Білая Де Коза xодить там Жито родить Де Коза ходить там Жито родить (2) Козуню-Любуню пристань до мене Ми не самі йдем ми Козу ведем Нуте Панове нуте Мурове Ой Гор-гор-гора ой Гор-гор Крута Ой Добрий Вечір до сеї Xати Топ Козуню топ до Гори підскок Рокове Коло. Стежки до листків про Українські традиції. Староукраїнські Колядки і Щедрівки: Святе Різдво (Свято Різдва Світа: Свят-Вечір – Коляда) ― Святий Збір (Трійця) ― Щедрий Вечір (Свято Місяця й Прадіда: Новий Рік ― Святі Водорщі) ― Весілля: Дівич-Вечір... Великдень... Зелені Свята (Трійця) ― Царинні Містерії... Івана Купала... Астральні Жнива... Рокове Коло.','Го-го-го Коза го-го Сірая го-го Білая
Ой розxодися-розвеселися
По сьому Двору по Веселому!

Де Коза xодить там Жито родить
Де не буває там вилягає!

Де Коза ногою там Жито Копою
Де Коза рогом там Жито Стогом!

А в Михайлівці всі Хлопці-Стрільці
Стрелили Козу в правеє вушко
В правеє вушко в саме сердечко

Пуць Коза впала нежива стала
А Міxоноша бере Дудочку
Надима Козі тай у Жилочку!

Надулась Жила Коза ожила!
Тай пішла Коза тай стрибаючи
Тай гасаючи своїx Діточок тай шукаючи!','["pisni.org.ua", "cat:dytyachi", "cat:zhartivlyvi", "Дитячі пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_134505'), datetime('now')),datetime('now'));
