INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1341127','Ой, зійшла, зійшла',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ой, зійшла, зійшла Правда на землю
Та й обітала там між людьми.
Все розказала, що треба людям,
Як треба жить, як Бог велить.

Приспів:
Де ж тая Правда, звідки з''явилась?
Де ж вона нині на світі є?
Там в Вифлеємі в яслах родилась,
А тепер в вірних серцях живе.

Христос є Правда, Христос є Світло,
Христос є Хліб життя для нас.
О, якби люди зі всього світу
Прийшли до Нього, Він би їх спас.

Приспів.

І Дух Святий, і Правда із неба
Шукають собі в серцях ясел,
Щоб поселитись, щоби родити
Плоди Правди в серцях людей.

Приспів.

І в кому знайдуть місце для себе,
Там запанує радість свята,
Тому дарують місце на небі
Та й помагають нести хреста.

Приспів.    Фонограма-мінус (mp3, 320 kbps)  (','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1341127'), datetime('now')),datetime('now'));
