INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_134202','Сійся-родися Жито-Пшениця','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Пасла Маланка Два Качура Роди Боже Жито й Пшеницю. Символіка Щедрого Вечера і Василя. Щедрий Вечер, 13-14 січня, зачинається властиво під Новий Рік (7 днів наперед Богоявління — символ Місячний!), т. є. в вечер перед св. Василя. Це особливо улюблене Українське свято: мітичного Василя і Маланки, — є найщирішим шануванням Місяця з його женихальними мотивами (ними переповнені Щедрівки). Тоді мітичну постать Василя мішають часто з мітольоґійно-Місячною постаттю Іллї — Ілії, який є в Українського народу покровителем урожаїв збіжжя, особливо жита (сніп жита, дід Ілля, — в часі жнив, — це постава Місяця). Стежки до інших листків про Українські традиції.','Відміна 1:

Сійся-родися Жито-Пшениця
Всяка Пашниця
Коноплі під Стелю
І Лен по коліна!

Щоб Вас ніколи голова не боліла
Щоб була у Вас завжди Радість і Втіxа
Щоб Ваша Хата не знала лиxа
Xай Добро і Щастя Вас не минає
Щедрість і Ласка всіx звеселяє!

Відміна 2:

Сійся-родися Жито-Пшениця
Сійся-родися Жито-Пшениця
Всяка Пашниця
Зверху Колосиста зісподу Корениста
Будьте з Святом здорові
З Новим Роком!

Відміна 3:

Сійся родися Жито Пшениця !
Сійся-родися Жито Пшениця !
На Щастя на Здоров''я на цей Новий Рік
Щоб Вам вродилося як торік
Коноплі до Стелі щоб було Дома весело
Льон по коліна щоб у Вас голова не боліла !','["pisni.org.ua", "cat:kolyadky", "cat:narodni", "cat:shchedrivky", "Колядки", "Народні пісні", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_134202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_134202','Сійся-родися Жито-Пшениця','Відміна 1:

Сійся-родися Жито-Пшениця
Всяка Пашниця
Коноплі під Стелю
І Лен по коліна!

Щоб Вас ніколи голова не боліла
Щоб була у Вас завжди Радість і Втіxа
Щоб Ваша Хата не знала лиxа
Xай Добро і Щастя Вас не минає
Щедрість і Ласка всіx звеселяє!

Відміна 2:

Сійся-родися Жито-Пшениця
Сійся-родися Жито-Пшениця
Всяка Пашниця
Зверху Колосиста зісподу Корениста
Будьте з Святом здорові
З Новим Роком!

Відміна 3:

Сійся родися Жито Пшениця !
Сійся-родися Жито Пшениця !
На Щастя на Здоров''я на цей Новий Рік
Щоб Вам вродилося як торік
Коноплі до Стелі щоб було Дома весело
Льон по коліна щоб у Вас голова не боліла !');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1354606','Диво-осінь','Музика: Анна Олєйнікова Слова: Лариса Ратич','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Анастасія Боднарчук.','Гарні дні, ласкаве диво,
Осінь тепла, золота!
Кольорове і красиве
Листя тихо обліта.

Приспів:
Осінь, осінь, осінь,
Ти - ласкава казка!
І в осінню днину
Годі сумувать!
Осінь, осінь, осінь,
Ти - остання ласка!
Здрастуй, диво-осінь! -
Буду я співать!

Сонечко ще гріє добре
І гуляють дітлахи,
Та летіти ген, за обрій,
Вже збираються птахи...

Приспів.

Птах летить в краї далекі,
Осінь каже: В добру путь!
До побачення, лелеко,
Повернутись не забудь!..

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1354606'), datetime('now')),datetime('now'));
