INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_135426','По Горі Горі Пави ходили','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Співаймо Світові-Дитині © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Стародавні Колядки-Щедрівки: Українські Різдво Світа і Щедрий Вечір. Десь узялася Молода Дівчина. Павочка xодить Пір''ячко губить. До Церкви ішла як Зоря зійшла. Чи Ти Царівна чи Ти Королівна. По Горі Горі Пави ходили Листки з приводу цієї Пісні: Колядки як Українські релігійні роздуми про Бога. Ой стояла Липка Тонка та Висока Стежки до листків про Українські традиції.','По Горі Горі Пави ходили
Приспів: Святий Вечір!

Пави ходили Пір''я губили
Красная Панна Пір''я збирала
Пір''я збирала в Рукавець клала
З Рукавця брала Віночок плела

При Одній Свічці умивалася
При Другій свічці утиралася
А убравшись до Церкви ішла
До Церкви ішла як Зоря зійшла
Здибають Її Пани Королі
Її здибають Її питають
Чи Ти Царівна чи Ти Королівна
Ні я Царівна ні Королівна
Батькова Дочка як Паняночка

По Горі-горі Пави ходили
Ой дай Боже!*

Пави ходили Піря губили
Красная Панна Піря збірала
Піря збірала в Рукавець клала
З Рукавця брала Віночок плела

При Одній свічцї умивалася
А при Другій утиралася
А убравши ся до Церкви йшла
До Церкви йшла як Зоря зійшла

Здибають Її Пани-королї
Її здибають Шапки здіймають
Шапки здіймають Її питають
Чи Ти Царівна чи Королївна
Нї я царівна нї королївна
Батькова Дочка як Паняночка','["pisni.org.ua", "cat:shchedrivky", "Щедрівки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_135426'), datetime('now')),datetime('now'));
