INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_136606','За горою кам''яною','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Веснянки. Українські народні пісні. - К.: Музична Україна, 1988. С. 44.',NULL,'За горою кам''яною, да рано, рано,
За горою кам''яною, да ранесенько.

Там бояре терем вили, да рано, рано,
Там бояре терем вили, да ранесенько.

У три стіни кам''янії, да рано, рано,
У три стіни кам''янії, да ранесенько.

Четвертая золотая, да рано, рано,
Четвертая золотая, да ранесенько.

