INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1366323','Ой, леле, леле','Слова: Назар Незнаний','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує тріо священників "Новий Час".','Ой, леле, леле, - голосила стиха,
Над знятим нахилившися Марія,
Курликала, немовби журавлиха,
Чий син - журавлик відлетів у вирій.

Приспів:
Плакала, ридала, голосила,
Як голубка сива крильми била.
Ой, леле, леле, доле моя, доле, -
Все не стихала пісня журавлина, -
Ой, терен, терен серце моє коле, -
За Ним у вирій пісня її лине...

Ой, журу, журу, - жебоніла стиха
І слала пісню, слала сльози слідом, -
О, леле, леле, наздогнало лихо, -
Курличе тихо, - бідо моя, бідо!..

Приспів.','["pisni.org.ua", "cat:strasni", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1366323'), datetime('now')),datetime('now'));
