INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1363024','Плакала','Музика: Сергій Єрмолаєв, Андрій Ігнатченко Слова: Сергій Локшин. Виконує: КАZКА','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Врятуюсь від слів твоїх - буду ціла,
За рік образ не складу ціну я.
Горять мости, горять і сліз моря,
Та знай, це гра моя -
Менш слів, більше діла!
Врятую від стріл твоїх хоч би тіло,
Загнав під лід, не знайду душу я.
Болить, ой, як болить, і кров кипить
Та донька вже не спить,
Менше слів, більше діла.

Приспів:
Поплакала і стоп! Фіалка розцвіла,
Засяяв день таємними знаками...
І мама молода й закохана мала
На кухні всі однаково плакали...

Зотліла ніч, зранку все стало сіре,
Знайти нові кольори мушу я.
Лице умий дощем, що треба ще?
Дай серцю під плащем
Менше слів, більше віри!

Приспів. (2)','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1363024'), datetime('now')),datetime('now'));
