INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_136024','Ой літа орел','Музика: Кирило Стеценко Слова: Тарас Шевченко. Виконує: Василь Жданкін, Ансамбль Орфей, Рушничок, Тарас Житинський, Василь Лютий, Національна капела бандуристів України імені Г.Майбороди','uk','ukraine_before_1917',NULL,NULL,'1. Кобзар. 2. Туристський пісенник "Де гори Карпати, де Писаний Камінь". - Літо, 1982. 3. Плавай, плавай, лебедонько. - К.: Музична Україна, 1989. С. 62.','*Оригінальний текст Тараса Шевченка. Текст пісні - уривок з думи, вкладеної Тарасом Шевченком в уста кобзаря в поемі "Гайдамаки".','Ой літа орел, літа сизий
Попід небесами;
Гуля Максим, гуля батько    |
Степами, лісами.            |(2)
Ой літа орел, літа сизий,
А за ним орлята;
Гуля Максим, гуля батько,   |
А за ним хлоп''ята.          |(2)
Шануйтеся ж, вражі пани,
Скажені собаки:
Йде Залізняк Чорним шляхом, |
За ним гайдамаки.           |
Акорди:
Ой літа орел, літа сизий
Попід небесами;
Гуля Максим,  гуля батько   |(2)
Степа___ми, лісами.         |
Літа орел, літа сизий
Попід небесами;
Гуля Максим, гуля батько
Степами-лісами.
Ой літає орел сизий,
А за ним орлята;
Гуля Максим, гуля батько,
А за ним хлоп''ята.
Запорожці ті хлоп''ята,
Сини його, діти, —
Поміркує, загадає,
Чи бити, чи пити,
Чи танцювать; то й ушкварять,
Аж земля трясеться.
Заспіває — заспівають,
Аж лихо сміється.
Горілку, мед не чаркою —
Поставцем черкає,
А ворога, заплющившись,
Ката, не минає.
Отакий-то наш отаман,
Орел сизокрилий!
І воює, і гарцює
З усієї сили —
Нема в його ні оселі,
Ні саду, ні ставу...
Степ і море; скрізь битий шлях,
Скрізь золото, слава.
Шануйтеся ж, вражі ляхи,
Скажені собаки:
Йде Залізняк Чорним шляхом,
За ним гайдамаки.*','["pisni.org.ua", "cat:dumy", "cat:istorychni", "Думи", "Історичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_136024'), datetime('now')),datetime('now'));
