INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1357622','Сорока-ворона','Музика: Олександр Шевченко Слова: Зоряна Лісевич','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Оля Бандура ("Фора").','Сорока-ворона
Діткам кашку варила,
Кашку із манки
Діткам до сніданку.
Ополоником мішала,
Хвостиком накривала
Кашку із манки,
Діткам до сніданку.

В миски накладала,
Діток годувала:
Цьому дала, й цьому,
Тому і тамтому!
А одно не захотіло -
Фур, і полетіло!

Сорока-ворона
Діткам кашку варила,
Кашку вівсяну
Рано-спозарана.
Ополоником мішала,
Хвостиком накривала
Кашку вівсяну
Рано-спозарана.

В миски накладала,
Діток годувала:
Цьому дала, й цьому,
Тому і ще тому!
А одно не захотіло -
Фур, і полетіло!

Сорока-ворона
Діткам кашку варила,
Кашку пшоняну
Рано-спозарана.
Ополоником мішала,
Хвостиком накривала
Кашку пшоняну
Рано-спозарана.

В миски накладала,
Діток годувала:
Цьому дала, й тому,
А більше нікому!
А одно не захотіло -
Фур, і полетіло!

Сорока-ворона
Діткам кашку варила,
Кашку гречану
Рано-спозарана.
Ополоником мішала,
Хвостиком накривала
Кашку гречану
Рано-спозарана.

В миски накладала,
Діток годувала.
Дала кашку у горнятку
Та й найменшому дитятку,
А дитятко кашку з''їло -
Фур, і полетіло!','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1357622'), datetime('now')),datetime('now'));
