INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1368404_l2','pisniua_1368404','YouTube','https://www.youtube.com/watch?v=IcB6wPLeixc','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_136323','Ой, Морозе, Морозенку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Струни серця. Українські народні пісні про кохання. Київ, Держлітвидав, 1969.',NULL,'Ой, Морозе, Морозенку,
Ой, да Ти славний козаче!
За тобою, Морозенку,   |
Вся Вкраїна плаче.     | (2)

Ой, не так же Україна,
Як те горде військо.
Заплакала Морозиха,    |
Ідучи на місто.        | (2)

Ой, не плач же, Морозихо,
Не плач, не журися,
Піди з нами, козаками, |
Меду-вина напийся.     | (2)

"Чогось мені, козаченьки,
Мед-вино не п''ється:
Десь мій син Морозенко |
З татарами б''ється".   | (2)

Із-за гори, з-за кручі
Удале військо виступає,
Попереду Морозенко    |
Сивим конем виграває. | (2)

Та схилив вже голівоньку
Сиву коню аж на гриву,
Та й розпустив чорні кудрі |
Сиву коню до копитів.      | (2)

То ж не грім в степу горгоче,
То ж не хмара світ закрила -
То ж татар велика сила |
Козаченьків обступила. | (2)

Бились з ранку козаченьки
До ночі глухої,
Козаків лягло чимало, |
А татар - утроє.      | (2)

Ні один козак не здався
Живим у неволю,
Полягли всі,                |
Не вернувся ні один додому. | (2)

Не вернувся Морозенко,
Голова завзята, -
Замучили молодого |
Вороги прокляті.  | (2)

Вони ж його не стріляли
Й на четі не рубали,
Тільки з його, молодого, |
Живцем серце виривали.   | (2)

Взяли його, поставили
На Савур-могилу:
"Дивись тепер, Морозенку, |
На свою Вкраїну!"         | (2)','["pisni.org.ua", "cat:istorychni", "cat:narodni", "cat:patriotic", "Історичні пісні", "Народні пісні", "Патріотичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_136323'), datetime('now')),datetime('now'));
