INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1364202','Зима на Україні','Музика: Уляна Соколишин Слова: Уляна Соколишин','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Юрій Ніколайчук.','Замела зима
Гори і долини -
Не впізнати тепер
Ліси і полонини,
Снігом вкрило все -
І міста, і села,
А в душі живе
Музика весела!

Приспів:
Така краса лише
На Україні,
Співочій, рідній,
Милій і єдиній!
І де б ви не були,
В якій країні,
Вертайтеся
До рідної святині!
Така зима лише
На Україні,
Тут казка лісова
Чарує нині,
І чути спів десь там,
На полонині!
Така зима лише
На Україні!

Горами летить
Пісень моїх відлуння,
Хай воно дзвенить на добро,
На радість людям,
Щоб співали всі раділи,
Танцювали,
Щоб ніколи ми
Горя не зазнали!

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1364202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1364202','Зима на Україні','Замела зима
