Приспів.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1375303','У Магурі, на поляні',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Лопушанка, Хащівська сільрада, Турківський район, Львівська область. Респонденти: Кметик Степанія, Волошинівська Анастасія. Збирачі: Артем''як Мар''яна, Довгань Оксана, Папіш Марія.','У Магурі, на поляні,
У малих смерічках,
То там сидить собі          |
Рубан у своїх криївках.     | (2)

А прокляті ті сексоти
Москалям сказали,
Що там сидить собі Рубан    |
З своїми друзями.           | (2)

А в п''ятницю дуже рано
Сніги ся ввали,
То там його славні друзі    |
Вечерю варили.              | (2)

А в п''ятницю дуже рано
Усі повставали,
А в суботу після обіду      |
Бункер облягали.            | (2)

Як обляли, то й кричали:
Добре сторожіте,
Бо повстанці всі вояки      |
Можуть нас побити!          | (2)

Як вискочив перший Рубан
Та й стався ся дивити,
Вітки було ту комуну        |
Добре покропити.            | (2)

А як вийшли на поляну,
Сталися дивити:
Ой, Нового з нами нема,     |
Певно, Новий вбитий.        | (2)

Ой, Нового з нами нема,
Певн,о Новий вбитий,
Всім нам, хлопці, за Нового |
Треба відомстити!           | (2)','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1375303'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1375303','У Магурі, на поляні','У Магурі, на поляні,
