INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_137202','Туман Яром по Долині','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Потаємні пісні любощів і кохання © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2002','Гаїлки-Великдень: Українське свято Відродження Світа. Пара — любощі: Поцілунки. Еротика: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Завтра вранці помандрую. Кличе Голуб Голубочку. Прийди Серце поцілую. Молодому Козакові Мандрівочка пахне. А вже Весна а вже Красна Туман Яром по Долині Вже Весна воскресла. Вибирай си кого любиш. Правой ручкою обняла ще й поцілувала. Стежки до листків про Українські традиції.','Туман Яром по Долині    |(2)
Широкий Лист на Калині  |(2)

А ще ширше на Дубочку   |(2)
Кличе Голуб Голубочку   |(2)

А Він кличе не чужую    |(2)
Прийди Серце поцілую    |(2)

Поцілую помилую         |(2)
Завтра вранці помандрую |(2)','["pisni.org.ua", "cat:vesnyanky-hayivky", "cat:zeleni-svyata", "Веснянки та гаївки", "Пісні до Зелених свят"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_137202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_137202','Туман Яром по Долині','Туман Яром по Долині    |(2)
