INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1359404','Хто далі йде','Музика: Сергій Бабкін Слова: Сергій Бабкін. Виконує: Сергій Бабкін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Невідомий хтось з''єднує мости -
Доленосні погляди,
Всередині нас на самому дні
Розкидані сліди...
Завуальований синхрон,
Деякі змогли вийти за межі...
Снайпер Купідон,
Єднаючи серця, бентежить...

Приспів:
Той, хто невдовзі впаде,
Звільнить простір для того,
Хто далі йде!
Той, хто до краю дійде,
Зведе сходи для того,
Хто далі йде!.. | (6)

Пустельні кораблі
Летять на відчутті, стираючи небо...
Далеко від землі
В іншому житті знайдеш себе...
Одиниці і нулі,
Як наші імена, будують вежу...
Все, що в тобі є,
Не лише тобі належить...

Приспів.

Палай! Палай! Палай!
Палай! Палаєм!
Не знаходим, але сяєм...
Шукай! Шукай! Шукай!
Шукай! Шукаєм!
Те, що є не помічаєм...
Долай! Долай! Долай!
Долай! Долаєм!
Лабіринтами блукаєм...
Зникай! Зникай! Зникай!
Зникай! Зникаєм!

Приспів. (2)','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1359404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1359404','Хто далі йде','Невідомий хтось з''єднує мости -
Доленосні погляди,
Всередині нас на самому дні
Розкидані сліди...
Завуальований синхрон,
Деякі змогли вийти за межі...
Снайпер Купідон,
Єднаючи серця, бентежить...

Приспів:
Той, хто невдовзі впаде,
Звільнить простір для того,
Хто далі йде!
Той, хто до краю дійде,
Зведе сходи для того,
Хто далі йде!.. | (6)

Пустельні кораблі
Летять на відчутті, стираючи небо...
Далеко від землі
В іншому житті знайдеш себе...
Одиниці і нулі,
Як наші імена, будують вежу...
Все, що в тобі є,
Не лише тобі належить...

Приспів.

Палай! Палай! Палай!
Палай! Палаєм!
Не знаходим, але сяєм...
Шукай! Шукай! Шукай!
Шукай! Шукаєм!
Те, що є не помічаєм...
Долай! Долай! Долай!
Долай! Долаєм!
Лабіринтами блукаєм...
Зникай! Зникай! Зникай!
Зникай! Зникаєм!

Приспів. (2)');
