INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1367220','Шабля козацька','Музика: Михайло Добрянський','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Гей, моя жінко, шабля козацька,
Скільки ти січ пережила? Гей!
Била татар та ляхів зненацька
Шабля моя гостроклила!

Приспів:
Гей, моя шабля, гостра, як криця,
З неба блакиті-стрімка блискавиця!
Гей, моя шабля, шабля козацька,
Воля народна, слава гетьманська!

Ти замінила мені родину,
В битвах не раз рятувала!
Ти захищала рідну Вкраїну,
Ворогу голови тяла!

Приспів.

Шабля козацька, волю здобути
Важко для нашого люду!
Ми розірвемо ярма та пута,
Ти - захисниця народу!

Приспів.','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1367220'), datetime('now')),datetime('now'));
