INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1374707','Запалала свічечка життя','Слова: Лідія Вудвуд','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує сім''я Колядичів.','Запалала свічечка життя,
Що від Духа Божого зачате,
Прийняла Його Марія мати —
Народилось Божеє дитя!
Мати сліз щасливих не хова,
Не надивляться на Сина очі,
Знову в серці ожили пророчі,
Незабутні та святі слова:

Приспів:
Хоч у Ньому кров тече моя,
Божий Дух у цім малім Дитяті!
Він спасіння людям хоче дати,
Хай же воля сповниться Твоя!
Хай же воля сповниться Твоя!

Він сьогодні ще спокійно спить,
Благодаті сповнені хвилини.
Що тебе чекає, любий Сину? —
Затремтіло її серце вмить.
І тривога крає, наче ніж:
Мусиш Ти від цього постраждати.
Над колискою шепоче мати:
Вірю, Отче, Сина захисти.

Приспів. (2)

Народилось Божеє дитя!
Народилось Божеє дитя!
Народилось Божеє дитя!','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1374707'), datetime('now')),datetime('now'));
