INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1375606','Спасибі вам, рідненькі вчителі!','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Спасибі вам, рідненькі вчителі,
Що нас навчили жить на світі,
За те, що з нами ви добрими були
І дарували світ відкритий!
За кожен день і кожен час,
Що називається "Дитинство",
Усі овації для вас,
Ми уклонімось низько-низько!

Приспів:
Зичимо щастя кожної днини,
Не забувайте нас!
Дні пролітають і з дітьми своїми
Скоро ми прийдемо в клас!

Спасибі вам, рідненькі вчителі,
Що на порозі нас стрічали,
Що ви неначе всі журавлі,
Мов пташенят нас захищали!
За кожен день і кожен час,
Що називається "Дитинство",
Усі овації для вас,
Ми уклонімось низько-низько!

Приспів.','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1375606'), datetime('now')),datetime('now'));
