INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1375909','Друзям за синє море','Музика: Павло Дворський Слова: Андрій Малишко. Виконує: Назарій Яремчук, Павло Дворський, Ніна Мельник','uk','ukr_ssr_1919_1991',NULL,'1988','аудіозапис','Ніна Мельник, Назарій Яремчук, Павло Дворський - Біла Криниця (1988), магнітоальбом.','Пригадаю те життя, суворе,
Давні ночі видяться мені,
Грає море, грає синє море,
Білі чайки линуть в далині...
Там шумлять дуби зеленочолі,
Дужий вітер хвилю нажене,
У містах і у канадськім полі
Милі друзі згадують мене...

Приспів:
Рідна пісня заплете розмову,
У стареньких висушить сльозу,
Я в Канаду ще приїду знову, |
З України пісню привезу!    | (2)

Шахтарі, і ливарі, й солдати,
Затамуєм ран минулих біль,
В дружнім колі сядем біля хати,
Як було - поділимо хліб, сіль,
Ще минеться те життя, суворе,
Інші ранки видяться мені:
Грає море, грає синє море,
Білі чайки линуть в далині...

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1375909'), datetime('now')),datetime('now'));
