INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1379202','Поведи мене','Музика: Володимир Домшинський Слова: Василь Савюк. Виконує: Гурт Будьмо','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'А любов нас кличе
В яворовий гай, де зорі.
А любов нам каже:
Місяць вже, уже на дворі
І відкриє душу нам
Замріяна смерека,
Подарують гори файну пісню
Нам здалека.

Приспів:
Поведи мене,             |
Де зорі цілувались,      |
А любов казала: Гірко!.. |
Поведи мене,             |
Де ночі обнімались,      |
А любов співала дзвінко! | (2)

Я тебе чекаю
На закоханій стежині,
Щоб зустріти знову
Твої очі сині, сині!
Хай любов не в''яне,
Хай любов веде до пари,
Десь високо в горах
Хай горять для нас стожари!

Приспів.','["pisni.org.ua", "cat:lirychni", "Пісні про кохання, ліричні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1379202'), datetime('now')),datetime('now'));
