INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_137808','Ой Морозе Морозенку ти Славний Козаче','Українська народна пісня. Виконує: Микола Будник','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Морозенко, як і Байда, — Український символ Спасителя. Чому "повели ж Його Морозенка на Савур-могилу" (Лиса-гора, Голгота)? Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Повели ж Його Морозенка на Савур-могилу. Подивися Морозенку тай на Свою Україну. Ой Морозе Морозенко ти Славний Козаче Ой Морозе Морозенку ти Славний Козаче Ой Морозе Морозенку... Ой на Горі на Могилі Господа Милосердного прохали та благали. За Тобою Морозенко вся Вкраїна плаче. Ой устань же Козаченьку. Байді Молодому Мед-горілку пити. Ой що Ти бачиш Байдо Молодецький. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Гаїлковий Білоданчик і Первісний Молодець-Стрілець Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Стежки до листків про Українські традиції.','Ой Морозе Морозенку ти Славний Козаче
За тобою Морозенку уся Україна плаче              |(2)

Не так тая Україна як те Славне Військо
Заплакала Морозиха ідучи на Місто                 |(2)

Ой не плач не плач Морозихо не плач не журися
Піди з нами Козаками та і Мед-вина напийся        |(2)

Ой чомусь мені Милі Браття Мед-вино не п''єцця
Ой десь мій Син Морозенко з Ворогами б''єцця       |(2)

Із-за Гори з-за Крутої Горде Військо виступає
Попереду Морозенко Сивим Конем виграває           |(2)

Ой і став же він Морозенко в Чистім Полі гуляти
Ой і стали Морозенка та і Турки обступати         |(2)

Морозенко-козаченько як Мак розпускався
Морозенко-козаченько у Неволю тай попався         |(2)

Повели ж Його Морозенка на Савур-могилу
Подивися Морозенку тай на свою Україну            |(2)

Ой вони ж Його не стріляли не четвертували
Тільки з Нього Молодого живцем Серце тай виймали  |(2)','["pisni.org.ua", "cat:dumy", "cat:kozacki", "cat:philosophic", "Думи", "Козацькі пісні", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_137808'), datetime('now')),datetime('now'));
