INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1375323','Ци, де хто снав, ци, хто думав',NULL,'uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис','Місце побутування: с. Вовче, Вовченська сільрада, Турківський район, Львівська область. Респондент: Савчин Настуня. Збирачі: Іванищук Марія, Беднарська Ружена.','Ци, де хто снав,
Ци хто думав,
А як по силу стріляла
Павлова боївка.

А Павлова стріляла,
Рісковського вбила,
Я забігла й у комору,
Там їм ся сховала.

Як ня найшов анкагебіст,
Та бідову вдару:
Скажи, скажи, чорнобрива,
Як любиш Бандеру.

Я стояла та й мовчала,
Лиш Бога просила,
Бо я знала - переможе
України сила!

Та тепер суть лихі люди,
Не мож ся міряти,
Бо вни кажуть, що за руських
Било добре жити.

А я вкрала трохи булі
Й несла в пирибиси,
А ту мине перестріли
Всі конторські криси.

Шофер повіз пів кузова,
Їздовий в тачанці,
А я мала й уміщати
Та й вергла в млочарці.','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1375323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1375323','Ци, де хто снав, ци, хто думав','Ци, де хто снав,
Ци хто думав,
А як по силу стріляла
Павлова боївка.

А Павлова стріляла,
Рісковського вбила,
Я забігла й у комору,
Там їм ся сховала.

Як ня найшов анкагебіст,
Та бідову вдару:
Скажи, скажи, чорнобрива,
Як любиш Бандеру.

Я стояла та й мовчала,
Лиш Бога просила,
Бо я знала - переможе
України сила!

Та тепер суть лихі люди,
Не мож ся міряти,
Бо вни кажуть, що за руських
Било добре жити.

А я вкрала трохи булі
Й несла в пирибиси,
А ту мине перестріли
Всі конторські криси.

Шофер повіз пів кузова,
Їздовий в тачанці,
А я мала й уміщати
Та й вергла в млочарці.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_137828','Ой летів Пугач тай через Могилу','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українські релігійні роздуми про Спасіння © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2003','Спасительна: світ не по Правді. Українські релігійні роздуми про Воскресіння, Неволю і Спасіння. Ой Ми зіслані на признаванє. Нема в світі Правди не зіскати. Ой устань же Козаченьку. Ой а ще Серце та Козацьке та не боїться Турків. Листки з приводу цієї Пісні: Українські реліґійні роздуми про Неволю та Спасіння Коляда і Великдень: Різдво і Відродження Світа. Еротичні містерії, тиждень від Катерини 7.12 до Калети. Доля. Св. Микола 19.12 – Народний речник перед Богом і Прадід. Рокове Коло. Стежки до листків про Українські традиції.','Ой летів Пугач тай через Могилу як Пугу так Пугу!
Ой чи не дасть Біг та Козаченькам та іще раз Потугу |(2)

Ой щодень-щоніч та Війни ждемо Поживи немає
Ой давно була та Хмельниччина та уже й згадаєм      |(2)

Ой то колись ми воювали та більше не будем
Ой того Щастя та Тихої Долі да повік не забудем     |(2)

Ой а вже Шаблі та заржавіли Мушкети без курків
Ой а ще Серце та Козацьке та не боїцця Турків      |(2)','["pisni.org.ua", "cat:kozacki", "Козацькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_137828'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_137828','Ой летів Пугач тай через Могилу','Ой летів Пугач тай через Могилу як Пугу так Пугу!
Ой чи не дасть Біг та Козаченькам та іще раз Потугу |(2)

