INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1382808','Рано','Українська народна пісня. Виконує: The Doox','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Хто не вийде
На Купайло,
Щоб воно лягло   |
Та й не встало!  | (2)

Щоб воно лягло   |
Та й не встало,  |
Святого Петра    |
Не дождало!      | (2)

Щоб воно лягло
Колодою,
А завтра встало
З хворобою!

Приспів:
Рано!.. Рано!..
