INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1382220','Вітаю вас, молодятка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Вітаю вас, молодятка,
Кущиком міртуса,
Та й най же вас благословить
Серденько Ісуса.

Вітаю вас, молодята,
Квіточков лелії,
Та й най же вас благословить
Серденько Марії.

Вітаю вас, молодята,
Та й даю вам п''ятку,
Бисьте мали штири хлопці,
А п''яте дівчатко.

Ой, ті штири кавалери —
Сіяти й орати,
А те п''яте дівчаточко
Хатку підмітати.

Вітаю вас, молодята,
Даю гроші в руки,
Та най вам ся діти ведут,
Як у бульбі жуки.

Вітаю вас, молодята,
З грішми на тарели,
Щоби усі штири сини
Були інженери.

Вітаю вас, молодята,
На всі штири канти,
Бисьте мали штири сини
І всі музиканти.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1382220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1382220','Вітаю вас, молодятка','Вітаю вас, молодятка,
Кущиком міртуса,
Та й най же вас благословить
Серденько Ісуса.

Вітаю вас, молодята,
Квіточков лелії,
Та й най же вас благословить
Серденько Марії.

Вітаю вас, молодята,
Та й даю вам п''ятку,
Бисьте мали штири хлопці,
А п''яте дівчатко.

Ой, ті штири кавалери —
Сіяти й орати,
А те п''яте дівчаточко
Хатку підмітати.

Вітаю вас, молодята,
Даю гроші в руки,
Та най вам ся діти ведут,
Як у бульбі жуки.

Вітаю вас, молодята,
З грішми на тарели,
Щоби усі штири сини
Були інженери.

Вітаю вас, молодята,
На всі штири канти,
Бисьте мали штири сини
І всі музиканти.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1382202','Ой, ви, свату','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ой, ви, свату, та ви, свату,
Пускайте до хати,
А що сь те нам обіцяли,
Мусите нам дати.

А в вашого молодого
Всі дружби розслізли,
Три години по драбині
За цибульов лізли.

Ой, на горі на високій
Пес чорний загавкав,
Подивіться, люди добрі,
Дружба ся засмаркав.

Ой, червоний бурячок,
Зеленийка гичка,
Перший дружба, як бичок,
Дружка, як теличка.

Ой, ти, дружбо, не співай,
Та й марно не дрися,
А йди домі, візьми бритву
Й добре поголися.

Ой, наш дружба молодийкий,
Любити не вміє,
Як на дружку ся подивит,
Відраз червоніє.

Ой, що ж то у вас за дружба,
Що то за зараза,
Що він так боїтся дружки,
Як противогаза.

Ой, вашого дружбу
До школи би дати,
Щоби там го підучили
Дружку цілувати.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1382202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1382202','Ой, ви, свату','Ой, ви, свату, та ви, свату,
