INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1384000','Молитва зниклого безвісти','Музика: Ігор Жук Слова: Ігор Жук','uk','ukraine_1991',NULL,'2019','Літопис авторської пісні України №29 (567) 2019 рік',NULL,'Знайди мене, Боже, бо людям уже не знайти,
А це таки страшно - пропасти без жодної вістки,
Згорьовану матір лишити на розпач невістки,
І, тільки приснившись, дитині шепнути: "Прости!.."

Знайди мене, Боже, бо сам і не знаю, де я:
Живий, чи помер, чи в тюрмі божеволію з муки,
Чи ворог зрізає мій скальп, витираючи руки
Об мій однострій, на якому нашите ім''я...

Знайди мене, Боже. Тут сумно... Тут тиша і тьма,
І подихи тих, кого чути, та вже не торкнути...
Ми всі, зниклі безвісти, зниклі - але не забуті,
Мабуть, не в раю ще, бо смерті ж героям нема...

Знайди мене, Боже... Хай морок стирає сліди,
Хай біситься зло - та добро, Ти ж казав, переможе!?.
Шеврон, ДНК, чи той скальп - розшукай мене, Боже...
Знайди нас усіх!.. Ми іще почекаєм!.. Знайди!..','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1384000'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1384000','Молитва зниклого безвісти','Знайди мене, Боже, бо людям уже не знайти,
А це таки страшно - пропасти без жодної вістки,
Згорьовану матір лишити на розпач невістки,
І, тільки приснившись, дитині шепнути: "Прости!.."

Знайди мене, Боже, бо сам і не знаю, де я:
Живий, чи помер, чи в тюрмі божеволію з муки,
Чи ворог зрізає мій скальп, витираючи руки
Об мій однострій, на якому нашите ім''я...

Знайди мене, Боже. Тут сумно... Тут тиша і тьма,
І подихи тих, кого чути, та вже не торкнути...
Ми всі, зниклі безвісти, зниклі - але не забуті,
Мабуть, не в раю ще, бо смерті ж героям нема...

Знайди мене, Боже... Хай морок стирає сліди,
Хай біситься зло - та добро, Ти ж казав, переможе!?.
Шеврон, ДНК, чи той скальп - розшукай мене, Боже...
Знайди нас усіх!.. Ми іще почекаєм!.. Знайди!..');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_139024','Ой там у Лісі Калина','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Пісні з Волині. Упорядкування текстів та примітки О. Ф. Ошуркевича. Упорядкування нотних матеріалів М. С. Стефанишина. - К.: Музична Україна, 1970. - 336 с.','Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Пара - любощі: Ліс-Калина. Руса Коса - Біле Личенько. Дівчина-Ратайко - Лінтяйко. Вмивання. Вибір Пари. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Під Калиною Дівчина там Косу Русу чесала. Там Біле Личко вмивала. Кому ж Ти будеш миленьке. Були Світилки Яснії Зірки. Не гинь Миленький дам Ти Радоньку. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой там у Лісі Калина
Під Калиною Дівчина
Там Косу Русу чесала
Там Біле Личко вмивала

Ой ти Личенько Біленьке
Кому ж Ти будеш миленьке
Ци Ратайку дай Боже !
Ци Лінтяйку крий Боже !

Бо Ратайко працює
А Лінтяйко балує
Бо Ратайко в Полі є
