INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_139000','Ой там у Ліску на Кленку висить Колиска із Шовку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Пісні з Волині. Упорядкування текстів та примітки О. Ф. Ошуркевича. Упорядкування нотних матеріалів М. С. Стефанишина. - К.: Музична Україна, 1970. - 336 с.','Колискові: Світові-Дитині. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Пара - любощі: Лісок-Кленок. Колиска із Шовку. Дитятко Молодесенький Іванко - Дівчина. Перстень-Гуляння. Вибір Пари. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Були Світилки Яснії Зірки. Висіла Колисонька на Шнурку. Де Моя Дівчина гуляє з ким Вона Перстень міняє. Золотарю Царю скуй мені Перстеник. По чім Його ви так упізнали. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой там у Ліску на Кленку
Висить Колиска із Шовку
У тій Колисці Дитятко
Молодесенький Іванко

Ой колишіть мене Високо
Нехай я бачу Далеко
Де Моя Дівчина гуляє
З ким Вона Перстень міняє    Голос 1','["pisni.org.ua", "cat:kupalski", "cat:volynski", "Купальські пісні", "Пісні з Волині"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_139000'), datetime('now')),datetime('now'));
