INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_138707','Ой за Гаєм ой за Гаєм за Дунаєм','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Берег-Купання. Світ-Коні-Шаблі. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. На Бережечку сушилася й на Три Шляшки дивилася. Були Світилки Яснії Зірки. Кониками Світ затьмили Шабельками роз''яснили. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Ой за Гаєм ой за Гаєм за Дунаєм
Там Тетяна купалася

Купалася купалася-купалася
На Бережечку сушилася

На Бережечку на Бережечку сушилася
Й на Три Шляшки дивилася

Ой з-за Гори ой з-за Гори Чорні Хмари встали
То не Хмари Молоді Гусари

Їдуть Ляшки їдуть Ляшки на Три Шляшки
А Гусари на Чотири

А Гусари а Гусари на Чотири
Ківерами Степи вкрили

Ківерами-ківерами Степи вкрили
Кониками Світ затьмили

Кониками-кониками Світ затьмили
Шабельками роз''яснили','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_138707'), datetime('now')),datetime('now'));
