INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_139303','Місяцю Розроженьку світи нам Дороженьку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Помолімося Богу бо поїдемо в Дорогу Місяцю Розроженьку Світи нам Дороженьку. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Жертви для Бога як реліґійний ідеал. Свята, Тайна, Вечеря 6.01 — Що вона означає і як її підготувати? Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Коляда і Великдень: Різдво і Відродження Світа. Про Свято Івана Купала Весілля — Свята Неділя: Святий Коровай. Стежки до листків про Українські традиції.','Місяцю Розроженьку
Світи нам Дороженьку
Щоби ми не зблудили
Віночка не згубили','["pisni.org.ua", "cat:manrivni", "cat:obzhynkovi", "Пісні на мандрівну тематику", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_139303'), datetime('now')),datetime('now'));
