INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1382529','А ти, тату, рубай дрова','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'А ти, тату, рубай дрова,
