INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_138725','Сьогодні Купала а завтра Івана - Дівка-сирітка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004 2. Купальські пісні. Українські народні пісні. Пісенник. Упорядник О. Ю Чебанюк. - К.: Музична Україна, 1989. - 196 с.','Пара - любощі: Ліс-Ягідки. Астральні Заручини — Українське містичне Весілля: Різдво Світа / Купала. Обрядове Купання. Еротика, жарти, забави: Катерини – Калета – Андрія... Гаїлки-Великдень... Зелені Свята... Івана Купала... Весілля... – Щедровечірнє й Новорічне: Маланки-Василь. Коза. Кіт... – Мед і Ябка... Рай розвився Господь звеселився. Івана Купала тай в Воду упала. Скрізь Вода та Лілеями а на Морі Вода грає. Ой прийшлось Їй та Дунай брести. Були Світилки Яснії Зірки. Ой ішли Дівочки в Ліс по Ягідочки. Дівка-сирітка іде напереду. Не гинь Миленький дам Ти Радоньку. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Українські релігійні роздуми про Бога. Про Свято Івана Купала Стежки до листків про Українські традиції.','Сьогодні Купала а завтра Івана

Приспів:
Скрізь Вода та Лілеями
А на Морі Вода грає
На Долині Роса впала
На Юлиці в''ють Купала на Йвана

Ой ішли Дівочки в Ліс по Ягідочки
Дівка-сирітка іде напереду

Ой прийшлось Їй та Дунай брести
Дівці-сирітці та перед вести
І перед повела і Дунай побрела
Замочилася і втопилася

Прийшли слихи аж до Батенька
Батько плаче а Дунай скаче
Прийшли слихи та до Мачухи
Мачуха плаче а Дунай скаче

Лісом несли Ліси шумлять
Полем несли Поле скаче
Селом несли Село плаче','["pisni.org.ua", "cat:kupalski", "Купальські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_138725'), datetime('now')),datetime('now'));
