INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1397808','Вітай, Мати наймилосердніша!',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Вітай, Мати наймилосердніша,
Мати Бога і Мати прощення,
І надії і благодаті,
Мати повна святої радості,
О, Маріє!

О, Прикрасо людського роду,
Діво гідна усяких почестей,
Своїм дівством ідеш на чолі усіх,
Трон найвищий верхівям став Твоїм,
О, Маріє!

Приспів.

Ти - створіння рук Бога Отця,
І для Сина Ти - люба Матінка,
Святим Духом цілком отінена,
Отже, Діво, Ти вся божественна,
О, Маріє!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1397808'), datetime('now')),datetime('now'));
