INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1394828','Ти - моє все!','Музика: Володимир Сірант Слова: Володимир Сірант','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти - моє все!
Ти - теплий в полі вітер!
Ти - моє все!
Весняні в лісі квіти!
Моє - ти - все!
Ти - пташка на долоні!
Моє - ти - все!
Моя ти рідна доня!

Приспів:
Я хочу бачити тебе
Завжди щасливою, смішною,
І хочу бачити тебе
Я безтурботною, малою!
Перед тобою простелю
Всю свою душу на дорогу!
За тебе ангела прошу,
За тебе я молюся Богу!

Ти - моє все!
Ти - зірка моя ясна!
Ти - моє все!
Ти - сонечко прекрасне!
Моє - ти - все!
Сніжинка на долоні!
Моє - ти - все!
Моя ти рідна доня!

Приспів.

Ти - моє все!
Струмок веселий в гаї!
