INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1397828','Діво Маріє, в зірках і квітах',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Діво Маріє, в зірках і квітах,
Царице неба і Пані світу,
Серця Тобою наші палають з любов''ю,
Мати, всі Тебе славлять.

Приспів:
О, Непорочна, в руках розарій.
Хай Твоя милість нас захищає.

До ніг Твоїх ми несемо квіти,
Щоб Твої очі з радістю квітли.
Святий розарій і всі прохання
Прийми ласкаво наші благання.

В руках розарій завжди тримаєш
Віддано Бога любить навчаєш.
Через розарій ми всі пізнаєм,
Яку Царицю ми в небі маєм.

Наша молитва життя міняє
Через розарій Бога пізнаєм.
Царицю нашу ангельські хори
У всі народи славлять з любов''ю.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1397828'), datetime('now')),datetime('now'));
