INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_139323','Ходзіў Бог по Полю','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Староукраїнські релігійні роздуми про Бога © Видавництво "Павутинонька", Нью Йорк – Львів – Київ – Харків – Москва, 2004','Білоруська Обжинкова пісня. Білоруські анальоґії в Колядках, Піснях обжинкових і весільних є дуже цінні, хоч їх, особливо Старовіцьких колядок, є мало. Вони не раз доповняють думку Українських Святочних пісень. І є доказом, що Білорусини старинною своєю культурою й реліґійною ідеольоґією найблизші зі всіх Славян до Українців. Найновіші погляди етнольоґів про культурно-історичну єдність Білорусинів з північними Славянами з цим фактом культурно-реліґійної спільности Білорусинів з Українцями — не гармонізують. Помолімося Богу бо поїдемо в Дорогу. Листки з приводу цієї Пісні: Українська Астрально-мітольоґічна реліґійна концепція. Жертви для Бога як реліґійний ідеал. Свята, Тайна, Вечеря 6.01 — Що вона означає і як її підготувати? Св. Микола 19.12 – Народний речник перед Богом і Прадід. Бог, Різдво Світа, Дідух і Лицарі. Коляда і Великдень: Різдво і Відродження Світа. Про Свято Івана Купала Весілля — Свята Неділя: Святий Коровай. Стежки до листків про Українські традиції.','Ходзіў Бог по Полю
Пацєраў Карону
Ваши Жнєйкі жалі
Карону паднялі','["pisni.org.ua", "cat:obzhynkovi", "Обжинкові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_139323'), datetime('now')),datetime('now'));
