INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1392404','В Ніч Різдва','Музика: Тетяна Навроцька (Tanya Navrotski) Слова: Марія Звірід (Mariya Zvirid)','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Лариса Кайдрис.','Ніч та була особлива,
Зорі над полем світили,
Поміж ягнят спить немовля
Божий дарунок землі...
Ніжно Марія гойдала
І колискову співала,
Солодко спи, очки закрий,
Сину малесенький мій!..

Приспів:
Він прийшов
Спасіння усім принести,
Щоб у небо могли увійти ті,
Хто серце для Бога відкриють
В Ніч Різдва Спаса прийми!
Він прийшов
Спасіння усім принести,
Щоб у небо могли увійти ті,
Хто серце для Бога відкриють
В Ніч Різдва, в ніч доброти!

Ангели в небі співали,
Славу Господню звіщали
На висоті, мир на землі
І благодать між людьми!
Скрипка у небі звучала,
Дивну дитину вітала.
Єрусалим миро тримав
І про месію не знав.

Приспів. (2)

В Ніч Різдва ти Спаса прийми!
В ніч доброти!..','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1392404'), datetime('now')),datetime('now'));
