INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1398127','Мати Церкви, добра Мати',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'До Тебе підносимо очі свої,
Ти, що живеш не в земній красоті,
Як очі слуг, що не зводяться
З рук їх вчителів і панів.

Приспів:
Мати Церкви, добра Мати,
Дай достойно споглядати
Тайну Церкви-Матері,
Тайну Церкви Матері.

Ти - віри скарбниця і послуху взір,
З Тебе походить вся радість і мир,
Ти захопила красою увесь світ,
В єдності Захід і Схід.

Приспів.

О, Ангелів Радосте й Сило Святих,
Мудрості Трон, Допомого малих!
Прийми всі наші діла і слова,
Ти, що родила Христа!

Приспів.

Ти - Донька улюблена Бога Отця,
Мати предивна Ісуса Христа,
Духа Святого Невіста свята!
Радуйся! Алілуя!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1398127'), datetime('now')),datetime('now'));
