INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1403808','Зима','Музика: Ольга Мамієнко Слова: невідомий. Виконує: Зоряна Рощук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знову випав білий сніг
Та й до мене на поріг,
Застелив усі стежки і дороги,
І на конях вороних,
На санчатах золотих
Завітала зимонька на пороги!

Приспів :
Подивись, іде зима в Україну,        |
Засипає все навкруг снігом білим,    |
І малює на вікні візерунки,          |
Щастя, радість, всім несе подарунки! | (2)

Скрізь луна веселий сміх,
Бо на дворі Новий рік,
Дід Мороз несе усім подарунки!
Всі радіють навкруги,
І дорослі і малі,
Під ялинку заховав він пакунки!

Приспів.

А в ясну, чудову ніч
Запалає сотня свіч,
Залунає коляда в кожній хаті,
Бо настав різдвяний час,
І віншуємо ми вас,
Будьте всі здорові ви і багаті!

Приспів.

Речитатив:
Гарна днина, в добрий час
Із Різдвом вітаєм вас!
Із вечерею святою,
Із веселой колядою!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1403808'), datetime('now')),datetime('now'));
