INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1403529','Там, за небокраєм','Музика: Тарас Житинський Слова: народні. Виконує: Тарас Житинський','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'аудіозапис',NULL,'Там за небокраєм сонце сяйвом грає,
Стрілецькеє військо окопи кидає.
Окопи, окопи, важко вас кидати,         |
