INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1399921','Хай лине аж до небес наш спів',NULL,'uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хай лине аж до небес наш спів
Пречистій Діві Марії:
Ясніше сонця Вона сія,
Даруючи нам надії.

Приспів:
Благаєм: Нас не забувай,
Нам поміч з неба свою дай!

Твій трон у почестях і хвалі
Є поруч із троном Сина.
Ти милосердя для нас проси,
Опоро наша єдина.

Приспів.

В Твоїх ласкавих, ясних очах
Є доброта нескінченна.
Нам сльози смутку й журби утри,
Маріє благословенна!

Приспів.','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1399921'), datetime('now')),datetime('now'));
