INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1404707','Моя мамка - молдаванка!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Моя мамка - молдаванка -
Вийшла заміж за Іванка!
За Іванка, за п''яничку,
Ще й дурного, як теличка!

Приспів
Гоп, гей, ші-ді-рі-ді-дана, |
Гоп, гей, ші-ді-рі-ді-дана, |
Моя мамка - молдаванка!     | (2)

Моя мамка - молдаванка -
Прийшла з нами на гулянку.
Прийшла з нами на гулянку,
Танцювала аж до ранку!

Приспів.

А у нашого Іванка
Та й там, на бороді, ямка.
Хлопці, коли його били,
Ямку там йому зробили!

Приспів.

Коли мамку в танець брали,
Дуже гарно танцювали,
А Іванка коли били,
Зуби в боки всі летіли!

Приспів.

Біжить заєць по дорозі,
Підкидає обі нозі,
Я би також підкидала,
Якби такі ноги мала!

Приспів.','["pisni.org.ua", "cat:zhartivlyvi", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1404707'), datetime('now')),datetime('now'));
