INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1398707','Дружать діти на землі!','Музика: Давид Львов-Компанієць Слова: В. Вікторов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Дружать квітка і бджола,
І метелик, і трава,
Дружать ріки і ліси,
Дружать в хорі голоси!

Приспів:
В коло всі, в коло всі!
Музика гука.
Той, хто брат, той, хто друг, -
Ось тобі рука!

Дружать птахи в вишині,
Дружать риби в глибині,
Дружить з небом синь морів,
Дружать люди всіх країв!

Приспів.

Дружать сонце і хмарки,
Дружать місяць і зірки,
Дружать в морі кораблі,
Дружать діти на землі!

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1398707'), datetime('now')),datetime('now'));
