INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_140505','А я стою й дивлюся на сніги','Музика: Зоя Слободян Слова: Ігор Павлюк. Виконує: Зоя Слободян','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Зоя Слободян. Давай помовчимо (Cпівана поезія)" (2000)','Текст записано на слух з аудіо.','Передмова:
Дрімучий світ. І раптом - добре, й легко,
І просто так. Колиска і крило.
Ми всі ще - час. Ми близько і далеко.
Ми любим біль. Нас довго не було.

А я стою й дивлюся на сніги,
Дивлюсь на море і дивлюсь на себе.
Спасибі вам, і друзі, й вороги,
спасибі за компанію під небом.

Життя своє природі віддаю.
Циганка-осінь з душ виймає кулі,
І зло простить і доброту чиюсь,
Всміхнувшись до майбутнього й минулого.

Скрізь чоловік, мадонна і дитя.
Хтось із Венери впав, розкинув руки,
хоч розпинай на кожному Христа.
І думка, наче думав, що в світах
Триєдне щастя й триєдина муко.

А я стою й дивлюся на сніги,
дивлюсь на море і дивлюсь на себе.
Спасибі вам, і друзі, й вороги,
спасибі за компанію під небом','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_140505'), datetime('now')),datetime('now'));
