INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_140529','День міста Лева','Музика: Олесь Дяк Слова: Микола Пшеничний. Виконує: Олесь Дяк','uk','ukraine_1991',NULL,NULL,'Аудіо-CD "Олесь Дяк. "Магія Львова" (2002)','Текст і акорди записано на слух з аудіо.','Я прив''язаний, Львове, до тебе, неначе трамвай,
H7                                  Em ...
у який добровільно запряжені леви з сумними очима.
Тільки рейками рук ти мене не тримай, не тримай;
краще ти в моїх споминах, Львове, подовше затримайсь.

Приспів:
Dm                  E        Am ...
Пройде триста віків, поміняються триста плакатів,
триста левів помре, та залишиться хоч би один;
і цей Замок Високий як стояв, так і буде стояти,
і Франко як ходив, так по Львову і буде ходить.

Ще не раз посміхнеться заплакана юна трава,
коли буде асфальт піднімати своїми плечима.
Я закоханий в коней, та сам я неначе трамвай,
у який добровільно запряжені леви з сумними очима.

Приспів.','["pisni.org.ua", "cat:bardivski", "cat:lviv", "Бардівські пісні", "Пісні про Львів"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_140529'), datetime('now')),datetime('now'));
