INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_141404','Нове покоління -вибирає Пепсі','Музика: Руслан Навроцький Слова: Руслан Навроцький. Виконує: Руслан Навроцький','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Все позаду,
Трохи вирівнялось
Незалежне життя в Незалежній країні.
Ще далеко до повного "ЩОСЬ"
Та вже Вчора і Завтра не владує на Нині.
Хто хотів на Базар-той вже Там.
Хто Мовчав той- Мовчить.
Хто Шукав,той і нині Шукає.
Хто хотів потриматись "ЗА РУЛЬ",
Той-Тримавсь.
Тішив думкой себе,ну а Нас-мордував,
"Я Владую!Владую!Владую!"
Слава Богу,що по владував мало...
Що своїми Брехнями ти нам показав,
Що Розвал-це Розвал!
І що тут не врятує ні Тризуб,ні Сало.
І що Совість-це Совість...
Не довів нас до Крові-
Славі Богу...

А я шукав на Небі,шукав на Землі,
І в Вас,і в Собі.
І ледь не кинув.
Нарешті-
Від того всього-був вже біля петлі.
Але Бог зберіг.
А куди мені!А куди мені...
Коли Нове Покоління-вибирає Пепсі.

Все позаду.Вже розвиднілось.
І упевніший крок,та й і думка ясніша.
І вже можу сказати-
То це ж я-Патріот!
І це буде сприйматись
Не грішно,не смішно.
Патріот!Патріот!
Бо в лукаві часи не ховавсь
Ні за Рух ,ні за Владу.
Бо не вірив в прекрасністьЧужої краси.
Не шукав її ні в USA, ні в Канаді.

А я шукав на Небі,шукав на Землі,
І в Вас,і в Собі.
І ледь не кинув.
Нарешті-
Від того всього-був вже біля петлі.
Але Бог зберіг.
А куди мені!А куди мені...
Коли Нове Покоління-вибирає Пепсі.

Я любив Україну,та не бачив доцільності
Свою дитину роздягнуть із котону,
І вдягнуть у минулу свитину.
Не співав я пісень лиш про Червону калину
В угоду усім політичним забродам.
Я співав свої вірші.
Мав Совість і Волю
В Житті і в Пісні -Бути собою.
Патріот!Патріот!
Бо в лиху і в лукаву годину,
Був з своїм я народом!
(Хоч в офіціозі брехливім
Прослив-Юродивим.)
Бо шукав на Небі,шукав на Землі,
І в Вас,і в Собі.
І ледь не кинув.
Нарешті-
Від того всього-був вже біля петлі.
Але Бог зберіг.
А куди мені!А куди мені...
Коли Нове Покоління-вибирає Пепсі.
Нове Покоління-вибирає Пепсі.','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_141404'), datetime('now')),datetime('now'));
