INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1410404','Твоє Успіння, о, Божа Мати','Музика: П. Хоркавців Слова: Марія Мазурик','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Твоє Успіння, о, Божа Мати,
Радість принесло усій землі!
Тобі Пречистій і Всемогутній
Славу підносять всі святі!

Твоє Успіння, Діво Пречиста,
Дало спасіння грішній душі!
Мати ласкава, завжди будь з нами
І помагай нам у біді!

Мати Пречиста і Непорочна,
Благаєм щиро ми Тебе днесь:
Візьми усіх нас на свої руки
І заведи нас до небес!

Твоє Успіння, о, Божа Мати,
Страшне для пекла, грізне, як грім,
Тож запровадь нас до свого Сина,
Де сяє святість всіх святих!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1410404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1410404','Твоє Успіння, о, Божа Мати','Твоє Успіння, о, Божа Мати,
