INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1409505','Миколай','Музика: А. Пряжніков Слова: невідомий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ти сьогодні швидше спатоньки лягай,
Бо прийде у гості Миколай.
Бачиш, перша зіронька вже горить,
То наш Миколай до нас спішить!
В нього коні білі, наче сніг,
Борода сивенька аж до ніг,
У сріблясті саночки він сіда
І за вітром в''ється борода!

Приспів:
Миколай! Миколай! -
Ляльки, зайчики, дарунки!
Миколай! Миколай! -
Втілення усіх надій!
Миколай! Миколай! -
І цукерочок пакунки!
Миколай! Миколай! -
Здійснення дитячих мрій!

Миколай про діток знає все,
Подарунки кожному він несе!
Має для дитячих подушок
Подарунків повно - аж мішок!

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:svyatyy-mykolay", "Дитячі пісні", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1409505'), datetime('now')),datetime('now'));
