INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1410707','Богородице Пресвятая','Музика: Петро Корж Слова: Петро Корж','uk','ukraine_1991',NULL,NULL,'аудіозапис','Пісню виконує Андрій Бигар.','Мри на землі, світла радість завжди
Мати Христова спасе від біди,
Світлом своїм омофор відбиває,
Нас, християн, завжди благословляє.
Богородице Діво-Маріє,
Свого Сина проси за нас,
Щоб завжди дарував нам надію
На щасливий прийдешній час!
Ти, Заступнице Наша Небесна,
Борони нас від горя й біди,
Подаруй нам години чудесні,
Щоб у мирі жили ми завжди!

Благословив Тебе Господь в свій час,
Що породила Ісуса для нас.
Люди раділи появі Месії,
Жили у вірі, любові й надії!
Богородице Пресвятая,
У жнива дай погожі дні,
Хай із неба нам сонечко сяє,
Милі квіти цвітуть навесні.
Борони від стихійного лиха,
Борони нас від горя і зла,
Щоб земля заливалася сміхом,
Аби доля щаслива була!','["pisni.org.ua", "cat:do-bohorodyci", "Пісні до Богородиці"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1410707'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1410707','Богородице Пресвятая','Мри на землі, світла радість завжди
Мати Христова спасе від біди,
Світлом своїм омофор відбиває,
Нас, християн, завжди благословляє.
Богородице Діво-Маріє,
Свого Сина проси за нас,
Щоб завжди дарував нам надію
На щасливий прийдешній час!
Ти, Заступнице Наша Небесна,
Борони нас від горя й біди,
Подаруй нам години чудесні,
Щоб у мирі жили ми завжди!

Благословив Тебе Господь в свій час,
Що породила Ісуса для нас.
Люди раділи появі Месії,
Жили у вірі, любові й надії!
Богородице Пресвятая,
У жнива дай погожі дні,
Хай із неба нам сонечко сяє,
Милі квіти цвітуть навесні.
Борони від стихійного лиха,
Борони нас від горя і зла,
Щоб земля заливалася сміхом,
Аби доля щаслива була!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1406828','Кіно','Музика: Максим Сиволап, Тарас Тополя Слова: Тарас Тополя. Виконує: АнтитілА','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Кіно! Це все якесь кіно.
Давно на нас хтось тестить
Новий світ ще раз... Я пас!
Я бачу дежавю в кімнаті на краю,
Будіть мене, мабуть, я сплю.

Приспів:
Мама! На лице бандана,
Ми ж не Далай-лама,
Один раз живем!
Живем! Живем!
Живем! Живем!
Мама! Чілим-чілим, мама.
Все буде нормально,
Все переживем!
Живем! Живем! Живем!

В куток, браваду у куток,
Кураж погас...
На паузі мій персонаж...
Хто ми? І в чому тут резон?
Як відповідь знайдем,
То все переживем разом!
Просто маленькі люди,
Просто такий сюжет...

Приспів.','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1406828'), datetime('now')),datetime('now'));
