INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1406828_l1','pisniua_1406828','YouTube','https://www.youtube.com/watch?v=B9gvM_-WYwo','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1406202','Дінь дон','Музика: Ірина Тарнавська Слова: Альона Карпина','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Різдвяний день вже починається,
Сніжинки людям посміхаються,
На гілці пташечка гойдається,
Святу Вечерю дожидається.

Приспів:
Дінь-дінь-дон!
В небі співають ангелики!
Дінь-дінь-дон!
Свято хай радістю їм стелиться!
Дінь-дінь-дон!
Святая Вечеря хай вдасться!
Дінь-дінь-дон!
У кожній родині щастя!

Вкраїна в ніч вся огортається!
Колядки всюди хай співаються
Весь світ сьогодні звеселяється,
Бо вже Ісус Христос рождається!

Приспів.

З небес нам зіронька всміхається,
І шлях до неба прокладається,
Молитва за столом читається,
На щастя нам Христос рождається!

Приспів.','["pisni.org.ua", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1406202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1406202','Дінь дон','Різдвяний день вже починається,
