INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1415529','Чому з тобою ми не хвилі?','Музика: Михайло Віятик Слова: Олександр Олесь. Виконує: Ґречна','uk','ukraine_1991',NULL,NULL,'https://grechna.com/','Романс на вірші Олександра Олеся "Чому з тобою ми не хвилі?" із фільму "Гріх". Обробка для фортепіано Михайла Віятика.','Чому з тобою ми не хвилі?
Удвох за руки ми б взялись
І в край щасливий полетіли,
Де ждала нас любов колись...

Чому не птахи ми з тобою?
Ми б не нудились на землі,
А над горою сніговою
З ясними хмарами жили!..

Чому ми й досі не здолаєм
Свого минулого забуть?..
Ми б в щасті чистім і безкраїм
Могли б, як в морі, утонуть...','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1415529'), datetime('now')),datetime('now'));
