INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_142303','Ой на Луці Зеленій','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: єлені - олені; кед - коли, як; мі - мені; поімати - упіймати; ты - ти.','Ой на Луці Зеленій   |(2)
Пасут ся там Єлені   |(2)

Проходит ся Яничек   |(2)
В Камизельці Зеленій |(2)

