INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1415505','Рідна школа','Музика: Віталій Богайчук Слова: Світлана Богайчук. Виконує: Тетяна Щербачук','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Тетяна Щербачук (альбом - Школа forever).','Де берізки й тополі довкола
У віночку з барвистих квіток,
Притулилася наша школа,
З нетерпінням чекає діток.
Кличе дзвоник дітей на уроки,
Нові вміння й знання здобувать,
А шановний учитель крізь роки
Буде шлях до наук відкривать.

Приспів:
Школо рідна Лісівська моя,
Наша дружна шкільна сім''я!
Зерна мудрості, знань, доброти
Щедро сієш в душу ти!..

Дні дитинства буденні й святкові
Тут минають в навчанні й труді,
Вчителі тут працюють чудові
І душею завжди молоді!
Друже наш, пам''ятай рідну школу,
Що в життя простеля світлу путь,
Ми прийдем, привітаємось знову,
Бо стежину сюди не забуть!

Приспів','["pisni.org.ua", "cat:shkilni", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1415505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1415505','Рідна школа','Де берізки й тополі довкола
