INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1423024','Де поділось літечко?','Музика: Ольга Янушкевич Слова: Марія Ясакова','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Де поділось літечко? - Я в усіх питаю.
Я веселе літечко цілий день шукаю.
Літечко, літечко, ти куди сховалось?     |
Чом зі мною, літечко, ти не попрощалось? | (2)

Ми з тобою, літечко, дуже гарні друзі,
Пригадай, як грілися на веселім лузі.
Відгукнися, літечко, де ти заховалось?   |
Чом зі мною, літечко, ти не попрощалось? | (2)

Каже мама: Літечко прийде за весною,
Дощиком прощалося літечко з тобою.
Підросту я, літечко, - як мене пізнаєш?  |
Як мене ти, літечко, в лузі відшукаєш?   | (2)','["pisni.org.ua", "cat:krasa-pryrody", "cat:nostalgia", "Пісні про красу природи", "Пісні з ностальгічними мотивами"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1423024'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1423024','Де поділось літечко?','Де поділось літечко? - Я в усіх питаю.
Я веселе літечко цілий день шукаю.
Літечко, літечко, ти куди сховалось?     |
