INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1414606','Колєда','Музика: Ірина Вихованець (Fiinka) Слова: Ірина Вихованець (Fiinka). Виконує: Ірина Вихованець (Fiinka)','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зима надворі, Різдво в календарі,
То найліпше свято в каждім місті і селі,
Ввечері пісне, зраня вже м''єсне,
Ліпше не вбиратисі на празники в тісне.
Купу пляцків ми напекли,
Бо родина має прийти,
І я тоже в гості піду,
Чуєш? Я до тебе йду, знаю нову колєду!

Приспів:
Колєд, колєд, колєда,
То шо студінь - не біда,
І від хати та й до хати
Будем ми усі свєта колєдувати!
Колєд, колєд, колєда,
Не кінчаїси їда,
І від хати та й до хати
Будем ми усі свєта колєдувати!

Зранє у двори купа дітвори,
Ти колєдничкові швидко двері утвори,
Колєду зачив - колєду скінчив,
Хто співав файніше - ше й до столу запросив.
Йдем до баби, бо то святе,
І кума мене в гості жде,
Під паху я флєшку беру,
Чуєш? Я до тебе йду, знаю нову колєду!

Приспів.

Кує мені зозулица, вилітає з гаю,
Та й дєкуєм за приймання сему господарю,
Та й дєкуєм за приймання, шо ви нас приймали,
Дай вам Боже многа літа, шоби-с ти діждали!

Приспів.','["pisni.org.ua", "cat:kolyadky", "cat:shchedrivky", "cat:suchasni-pisni-rizdvo", "Колядки", "Щедрівки", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1414606'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1414606','Колєда','Зима надворі, Різдво в календарі,
