INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_141725','Зелене Зелене коло Зеленого','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: бо-м - бо я; єден - один; засе - зась: не вільно, не можна; кін - кінь; лем - тільки; любувати - любити, кохати; мам, маш - маю, маєш; мя - мене; огваряти - обмовляти, знеславлювати; отава - трава, що виросла на місці скошеної; охота - бажання; паробок - парубок; перечко - перо на капелюсі; ти - тобі; ты - ти; тота - та, ота; тя - тебе; хоц - хоч; червене - червоне; шалене дівчатко - тут: дурненьке, недосвідчене; юж - вже.','Зелене Зелене коло Зеленого
Танцує Мій Милий а я коло Нього

Зелене Яблочко попід Гору скаче
Шалене Дівчатко за Миленьким плаче

Червене Яблочко попід Гору не скач
Шалене Дівчатко за Миленьким не плач

Не тота не тота Зелена не тота
Юж мя проминула за Милим охота

Сивий Кін Сивий Кін гей Отаву пасе
Єден мя любує а другому засе
Відміна:

Ты такий Яничку як Трава Зелена
Лем Тя приздобила Китайка Червена

Ты такий Паробок а я така Дівка
Ты не маш Перечка а я не мам Вінка

Ты не маш Перечка бо-м Ти не купила
Я не мам Віночка бо-м си не вивила

За то не огваряй мя Парадний Сину
Хоц Ты мя не возмеш я без Тя не згину','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_141725'), datetime('now')),datetime('now'));
