INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1417606','Друг','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Пісню виконує Софія Чайка (альбом - 53536666009).','Весело з другом співаю,
Із ним я весело граю.
Наша мелодія чиста,
Гарна і урочиста.
Стрибаєм ми весело з другом,
Співаєм ми про життя!
Коли нам стає усім сумно,
Ми вірим в своє майбуття!

Приспів:
З другом дуже весело
Співаєм ми про життя!
І коли ми сумуєм,
Співаєм ми про життя!

Як весело нам усім разом,
Знайшли нових друзів ми!
Стрибаємо ми весело,
І гарно співаємо ми!

Приспів.','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1417606'), datetime('now')),datetime('now'));
