INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1419127','Мамо, ніжно так тебе люблю я!','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Зранку прокидаюсь я від погляду твого,
Він теплом до мене ллється.
Цей чудовий світ існує лиш для нас обох,
Сонечко в тобі сміється!

Приспів:
Мамо, ніжно так тебе люблю я!
Мамо, і обожнюю тебе я!
Мамо, я без погляду твого,
Як птаха без крила!
Птаха без крила...
Мамо, ти для мене найрідніша!
Мамо, пригорни мене міцніше!
Мамо, дай зігрітись, мамо,
Від рук твоїх і серденька тепла!

Ти мені даруєш світ добра і теплоти,
Мамо рідна і єдина!
І для мене в цьому світі найдорожча ти,
Я - для тебе назавжди дитина!

Приспів.','["pisni.org.ua", "cat:pro-batkiv", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1419127'), datetime('now')),datetime('now'));
