INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1411909','Завітай, Миколай','Музика: Наталія Антоник Слова: Юлія Хандожинська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Там, де снігу гори, гори,
Де заметів не злічить,
На санчатах через поле
Миколай до всіх спішить!
З року в рік лише узимку,
З року в рік лише до свят
Чарівну свою торбинку
Він приносить до малят!

Приспів:
Завітай, завітай
В кожен дім, Миколай!
Завітай, добрим будь,
Ні про кого не забудь!

Тільки зіронька засяє,
Місяць в хмарках задріма,
Миколай в чарівну нічку,
Розпочне свої дива.
І слухняним, і нечемним
Він гостинці покладе
Та тихенько, посміхнувшись,
Щоб ніхто не чув, піде...

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:svyatyy-mykolay", "Дитячі пісні", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1411909'), datetime('now')),datetime('now'));
