INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1422127','Заметушечка','Музика: О. Козак Слова: О. Шевчук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я у мами одна, наче квіточка,
Коли вдома сама - беру віничка!
І кругом замету, наведу чистоту, |
Щоб ніде не було ні пилиночки!   | (2)

Приспів:
Мамочка моя, я - твоя донечка,
