INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1417909','Чому?','Музика: Олександр Пономарьов Слова: Олександр Пономарьов. Виконує: DZIDZIO, Олександр Пономарьов, ALEKSEEV, Артем Пивоваров','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Чому тебе раніше не зустрів?
