INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1424505','Вчитель','Музика: DZIDZIO Слова: невідомий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Альо, привіт присутнім!
До вас ми завітали
Без зошитів, книжок
І без щоденників.
Ось так!
Костюми повдягали,
Слова підготували,
Учителів вітати
Прийшли ми, як-не-як.
Ми зайві теревені
Культурно не розводим
І не жуємо жуйку,
Коли почавсь урок!
Ми просто Вам бажаєм,
Щоб збільшились доходи,
А ми, щоб не чекали,
Коли ж буде дзвінок!

Приспів:
Оу-я, оу-я-я,          |
Ваша праця нелегка,    |
Всі науки треба вам    |
Повкладать по головам! | (2)

Вчитель! Вчи-вчи-вчитель!
Вчитель! Вчи-вчи-вчитель!
Вчи, вчи, вчи нас!
Вчитель! Вчи-вчи-вчитель!
Вчитель! Вчи-вчи-вчитель!

Ми звилини на мозку
Конкретно напрягаєм,
Коли ваш погляд ніжно
Зупиниться на нас.
В душі ми невидимку
На себе одягаєм,
А вам так чемно кажем:
Подумать дайте час!
Вже місяць наші мізки
Посилено робили,
Всі набирались клепок,
Оцінок та ума!
Ми думали-гадали,
І так постановили:
"Учитель" звучить круто!
І сумнівів нема!

Приспів.

Вчитель! Вчи-вчи-вчитель!
Вчитель! Вчи-вчи-вчитель!
Вчи, вчи, вчи нас!
Вчитель! Вчи-вчи-вчитель!
Вчитель! Вчи-вчи-вчитель!
Вчи, вчи, вчи нас!
Вчитель! Вчи-вчи-вчитель!
Вчитель!','["pisni.org.ua", "cat:devoted", "cat:shkilni", "Пісні присвячені окремим особам", "Пісні про школу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1424505'), datetime('now')),datetime('now'));
