INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_142323','Кохання, я тебе, тебе вітаю!','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Спасибі, Вам, що Ви зі мною разом
Кохання зустрічаєте в житті,
Хай почуття жовтневим листопадом,
Як проліски зростають на весні!

Приспів:
Кохання, я тебе, тебе вітаю,
Хай десь далеко линуть журавлі,
Кохання, я тебе, тебе прохаю
Назавжди залишайся на Землі!

Дівоче серце, я тобі вклоняюсь
І молодість свою тобі дарю,
Звичайно, як і всі десь помиляюсь, -
Безгрішні не потрібні ми життю.

Приспів.

На сцені я і на шляху до мрії
Співаю Вам про мужність і красу,
І разом із козацьким вітром долі
Кохання в Ваше серце принесу!

Приспів','["pisni.org.ua", "cat:romansy", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_142323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_142323','Кохання, я тебе, тебе вітаю!','Спасибі, Вам, що Ви зі мною разом
