INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1429921','Осінь наступила','Музика: С. Насауленко Слова: С. Насауленко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Осінь, осінь наступила,
Листя осипаються,
Сонечка нема, стемніло,
Дощик починається...

Приспів:
Кап-кап на садочок,
Кап-кап на пеньочок!
Дощик, землю поливай,
З нами ти пограй!

Павучки, жучки та мушки
Всі летять, ховаються,
І в далекую дорогу
Пташечки збираються...

Приспів.','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1429921'), datetime('now')),datetime('now'));
