INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1426000_l1','pisniua_1426000','YouTube','https://www.youtube.com/watch?v=Lu3kc_P12no','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1434127','День подарунків','Слова: Роман Завадович','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коли святий Микола
З небес на землю йде,
То кожний дім і школа,
Мов вулик бджіл, гуде!

Там дітвора чекає
На срібних янголят,
Що із доріг безкраїх
На землю загостять!

Бо добре знають діти,
Що ні сніжний танок,
Ані мороз, ні вітер
Не спинять їх санок!

А на санках — подарки!
Ах, як багато їх!
Для Слави, для Одарки,
Для всіх! Для всіх!
Для всіх!

А тим, що пустували,
То чортик в темний кут
На пам''ятку поставить
Гнучкий з лозини прут!..','["pisni.org.ua", "cat:svyatyy-mykolay", "Пісні про Святого Миколая"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1434127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1434127','День подарунків','Коли святий Микола
З небес на землю йде,
То кожний дім і школа,
Мов вулик бджіл, гуде!

Там дітвора чекає
На срібних янголят,
Що із доріг безкраїх
На землю загостять!

Бо добре знають діти,
Що ні сніжний танок,
Ані мороз, ні вітер
Не спинять їх санок!

А на санках — подарки!
Ах, як багато їх!
Для Слави, для Одарки,
Для всіх! Для всіх!
Для всіх!

А тим, що пустували,
