INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1424828','Зачепила мене','Музика: Денис Ковальський Слова: невідомий','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Добрим людям на здоров''я,
Ми вітаємо вас з любов''ю,
Нам сьогодні добре було всім!
І це свято просто клас,
Вчителі, усе для вас,
Бо школа наша - рідний, рідний дім!
І як же не любити нам усім її,
Бо кращі роки тут проходять всі мої,
На все життя запам''ятаю, бо люблю
Школу мою! Школу мою!

Приспів:
Школа рідна моя, як люблю тебе я,
Ти до знань довела, все найкраще дала!
Зачепила мене, школа, ти за живе,      |
Я з тобою навік не на день, не на рік! | (2)

Зачепила мене!..

