INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1436529','З Новим роком, в добрий час','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'По світу полетіла
Сніжинка біла-біла,
Упала на долоні,
Розтанула за мить.
Шуміла завірюха,
Та хто її послухав.
Вже Новий рік сьогодні
У двері стукотить!

Приспів:
З Новим роком, в добрий час,
Ми вітаємо всіх вас!
З Новим роком, добрий день,
Всіх вітаємо людей!

Нехай добро прибуде,
У всіх здоров''я буде!
І Дід Мороз дарунки
Малечі роздає!
Хай сонце вам сміється!
Хай щастя вам ведеться!
Хай Бог усім любові
І радості дає!

Приспів.

З Новим роком, в добрий час,
Ми вітаємо всіх вас!
З Новим роком, добрий день!

Приспів.','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1436529'), datetime('now')),datetime('now'));
