INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1428725','Емігрант','Слова: Василь Чопей','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Добровільно свою я покинув країну,
Проявити хотів свій талант,
І поїхав в далеку, далеку чужину,
Мене звати тепер емігрант...

Приспів:
У чужину пірнув я, неначе в трясину,
І таких тут як я не один!..
Але що робити мені, коли я так люблю Україну,
Наче матір свою рідний син?!!

І талант все таки я зумів проявити,
Він мене навіть трішки підніс,
Але як мені рідний край не любити?
Край, де я народився і ріс?..

Приспів.

Емігрант - я, назавжди чужинець,
З цим тепер уже жити мені...
Зігріває мене тільки те тут, що я - українець!
Українські співаю пісні!

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1428725'), datetime('now')),datetime('now'));
