INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1438000','Гарно так','Музика: Vlad Chizhikov Слова: Vlad Chizhikov. Виконує: CHEEV','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знаєш, так чудово
