INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1438622','Колядуй, Україно!','Музика: Роман Скорпіон Слова: Роман Скорпіон. Виконує: Роман Скорпіон, YURIANA','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Господарю, відчиняйте,
Коляду Ви зустрічайте!
Колядує Україна,
Колядує вся Земля!
За столом уся родина,
Ми, від батька і до сина,
Прославляємо усі Христа!

Приспів:
Колядуй, Україно!  |
Колядуй, моя нене! |
Колядуй, Україно!  |
Колядуй, Земля!    | (2)

Тут стоїть кутя у хаті,
Щоб були Ви всі багаті,
Щоб були Ви всі щасливі,
І щоб був мир на Землі!
За столом уся родина,
Ми, від батька і до сина,
Прославляємо усі Христа!

Приспів.','["pisni.org.ua", "cat:kolyadky", "Колядки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1438622'), datetime('now')),datetime('now'));
