INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1441606','Гімн Безлюдівки','Музика: І. Зозуля Слова: Г. Земляний','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'У "Полі Дикім", на безлюдді,
