INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_143828','Ти, пластуне живи сам собою',NULL,'uk','ukraine_1991',NULL,NULL,'Збірник повстанських пісень "Ми у вічі сміялися смерті" видавницва "Азалія" 1992рік ст.17.','Слова цієї пісні я знайшов у збірнику повстанських пісень "Ми у вічі сміялися смерті" видавницва "Азалія" Рівненської організації Спілки письменників України. 1992рік. Там вона називається "Ми йдем у бій" тільки замість слів "ти, пластуне" записано "ти, юначе", та є ще декілька незначних відмінностей від поданих мною слів. Зазначено, що пісню записала Л.В.Велесик, уродженка с.Гутвин Костопільського району. Поблизу цього села був штаб "УПА-Північ", можливо пластуни, що були в УПА і навчили цієї пісні місцевих жителів. Так ця пісня "жила" в памяті людей поки не потрапила до збірника. Підбір акордів: Іруся Пігович','Ти пластуне живи сам собою,
В кожен мент буть готовий до бою,
Твій рідний край в неволі у кайданах,
Сочить кров в незагоєних ранах.

Приспів:
Підем в бій - всі як стій
За красу - за нарід свій
Гей же йдем, ідем, ідем, ідем. Гей!
Стяг побіди високо несемо!

Краю рідний за нас не журися
Лиш у наші серця  подивися
Там повно сили, віри незламної
Захистить від навали грізної.

Приспів.','["pisni.org.ua", "cat:plastovi", "Пластові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_143828'), datetime('now')),datetime('now'));
