INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1448505','Чекаю на тебе','Музика: Masha Kondratenko, Misha Averin Слова: Masha Kondratenko, Misha Averin','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Коханий, я сумую...
Засинаю кожну ніч
З телефоном в руках...
Я чекаю дзвінка,
І в моїх снах ми віч-на-віч...
Я гортаю наші фото,
Де по-справжньому живі,
Не цінували, що є,
Все шукали марне,
Не казали важливих слів...
Ти б знав, як хочу обійняти,
Як хочу, щоб закінчився цей сон!..
Нас лютий вирішив війною роз''єднати,
Забрав тебе на фронт...

Приспів:
Милий, я чекаю так на тебе!
Чекаю, що повернешся в наш дім!..
Коли ти бачиш зорі в синім небі -
То це я бережу тебе в війні!
Мій милий, я чекаю так на тебе!
Чекаю, що повернешся в наш дім!..
Я стану твоїм янголом у серці
І збережу тебе від ворогів!

Кожен день страшні новини,
Я вже не стримую сльозу...
Прокидаючись без тебе,
Це наче я тепер в бою...
Вдалині від свого міста,
Але вдома всеодно,
Незважаючи на відстань,
Ти захищатимеш наш сон!..
Ти б знав, як хочу обійняти,
Як хочу, щоб закінчився цей сон!..
Нас лютий вирішив війною роз''єднати,
Забрав тебе на фронт...

Приспів.','["pisni.org.ua", "cat:nostalgia", "cat:viyskovi", "Пісні з ностальгічними мотивами", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1448505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1448505','Чекаю на тебе','Коханий, я сумую...
Засинаю кожну ніч
З телефоном в руках...
Я чекаю дзвінка,
І в моїх снах ми віч-на-віч...
Я гортаю наші фото,
Де по-справжньому живі,
Не цінували, що є,
Все шукали марне,
Не казали важливих слів...
Ти б знав, як хочу обійняти,
Як хочу, щоб закінчився цей сон!..
Нас лютий вирішив війною роз''єднати,
Забрав тебе на фронт...

Приспів:
Милий, я чекаю так на тебе!
Чекаю, що повернешся в наш дім!..
Коли ти бачиш зорі в синім небі -
То це я бережу тебе в війні!
Мій милий, я чекаю так на тебе!
Чекаю, що повернешся в наш дім!..
Я стану твоїм янголом у серці
І збережу тебе від ворогів!

Кожен день страшні новини,
Я вже не стримую сльозу...
Прокидаючись без тебе,
Це наче я тепер в бою...
Вдалині від свого міста,
Але вдома всеодно,
Незважаючи на відстань,
Ти захищатимеш наш сон!..
Ти б знав, як хочу обійняти,
Як хочу, щоб закінчився цей сон!..
Нас лютий вирішив війною роз''єднати,
Забрав тебе на фронт...

Приспів.');
