INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1438606','Зима - красунечка','Музика: Наталія Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Летять сніжинки білі,
Летять сніжинки білі
І горнуться до матінки землі!
Усі кругом щасливі,
Усі кругом щасливі -
Нарешті дочекалися зими!

Приспів:
А зима, а зима,
Ти - красунечка,
Не барилася гостя зима!
А зима принесла
Подаруночки -
Ми чекали її не дарма!

Запалимо гірлянди
І розпочнеться свято,
І коло друзів прийде на поріг!
Радіють всі малята:
І хлопці, і дівчата,
Крокує довгожданний Новий Рік!

Приспів.','["pisni.org.ua", "cat:dytyachi", "cat:krasa-pryrody", "Дитячі пісні", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1438606'), datetime('now')),datetime('now'));
