INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1446725','Як ти?','Музика: Юлія Саніна, Валерій Бебко Слова: Юлія Саніна. Виконує: The Hardkiss','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Боже,
Залиш мені трохи сили,
Мій холодний розум
Затоплює люті злива...
Я не просила, не просила
"Рятувати" мене кулями!..
Той, хто прийшов, проросте
Тут травою отруйною!
Поміняли мрії на приціл,
Я тримаю твою руку в своїй руці,
Наші сльози на першій шпальті,
А я знову питаю:
Мамо, як ти?!!
Мамо, як ти?!!
Як ти?!!

Люди з кривавими рукавами
Руйнували храми,
Але Бог літав між нами!..
Очі дитини моєї країни
Вмить стали дорослими,
А я стала скелею,
Серце лишилося вдома
Під соснами.
Я питаю:
Мамо, як ти?!!
Мамо, як ти?!!
Мамо, як ти?!!
Мамо, як ти?!!
Як ти?!! Як ти?!!','["pisni.org.ua", "cat:viyskovi", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1446725'), datetime('now')),datetime('now'));
