INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_14505','За муром одцвіли каштани','(Чи чуєш Юрку?). Музика: невідомий Слова: Богдан Кравців','uk','ukr_ssr_1919_1991',NULL,'1933','http://proridne.com/','Автор музики невідомий. Текст написав Богдан Кравців з присвятою Юрієві Дачишину (липень-серпень 1933 р.), у львівській в''язниці "Бригідки". Ю. Дачишин був арештований у 30-х роках за приналежність до ОУН і засуджений до 20 років тюрми. Кравців потрапив у камеру, де сидів Юрко. І. Камінська (сама в''язень польських тюрем) подає: "У 40-50 роках це була найбільш популярна і душевна пісня у польських жіночих в''язницях. Ми співали дещо змінений текст... Я особисто ніколи не припускала, що зустріну Юрія з пісні. Свою історію розказав мені особисто Юрій Дачишин, який проживає в Чикаго з досить слабким здоров''ям, але ще з сильним духом". Б. Кравців - поет, літературознавець, нар. 1904 р., із Західної України, редактор націоналістичних видань. Помер в Америці. За волю України. Антологія пісень національно-визвольних змагань. Упорядник Євген Гіщинський. - Луцьк: Видавництво "Волинська обласна друкарня", 2002. - 316 с.','Чи чуєш, Юрку? - "Чую, друже"...
Бували лепські гулянки...
Мені ще двадцять зим в''язничних
Отак дзвенітимуть дзвінки.

За муром одцвіли каштани,
І вільний вітер залюбки
До мене в келію заносить
Останні білі пелюстки.

Спалився й витлів юний липень,
І серпень вигорів до тла,
І літо бабине снується
Тендітним прядивом срібла.

Вже крильми осінь має, лине
І вже десь золоті гаї,
І вже янчання журавлине
Об грати вдарило мої.

Над містом - ніч і шум, і гомін,
Із снігом біла заметіль,
І вже санковими дзвінками
Доносить молодість звідсіль.

Як звірі простір, ми любили
Блакиті далечі й сади,
І хижу волю, й вовчі ходи
В лютні тривожні холоди.

І нині нам - як звірам в клітці,
І хід розміряний у лад.
Чотири кроки, все чотири -
Туди й назад, туди й назад.

Колись, як будні серце здавлять,
І зрадить волю друг і брат,
Я, знаю, буду банувати
За днями, що в плетінні ґрат.

За ночами суворих келій,
Налитих померками вщерть,
Де йдуть юнацькі роки друзям,
Де усміхом стрічають смерть.

Дивлюся, друзі, аж вже сниться
Й, здається, радісно мені,
Бо, може, й вам коли прийдеться
Почуть з-за ґрат оці пісні','["pisni.org.ua", "cat:43", "cat:druzhba", "cat:povstanski", "cat:suspilno-politychni", "Еміґрантські пісні", "Пісні про дружбу", "Повстанські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_14505'), datetime('now')),datetime('now'));
