INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1458101','Вистоїмо!','Музика: Світлана Тарабарова, SOFIA Слова: Світлана Тарабарова, SOFIA. Виконує: TARABAROVA, SOFIA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тобі здається, що ти тут один,
І побратим взривається від мін,
Будинки сипляться,
І вже без стін моя душа...
Цей теплий вітер, як дитинства мить,
Очі закриєш, а вона щемить...
Як птах за волею вперед летить
Моя душа, твоя душа...

Приспів:
І ми вистоїмо!
Вдихаємо силу із повітря!
Вистоїмо! Не бійся!
Ти є моє світло!
Ми на стороні добра!
Ми на стороні добра!
Вистоїмо!
Чуєш, брат! Чуєш, сестра!
І ми вистоїмо!
І ми вистоїмо!
І ми вистоїмо!
Чуєш, брат! Чуєш, сестра!

За нами світло, маємо пройти
Крізь дим і втому, спалені мости.
Розправим крила і розквітне знов
моя душа,
Цей теплий вітер, як дитинства мить,
Очі закриєш, а вона щемить...
Як птах за волею вперед летить!..

Приспів.','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1458101'), datetime('now')),datetime('now'));
