INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_145323','Припадаю до Тебе мій Христе','Музика: невідомий Слова: церковна пісня','uk','ukraine_1991',NULL,NULL,NULL,'Пісню введено на сайт на пам''ять про нашу мамку. http://www.book.dkz.info/mamka.htm також слухайте: "Чому твої очі..."','О, світла правдо вічного життя,
О, незбагнена мудросте любові,
Прийди у наші зболені серця,
В святому Тілі, в найсвятішій Крові! | (2)

Приспів:
Припадаю до Тебе, мій Христе,
Щоб позбутись пекельних оков,
Чиста Крове і Тіло причисте,
В моїм серці замешкайте знов!        | (2)

Спаситель сам обійми нам відкрив
І рожі перетворюються в терня -
Тож блудний син вернувся бо прозрів,
І на колінах просить про прощення.   | (2)

Приспів.

Ягня покірне і, страшний судде,
Небесна славо, і, спасіння світу,
Допоки суд Твій праведний гряде,
Прийми нас грішних під Твою опіку.   | (2)

Приспів','["pisni.org.ua", "cat:cerkovni", "cat:christian", "cat:strasni", "Церковні пісні", "Пісні на християнську тематику", "Страсні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_145323'), datetime('now')),datetime('now'));
