INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1466808','Там, під Львівським замком','Українська народна пісня. Виконує: Фольктеатр Остапа Стахіва','uk','ukrainian_peoples_republic_1917_1921',NULL,NULL,'аудіозапис',NULL,'Там, під львівським замком,
Старий дуб стоїть.
А під тим дубочком
Партизан лежить.

Він лежить не дише,
Він неначе спить.
Золоті кучері вітер
Шевелить.

А над ним старенька
Матінка стоїть.
Плаче, сльози лиє,
Стиха говорить:

Як ти був маленьким,
Батько воював.
Він за Україну
Голову поклав...

А позаду неньки
Командир стоїть.
До матусі стих
Слова говорить:

Не плач, стара мати,
Син героєм став,
Він за Україну
Голову поклав!..','["pisni.org.ua", "cat:povstanski", "cat:strilecki", "Повстанські пісні", "Стрілецькі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1466808'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1466808','Там, під Львівським замком','Там, під львівським замком,
