INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1463529','Розбиті траси','Музика: Олександр Положинський, Іван Марунич Слова: Олександр Положинський. Виконує: Ол.Ів.''Є','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Це все сталось зі мною,
Мене кликали мандри,
А я залишався собою,
Я був невблаганним.
Все змінилось раптово,
Різко перемикнулось,
Щось прийшло випадково,
Інше забулось...

Приспів:
Я швидко втікаю розбитими трасами,
Я швидко втікаю з обіймів пітьми,
Із місць, де колись ми ставали нещасними,
В місця, де щасливими стали не ми...

Бачу, сонце яскраве
Сходить над горизонтом,
Займаюся з чашкою кави
Саморемонтом...
Відкриваю країни,
Дивлюся на перспективи,
Для чергової зміни
Потрібні активи.

Приспів.

Люди, картини, події -
Зміни в калейдоскопі,
Вчора був в Антарктиді,
Завтра - в Європі.
Де б мене не носило,
Як би мене не кидало,
Завжди знайдуться сили,
І все буде мало!

Приспів.','["pisni.org.ua", "cat:manrivni", "Пісні на мандрівну тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1463529'), datetime('now')),datetime('now'));
