INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1467707','Ой, там на Вкраїні','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис',NULL,'Ой, там на Вкраїні зорі засвітили,
Вони в кожній хаті новину звістили.
Хлопці молоденькі, разом повставайте,     |
Пісню про недолю разом заспівайте.        | (2)

Полягли герої в крові по коліна,
Но зате воскресне славна Україна!
Воскресла Вкраїна, буде панувати,         |
А на тії кровці буде дух зростати!        | (2)

Буде дух зростати хлопцям молоденьким,
Щоб ся відплатили ворогам тяженьким!
Бо тії вороги то є гниль проклята,        |
Не одна дитина лишилась без тата...       | (2)

На тім ми кінчаємо колядувати,
Будем на цім слові вас поздоровляти:
Здоровим вас, діти, і батька, і неньку,   |
За злих нас не майте хлопців молоденьких! | (2)','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1467707'), datetime('now')),datetime('now'));
