INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1469505','До Перемоги!','Музика: GREMO Слова: GREMO','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Згадай день, коли ти
Був щасливий, жив без війни!
Згадай день, де за обрій
Сонце сідає в твоєму вікні!
Одна мрія на всіх сильна,
Як моноліт,
В грудях твоїх і моїх:

Приспів:
До Перемоги
Пліч-о-пліч будем ми йти!
Кожен з нас - воїн
На своїй землі!
До Перемоги
Ми Україну приведем!
Тримайся!
Всіх їх переживем!

Пам''ятай, що твій дім -
Це не стіни, це люд і гімн!
Спільний дім - наша Україна!
Я поруч! Знай, ти не один!
Об''єднали весь світ
Ми - всієї нації цвіт!
Слава Героям навік!

Приспів.','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1469505'), datetime('now')),datetime('now'));
