INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_146220','Зацвіла ружа трояка','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Записав П. Лінтур 1963 р. в с. Запереділля від Василини Белі. П. Лінтур: Народні балади Закарпаття. - Львів, 1966. - С. 229-231',NULL,'Зацвіла ружа трояка          |(2)
Мала я мужа, мужа я мала,        |
Мала я мужа пияка                |(2)

Він нич не робить тілько п''є |(2)
Прийде додому, додому прийде,    |
Прийде додому, мене б''є          |(2)

Не бий ня, мужу, не карай    |(2)
Лишу ти діти, діти ти лишу,      |
А сама піду за Дунай             |(2)

Коли на човен сідала,        |(2)
Білом хусточком, хусточком білом,|
Білом хусточком махала           |(2)

Вернися, жоно, додому,       |(2)
Діти ти плачут, плачут ти діти,  |
Діти ти плачут за тобом          |(2)

-Хоть най плачуть, хоть не плачут, |(2)
Я не вернуся, з-за тебе в землю, |
З-за тебе в землю пропаду        |(2)

Кобы-сь не пив, мене не бив, |(2)
Любила бы-м тя, бы-м тя          |
Любила, твої чоботи носила       |(2)

-Не бий ня, мужу, не бий ня, |(2)
Твої чоботи, чоботи твої,        |
Буду носили, люби ня!            |(2)','["pisni.org.ua", "cat:socialno-pobutovi", "cat:zakarpatski", "Соціально-побутові пісні", "Закарпатські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_146220'), datetime('now')),datetime('now'));
