INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_146505','Я сой Хлопец Справедливий','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Лемківські співанки. Зібрав і упорядкував М. Соболевський. — К.: Музична Україна, 1967. — 320 с.','Пісня з добірки М.Соболевського: Лемківські співанки Діалектизми: быц - бути; віст - знає; лем - тільки; мі - мені; мя - мене; никто - ніхто; нич - нічого; пиц - пити; повіст, повідати - розкаже, розказувати; под - ходи, йди; пугар - келих, чарка; сой - собі; ты - ти; хоц - хоч; хцем - хочу фраїречка - дівчина, з якою ходить хлопець; юж - вже.','Я сой Хлопец Справедливий |
Никто на мя нич не віст   |(2)
Лем та Моя Фраїречка    |
Але Она не повіст       |(2)

Хоц бы хтіла повідати     |
Але Она не може           |(2)
Сама мене закликала     |
Под Яничку Небоже       |(2)

Сама мене закликала       |
До Комори до свойой       |(2)
Наляла мі Пугар Вина    |
До Ручечки до мойой     |(2)

Наляла мі Пугар Вина      |
Казала мі випити          |(2)
Випий-випий Мій Яничку  |
Завтра будеш убитий     |(2)
Відміна куплета 2:
Хоц бы мала повідати      |
Сама тому причина         |(2)
Сама мене закликала     |
Под Яничку до Сіна      |(2)

Відміна закінчення:
Я сой Хлопец Справедливий |
Я то Винко не хцем пиц    |(2)
Юж Ты Моя Наймилейша    |
Юж Ты Моя мусиш быц     |(2)','["pisni.org.ua", "cat:lemkivski", "Лемківські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_146505'), datetime('now')),datetime('now'));
