INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1467404','ЗСУ','Музика: Не Ждали Слова: Не Ждали','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сталось та як склалось,
Що горить кругом земля,
Орди орків йдуть на наші
Рідні степи і поля.
Лиха не боїмося,
Разом орків будем бить!
Станем всі за нашу землю,
Нашу волю не зломить!
Харків, берці, бронік,
Каска, в руки автомат,
На позиції тримаємось
І не здамо назад!
Влучно стріляють,
Тільки подавай патрони!
Гідно ворога зустрінуть
Пацани з тероборони!  | (2)

Воїн це професія серйозна
Без прикрас,
Гартує вправно зброю
І виконує наказ.
Мужні вояки -
Нащадки славних козаків!
Сильні і безстрашні
Зупиняють ворогів!
Постріли лунають,
Кулі потрапляють в ціль,
Орків розганяти
Їде Бандеромобіль!
Знищать в небі, полі,
Не залишать на плаву,
Гідно ворога зустрінуть
Пацани із ЗСУ!        | (2)

Кращі дівчата
Україну бережуть!
Взяли в руки зброю -
Тож нікому не здадуть!
Гарну вроду мають
І чарівні голоси,
Згинуть кляті орки
І від вбивчої краси!
Воїни безстрашні
Один одного тримають,
І справжні українці
Завжди всіх перемагають!
Стануть брат за брата
І завжди прикривають спину,
Гідно ворога зустрінуть
Збройні сили України! | (5)','["pisni.org.ua", "cat:ato", "cat:devoted", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1467404'), datetime('now')),datetime('now'));
