INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_147127','За нашою слободою','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Українське народне багатоголосся. — К., 1963. — С. 332.',NULL,'За нашою слободою (2)
Росте жито з лободою.

Ой там Ганя жито жала, (2)
В правій руці серп держала.

В правій руці серп держала, (2)
А лівою підбирала.

А лівою підбирала,— (2)
Назад себе снопи клала.

Назад себе снопи клала,— (2)
На шлях битий поглядала.

На шлях битий поглядала, (2)
Василечка виглядала.','["pisni.org.ua", "cat:podilski", "Пісні з Поділля"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_147127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_147127','За нашою слободою','За нашою слободою (2)
Росте жито з лободою.

Ой там Ганя жито жала, (2)
В правій руці серп держала.

В правій руці серп держала, (2)
А лівою підбирала.

А лівою підбирала,— (2)
