Василечка виглядала.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1469828','Від Різдва до Різдва','Музика: Ярослав Баран Слова: Ярослав Баран. Виконує: Ярек','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хочеш вірити у казку
Від Різдва до Різдва?..
І завдати злу поразку
Від Різдва до Різдва?..
Хочеш сам створити диво
Від Різдва до Різдва?..
Тож вставай і будь щасливим
Від Різдва до Різдва!

Приспів:
Від Різдва до Різдва
Всі разом в святковім хорі!
Від Різдва до Різдва
Хай дивують навіть зорі!
Від Різдва до Різдва
Мир між нами запанує!
Від Різдва до Різдва
Усі разом колядуєм!

Хочеш вірити у мрії
Від Різдва до Різдва?..
Якщо вмієш, чи не вмієш
Від Різдва до Різдва?..
Тож рушаємо в дорогу
Від Різдва до Різдва?..
Лише разом, лише з Богом
Від Різдва до Різдва!..

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1469828'), datetime('now')),datetime('now'));
