INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1478529','Піхота','Музика: Юрій Журавель Слова: Юрій Журавель','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тут начебто все просто,
Для творчості є простір,
АК, БК, гранати і лопата,
Стратегія і тактика -
За клаптиком клаптик
Вкраїну рідну жилами латати!
Я знаю тут кожен шматочок землі  |
На запах, на смак і на дотик,    |
Тому що периметри цих територій  |
Вимірюють кроком піхоти!         | (2)

Тривалий час не вдома
Потрохи усвідомив:
В руках моїх і зброя, і майбутнє!
Но права її пруть,
Потреба скрізь і всюди,
Просохнемо і знову в сухопутній!
Але я не заздрю героям-братам,   |
А втім, морякам і пілотам,       |
Тому що периметри цих територій  |
Вимірюють кроком піхоти!         | (2)

Техніка ворожа на купу гною схожа,
Проймають до кісток знайомі звуки.
Це дітлахи з підвалу кричать:
Героям Слава!
І стрімголов стрибають нам на руки.
Стара берегиня нас радо зустріне |
Гарячим борщем і компотом,       |
Тому що периметри цих територій  |
Вимірюють кроком піхоти!         | (2)

Тут начебто все просто,
Для творчості є простір,
АК, БК, гранати і лопата,
Стратегія і тактика -
За клаптиком клаптик
Вкраїну рідну жилами латати!
Я знаю тут кожен шматочок землі  |
На запах, на смак і на дотик,    |
Тому що периметри цих територій  |
Вимірюють кроком піхоти!         | (2)','["pisni.org.ua", "cat:devoted", "cat:viyskovi", "Пісні присвячені окремим особам", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1478529'), datetime('now')),datetime('now'));
