INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1467725','Тиха ніч, свята ніч','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'аудіозапис',NULL,'Тиха ніч, свята ніч,
Срібним сяйвом іскрить сніг,
Чаром тиші мріє ліс,
Божий Син нам мир приніс:
Всім народам на землі
І усій вселенній!

В тиху ніч, в святу ніч
Над Дніпром мріє Січ -
Дух Хортиці до життя
Нам відроджує УПА:
Сина Бога вітає -
"Слава во вишних" співає!

В тиху ніч, в святу ніч,
Народилась знову Січ -
І за правду, і любов,
розірвати міць оков
Стала на сторожу
Нам за волю гожу!

Тиха ніч, свята ніч
Заклика синів на Січ:
Гей, народи, ви не спіть,
А про волю-долю сніть -
Гнати вам зайдів із хати,
Боже Дитятко прийняти!','["pisni.org.ua", "cat:povstanski", "Повстанські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1467725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1467725','Тиха ніч, свята ніч','Тиха ніч, свята ніч,
