INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1472220','Слава нашим ЗСУ!','Музика: Олеся Май Слова: Наталія Май','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Слава нашим ЗСУ
Й вільному народу!
Бо немає переводу
Козацькому роду!
Слава нашим ЗСУ!
Буде мир та згода!
Бо немає переводу
Козацькому роду!

Ой, у полі калинонька
Файно розцвітає,
Наші хлопці - соколоньки
Всіх перемагають!
Буде нашим козаченькам
Слава по заслузі!
Не зламати червоненьку
Калину у лузі!

Приспів.

Ой, у полі криниченька,
А в саду калина,
Наші хлопці козаченьки -
Гордість України!
Хай від кулі вас молитва
Завжди захищає
І нехай в лиху годину
Бог оберігає!

Приспів.

Неспокійними ночами,
Посивівші від війни,
Молитви шепочуть мами,
Просять Бога за синів!

Приспів.','["pisni.org.ua", "cat:ato", "cat:devoted", "cat:patriotic", "cat:pro-batkiv", "cat:pro-ditey", "cat:viyskovi", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам", "Патріотичні пісні", "Пісні про любов до батьків", "Пісні про любов до дітей", "Пісні на військову тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1472220'), datetime('now')),datetime('now'));
