INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1474622','Друже Залужний','Музика: Юрій Галич Слова: Степан Галябарда','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Плюндрує Вкраїну москаль осоружний,
Немає спокою від хижих заброд...
Гартуйся у битвах, мій Друже Залужний, |
Тобі Перемогу довірив народ!           | (2)

Твій хист і уміння й душа патріота
Злились воєдино, щоб ворога бить!
З тобою, натхненні, за ротою рота,     |
Йдемо в смертний бій,                  |
Щоб по-людськи нам жить!..             | (2)

Твоє серце рветься від болю і злості
За спалені мрії, розстріляні сни...
Та згинуть ординці,                    |
Згниють тут їх кості,                  |
Щоб хтось не посіяв знов бурю війни.   | (2)

Тобі не страшні поза спиною змови,
І їхні потуги усі замалі...
Мій Друже Залужний,                    |
Придумай щось знову,                   |
Щоб вигнати орків з моєї землі!..      | (2)

Плюндрує країну москаль осоружний,
Але Перемога за нами таки!
Тож будьмо незламні,                   |
Мій Друже Залужний,                    |
На Славу Вкраїні, на вічні віки!       | (2)','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1474622'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1474622','Друже Залужний','Плюндрує Вкраїну москаль осоружний,
