INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1474622_l2','pisniua_1474622','YouTube','https://www.youtube.com/watch?v=qIUuDAIRtgM','video',NULL,2);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1484220','Як ласкаво дивиться Марія','Музика: Галина Капріян (Amelika Ocean) Слова: Галина Капріян (Amelika Ocean)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Як ласкаво дивиться Марія,
Скільки спокою в Її очах,
В них - моя Любов, моя Надія,
Відступає біль, зникає страх!..
Я дивлюсь на Неї й гірко плачу,
Падаю під тяжкістю гріха,
А Вона молитов моїх нестачу
У Любові тихо відняла.

Приспів:
Молиться за нас Свята Невіста, |
Ще не було, щоб не помогла!    |
Радуйся, Маріє, Діво Чиста!    |
Ти смиренням світ перемогла!   | (2)

Я схилю коліна перед Нею,
Пресвятая Діво, поможи!
Все життя невгасною зорею
До Спасіння Ти мене веди!
Мов дитина, я піду з Тобою,
Не відпустить Матінки Рука!
Твоїх вуст молитвою святою
Повернусь до Господа Христа!

Приспів. (2)

Ти смиренням світ перемогла!
Я ж до Тебе, Матінко, прийшла!','["pisni.org.ua", "cat:christian", "Пісні на християнську тематику"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1484220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1484220','Як ласкаво дивиться Марія','Як ласкаво дивиться Марія,
Скільки спокою в Її очах,
В них - моя Любов, моя Надія,
Відступає біль, зникає страх!..
Я дивлюсь на Неї й гірко плачу,
Падаю під тяжкістю гріха,
А Вона молитов моїх нестачу
У Любові тихо відняла.

Приспів:
Молиться за нас Свята Невіста, |
Ще не було, щоб не помогла!    |
Радуйся, Маріє, Діво Чиста!    |
Ти смиренням світ перемогла!   | (2)

Я схилю коліна перед Нею,
Пресвятая Діво, поможи!
Все життя невгасною зорею
До Спасіння Ти мене веди!
Мов дитина, я піду з Тобою,
Не відпустить Матінки Рука!
Твоїх вуст молитвою святою
Повернусь до Господа Христа!

Приспів. (2)

Ти смиренням світ перемогла!
Я ж до Тебе, Матінко, прийшла!');
