INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1477622','Ворога поборемо','Музика: Kozak Siromaha, V. Samoliuk, S. Chornyi, A. Vdovychenko Слова: Kozak Siromaha, Volodymyr Samoliuk, Manya Dorichenko','uk','ukraine_1991',NULL,NULL,'аудіозапис','Lyrics by: Kozak Siromaha, Volodymyr Samoliuk, Manya Dorichenko. Music by: Kozak Siromaha, Volodymyr Samoliuk, Stas Chornyi, Andrii Vdovychenko.','Прийдуть скоро часи ще хороші,
I ми хором
Співать будем пісні Божі!
Піде ворог і не вернеться
Не смердітиме порох,
Куля не полетить в серце!

