INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1479707','Чудово, що сьогодні ми зійшлись','Музика: Олег Митяєв Слова: Олег Митяєв','uk','ukraine_1991',NULL,NULL,'авторське подання','Переклад Віктора Леві.','І знов струни гітари
Чиясь рука торкнеться,
Струни стрімке відлуння
Злетить стрілою ввись.
І зоряне все небо
Від того колихнеться,
Чудово, що всі разом
Тут сьогодні ми зійшлись!..

Відбився захід сонця
У нашому багатті...
Що  зажуривсь, друзяко?
Ану, давай, всміхнись!
І хтось тобі найближчий
Журбу твою розрадить:
Чудово, що всі разом
Тут сьогодні ми зійшлись!..

І все ж із болем в горлі
Ми тут усіх згадаєм,
Кого в життєвих битвах
Ми втратили колись...
Пісні та мрії їхні
За них ми доспіваєм.
Чудово, що всі разом
Тут сьогодні ми зійшлись!..','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1479707'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1479707','Чудово, що сьогодні ми зійшлись','І знов струни гітари
