INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1481202','Вона','Музика: Ігор Татаренко Слова: Ігор Татаренко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Ранок. Кава. Амстердам.
Знов питання небесам:
Чому вона тут
І за що він там?..
Чом послухала його?..
Чом лишила одного
Дивитись у вічі війні
Сам-на-сам?..
А вона, а вона до нього,
Як ніколи ні до кого,
Йшла б не боячись нічого
Босоніж по втомленій землі!..
А вона, а вона за нього,
Як ніколи ні за кого,
По ночам молила Бога,
Щоб він ніжно обійняв її,
Коли настане наша перемога
В цій важкій війні!

Ранок. Стелиться туман.
Він знесилений від ран,
В руці телефон,
Погляд в екран...
Чом він не подзвонив
Цій, яку він так любив,
Залишивши тут на землі
Її сам-на-сам?..
А вона, а вона до нього,
Як ніколи ні до кого,
Йшла б не боячись нічого
Босоніж по втомленій землі!..
А вона, а вона за нього,
Як ніколи ні за кого,
По ночам молила Бога,
Щоб він ніжно обійняв її,
Коли настане наша перемога
В цій страшній війні!
Він повернеться, щоби знову
Ніжно обійняти її!..
Як ніколи і нікого!..
І скільки ж нас таких?..
Та вона тепер без нього...
Сильних та незламних
Українських жінок...','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1481202'), datetime('now')),datetime('now'));
