INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1480323','Мій син','Музика: Ванда Дріневська Слова: К. Вовчук. Виконує: Ванда Дріневська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'В ту мить, коли з''явився ти на світ,
Багатовіковий розтанув лід,
I пролилось сльозами щастя на землі...
У світлі чистоти в твоїх очах
Любов моя долає біль і страх!..
І тануть, наче тінь, тривоги і жалі...

Приспів:
Мій син!
Ти - радість мого серця,
Мій син!
Для тебе воно б''ється
І все чого бажаю я
Тобі!
Нехай тобі все вдасться,
Мій син!
Молюсь за твоє щастя,
Мій син!
В тобі моє життя!

Мені тебе Господь подарував,
Щоб гідним чоловіком ти зростав,
А серце материнське сили докладе,
Аби тобі відкрити шлях без меж,
Де ти свою дорогу прокладеш,
До бажаного щастя хай вона веде!..

Приспів.','["pisni.org.ua", "cat:pro-ditey", "Пісні про любов до дітей"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1480323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1480323','Мій син','В ту мить, коли з''явився ти на світ,
