INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1480323_l1','pisniua_1480323','YouTube','https://www.youtube.com/watch?v=HOeuEO_qSbk','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1482127','Форма війни','Музика: Іван Поклонський Слова: Іван Поклонський','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Тобі личить так форма воїна,
Ллється венами кров нескорена,
Ти незламна як предки трипільські,
Завжди в серці любов материнська!
Ти відроджена карою нелюдів
І пророчена смертю катів,
Жах несеш для ворожих урядів,
Стала прикладом світу братів!

Приспів:
Дівочу сукню на броню та зброю,
Змінила щастя на біду весною,
Та твої очі в балаклаві сяють,
Мрію не відберуть! І зозуля у путь
Ніжно так проводжає. Най кукує у путь!..

Залишена доля у полі, де квіти,
Залишено світле життя,
А зараз руїнами граються діти...
Хто ж знав, що таке майбуття?..
Тепер вона дивиться ворогу в очі,
Курок - не тремтить вже рука!
За мирнії дні та спалені ночі
Це плата та помста гірка!..

Приспів.

Речитатив:
Через біль та відчай посмішкою сяє,
Хоч складне завдання, слухавку тримає:
Ало, мам, жива я!
Як ти?
Все в порядку!..
Я молюсь за тебе! Ти тримайсь, дівчатко!

Приспів.','["pisni.org.ua", "cat:ato", "cat:devoted", "cat:pro-ditey", "cat:viyskovi", "cat:zahalni-cinnosti", "Пісні російсько-української війни та АТО", "Пісні присвячені окремим особам", "Пісні про любов до дітей", "Пісні на військову тематику", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1482127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1482127','Форма війни','Тобі личить так форма воїна,
