INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1490808','Він не любив Україну','Музика: The Кум Слова: Сергій Фаліон','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Москаль непомитий прийшов мене вбити,
Загадити простір і вкрасти мій простір,
Та весь помістився у пральну машину,
Бо він не любив Україну!
Бурят вузькоокий пристроївся збоку
І вперше побачив він буду собачу.
Візьму закопаю його під калину,
Бо він не любив Україну!

Приспів:
Він не любив Україну!
Пісню її солов''їну,
Гори і полонини!
Тут перетвориться в глину!

Кацап на світанку давив мене танком,
На БТР-і ломився у двері,
Підсмажив у сраку його Джавелін-ом,
Бо він не любив Україну!
Руська падлюка протягує руки
До всього святого, протягне і ноги.
Сокиру встромив між лопаток у спину,
Бо він не любив Україну!

Приспів. (2)

Прийшли, як туристи, російські фашисти,
Хотять голодрані парад на майдані.
Та кожен отримав свою домовину,
Бо він не любив Україну!

Приспів. (2)

Він не любив Україну!
Він не любив Україну!
Він не любив Україну!','["pisni.org.ua", "cat:ato", "cat:zahalni-cinnosti", "Пісні російсько-української війни та АТО", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1490808'), datetime('now')),datetime('now'));
