INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_148606','Без тучі без грому','Українська народна пісня. Виконує: Буття','uk','ukraine_before_1917',NULL,NULL,'1. http://www.buttia.kiev.ua/reper_2001.html',NULL,'Без тучі, без грому сам дощик іде.
Козак до Марусі щовечора йде.

Козак до Марусі щовечора йде,
Марусина да серце, порадуй мене!

Марусина да серце, порадуй мене,
Чи мені жениться, чи брати тебе?

На другую весну калина цвіла,
Йосталась Маруся да й ще й не сама.

Йосталась Маруся да й ще й не сама,
Йосталась в Марусі дитина мала.','["pisni.org.ua", "cat:poliski", "Пісні з Полісся"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_148606'), datetime('now')),datetime('now'));
