INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1498000','Валторна','Музика: PIVOVAROV Слова: Ліна Костенко, Артем Пивоваров','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'А в сірі будні буду     |
Бити, як в бубни, буду. |
Мені дуже легко,        |
Мені дуже трудно..      | (2)

Чорна ніч               |
Інкрустована ніжністю,  |
Горизонт піднімає       |
Багряним плечем день... | (2)

Любов неповторна,       |
Моя ти валторна.        |
Шляхи прощальні,        |
Перша скрипка печалі... | (4)

А в сірі будні буду     |
Бити, як в бубни, буду. |
Мені дуже легко,        |
Мені дуже трудно..      | (2)

Еволюція гусячих пер,
Філософій забрьоханий німб
Слово — прізвище думки тепер,
А частіше — її псевдонім...
То чого ж я шукаю і чим я жива?!
Велемовний світ, велелюдний...
Ви поезія, вірші?
Чи тільки слова?
Горизонт піднімає
Багряним плечем день,
Як нотну сторінку вічності,
Що сьогодні...

Любов неповторна,       |
Моя ти валторна.        |
Шляхи прощальні,        |
Перша скрипка печалі... | (4)','["pisni.org.ua", "cat:philosophic", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1498000'), datetime('now')),datetime('now'));
