INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1502505','Весняночка','Музика: Галина Заботіна Слова: Оксана Пічугіна','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Ми за руки взялися
На лужку,
Повели весняночку
