INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_148622','Там на горі є терен','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'виконання гурту Papalotl, автор проекту – Євген Манко, він же Скарамуш scaramousche.livejournal.com','Там на горі є терен, нема більше лиш один...
Да гей, уха-ха, нема більше лиш один...

А з-за того терена вийшла вдова молода
Да гей, уха-ха, вийшла вдова молода

Вийшла вдова молода, що зродила синів два
Да гей, уха-ха, що зродила синів два

Що зродила синів два - Орасима й Василя
Да гей, уха-ха, Орасима й Василя

Орасима й Василя в тихий Дунай пустила
Да гей, уха-ха, в тихий Дунай пустила

Ой ви круті береги, тримайтеся два сини
Да гей, уха-ха, тримайтеся два сини

А ти, жовтий пісочок, годуй моїх діточок,
Да гей, уха-ха, годуй моїх діточок

Через років двадцять п''ять став корабль припливать
Да гей, уха-ха, став корабль припливать

А на тому кораблі два матроси молоді
Да гей, уха-ха, два матроси молоді

Один книжку читає, другий вдову питає
Да гей, уха-ха, другий вдову питає

Ой ти вдово молода, чи підеш ти за нас два?
Да гей, уха-ха, чи підеш ти за нас два?

За одного сама йду, за другого дочку шлю
Да гей, уха-ха, за другого дочку шлю

Тепер такий світ настав, що син мати не впізнав
Да гей, уха-ха, що син мати не впізнав

Тепер така година - йшла би мати за сина
Да гей, уха-ха,  йшла би мати за сина

Тепер така мінута - йшла би сестра за брата
Да гей, уха-ха, йшла би сестра за брата

Там на горі є терен, нема більше лиш один...
Да гей, уха-ха, нема більше лиш один...','["pisni.org.ua", "cat:socialno-pobutovi", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_148622'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_148622','Там на горі є терен','Там на горі є терен, нема більше лиш один...
Да гей, уха-ха, нема більше лиш один...

А з-за того терена вийшла вдова молода
Да гей, уха-ха, вийшла вдова молода

Вийшла вдова молода, що зродила синів два
Да гей, уха-ха, що зродила синів два

Що зродила синів два - Орасима й Василя
Да гей, уха-ха, Орасима й Василя

Орасима й Василя в тихий Дунай пустила
Да гей, уха-ха, в тихий Дунай пустила

Ой ви круті береги, тримайтеся два сини
Да гей, уха-ха, тримайтеся два сини

А ти, жовтий пісочок, годуй моїх діточок,
Да гей, уха-ха, годуй моїх діточок

Через років двадцять п''ять став корабль припливать
Да гей, уха-ха, став корабль припливать

А на тому кораблі два матроси молоді
Да гей, уха-ха, два матроси молоді

Один книжку читає, другий вдову питає
Да гей, уха-ха, другий вдову питає

Ой ти вдово молода, чи підеш ти за нас два?
Да гей, уха-ха, чи підеш ти за нас два?

За одного сама йду, за другого дочку шлю
Да гей, уха-ха, за другого дочку шлю

Тепер такий світ настав, що син мати не впізнав
Да гей, уха-ха, що син мати не впізнав

Тепер така година - йшла би мати за сина
Да гей, уха-ха,  йшла би мати за сина

Тепер така мінута - йшла би сестра за брата
Да гей, уха-ха, йшла би сестра за брата

Там на горі є терен, нема більше лиш один...
Да гей, уха-ха, нема більше лиш один...');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_148622_l1','pisniua_148622','Переглянути варіанти >>','https://www.pisni.org.ua/#variants','external',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1501024','Диво те','Музика: Оля Андрощук Слова: Оля Андрощук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Диво те так давно було,
Скільки літ пройшло з того часу...
Диво те - то Христа Різдво,
Що сповняє  миром, щастям!

Приспів:
У душі свято, радості багато,
Всі несуть хвалу і славу Богу!
Хочеться співати, Бога прославляти
Рожденного і Святого!
Рожденного і Святого!

Диво те сповіщаєм ми
Поколінням всім, щоби знали,
Що колись в небі Ангели
Для Христа у хорі співали!
І лились ріки радості
У нові віки нашим дітям...
Бог нам дав в своїй милості
Дар спасіння, щоб вічно жити!

Приспів.

Слава Богу на землі!  |
Слава Богу угорі!     |
Слава Богу у віках    |
За народження Христа! | (2)

Приспів. (2)','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1501024'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1501024','Диво те','Диво те так давно було,
