INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_149529','Батькова сорочка','Музика: Павло Дворський Слова: Григорій Булах, В. Матвієнко. Виконує: Павло Дворський, Владислав Лєлюшкін','uk','ukraine_1991',NULL,NULL,'http://plus-msk.ru/forum/showthread.php?t=31038',NULL,'Шепотіла казку нам в дитинстві мати,
Як садив дубочка батько біля хати,
Як вона плекала теплою сльозою,
І як ріс дубочок з кожною весною.

Як, було, жахалась мати серед ночі,
Як вона до ранку не стуляла очі.
Сяде край віконця, вигляда та слуха,
Бо, здається, батько в шибочку постука.

Там, десь за Сибіром, кажуть, сходить сонце...
Листячко із дуба стукає в віконце,
А за сонцем вітер несе хмару сіру,
Один тільки батько не верта з Сибіру.

Ой, дубе, мій дубе, дубе мій, дубочку,
Одягну на тебе батькову сорочку,
Ту, що вишивала моя рідна мати,
Ту, що не прийшлося батькові вдягати.

Хай сяйне до мами у пригаслі очі
Батькова сорочка крізь зимові ночі,
Тож прийми від мене вишиту сорочку,
Нагадай нам батька, дубе мій, дубочку','["pisni.org.ua", "cat:nostalgia", "cat:pro-batkiv", "Пісні з ностальгічними мотивами", "Пісні про любов до батьків"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_149529'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_149529','Батькова сорочка','Шепотіла казку нам в дитинстві мати,
