INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1485707','Різдвяна ніч','Слова: Марта Лозинська','uk','ukraine_before_1917',NULL,NULL,'аудіозапис',NULL,'Різдвяна ніч настає,
Зоряне сяйво з неба б''є.
В тихій яскині в Вифлеємі,    |
Спочив Спаситель на сіні.     | (2)

