INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_149505','Біла акація',NULL,'uk','ukraine_1991',NULL,'2007','1. http://olga-kyjanka.uol.ua/2007/07/16/667.php','Відтворила моя дружина за спогадами дитинства - можливі неточності. Інформація - тут: http://olga-kyjanka.uol.ua/2007/07/16/667.php Може, хтось може уточнити цей текст?','Нам цілу ніч соловейко наспівував,
Мріяв Хрещатик з Дніпром віч на віч,
Пахощі дивні акації білої
Аж до нестями п''янили в ту ніч.

Місто вмивалось весняними зливами,
Танув Узвіз в срібнім сяйві надій.
Вальсом пелюсток кружляли, щасливі ми,
Часом досвітнім були молоді.

Роки промчали. Невже ми посивіли?
Де ж свіжий чар ніжних квітів живих?
Тільки зима заметілями білими
Нам нагадає сьогодні про них.

В час, коли вітер зітхає знесилено,
В небі згасає остання зоря,
Квіти духмяні акації білої
Марять майбутнім, де юність моя.','["pisni.org.ua", "cat:krasa-pryrody", "cat:nostalgia", "cat:romansy", "cat:translations", "Пісні про красу природи", "Пісні з ностальгічними мотивами", "Романси", "Переклади іноземних пісень"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_149505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_149505','Біла акація','Нам цілу ніч соловейко наспівував,
Мріяв Хрещатик з Дніпром віч на віч,
Пахощі дивні акації білої
Аж до нестями п''янили в ту ніч.

