INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1494101','Зима прийшла - свята привела','Музика: Ольга Маєвська Слова: Ольга Маєвська','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Люба зимонько-зима,
Радість дітям принесла,
Ми пісні співаєм їй
Величальні і дзвінкі!
Ой, зима, ти, зима,
Ти нам свято принесла!
Ой, зима, ти, зима,
Миколая привела!

Ми ялинку принесли,
Прикрашали, як могли,
А вона радіє,
Вогниками гріє!
Ой, зима, ти, зима,
Ти нам свято принесла!
Ой, зима, ти, зима,
Новий рік ти привела!

Будемо ми всі кружляти,
Круг ялинки танцювати!
Зиму величаємо,
Їй пісні співаємо!
Ой, зима, ти, зима,
Ти нам свято принесла!
Ой, зима, ти, зима,
Ти Різдво нам привела!

Рукавички одягли,
Сніжки граєм залюбки!
Сіли на санчата,
Їхали завзято!
Ой, зима, ти, зима,
Ти нам свято принесла!
Ти нам зиму привела,
Водохреща й Василя!
Ой, зима, ти, зима,
Ти нам свято принесла!
Ой, зима, ти, зима,
Вся радіє дітвора!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1494101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1494101','Зима прийшла - свята привела','Люба зимонько-зима,
