INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1501303','Коли закінчиться війна','Слова: Василь Чопей','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Коли закінчиться війна,
Та знає Бог один Всевишній...
Коли закінчиться війна,
В наш рідний край прийде весна!
Коли закінчиться війна,
Запахнуть так чарівно вишні!
Коли закінчиться війна!..

Коли закінчиться війна,
Замовкнуть назавжди гармати!..
Коли закінчиться війна,
Людські життя ж бо їй ціна...
Коли закінчиться війна,
Живим чекає сина мати!..
Коли закінчиться війна!..

Коли закінчиться війна,
Вже стільки лиха наробила...
Коли закінчиться війна,
Вдова заплаче й не одна...
Коли закінчиться війна,
Свічки запалять на могилах...
Коли закінчиться війна!..

Коли закінчиться війна,
Пробігне вітер по руїнах...
Коли закінчиться війна,
Колись зажурена сумна,
Коли закінчиться війна,
Знов посміхнеться Україна!..
Коли закінчиться війна!..','["pisni.org.ua", "cat:ato", "Пісні російсько-української війни та АТО"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1501303'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1501303','Коли закінчиться війна','Коли закінчиться війна,
Та знає Бог один Всевишній...
Коли закінчиться війна,
В наш рідний край прийде весна!
Коли закінчиться війна,
Запахнуть так чарівно вишні!
Коли закінчиться війна!..

Коли закінчиться війна,
Замовкнуть назавжди гармати!..
Коли закінчиться війна,
Людські життя ж бо їй ціна...
Коли закінчиться війна,
Живим чекає сина мати!..
Коли закінчиться війна!..

Коли закінчиться війна,
Вже стільки лиха наробила...
Коли закінчиться війна,
Вдова заплаче й не одна...
Коли закінчиться війна,
Свічки запалять на могилах...
Коли закінчиться війна!..

Коли закінчиться війна,
Пробігне вітер по руїнах...
Коли закінчиться війна,
Колись зажурена сумна,
Коли закінчиться війна,
Знов посміхнеться Україна!..
Коли закінчиться війна!..');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_150426','Ах, кохай мене, облиш розраду','Слова: Аполлон Майков, Анатолій Присяжнюк','uk','ukraine_1991',NULL,NULL,NULL,NULL,'Ах, кохай мене, облиш розраду,
Без журби всі сумніви розвій,
Без докорів, здогадів про зраду!
Що гадати, я твоя - ти мій!..

Усе забудь, все кинь, мені віддайся!..
І журливо так не позирай.
Розгадати серце - не старайся,
Весь йому віддайся - і кохай!

Я кохання не злічу, не змірю,
Захопило душу неземне!
Я кохаю - і кляну, і вірю...
Ах, життя, мій милий, чарівне!..

Ах, кохай мене, облиш  розраду,
Без журби всі сумніви розвій,
Без докорів, здогадів про зраду!
Що гадати, я твоя - ти мій!..','["pisni.org.ua", "cat:translations", "Переклади іноземних пісень"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_150426'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_150426','Ах, кохай мене, облиш розраду','Ах, кохай мене, облиш розраду,
Без журби всі сумніви розвій,
Без докорів, здогадів про зраду!
Що гадати, я твоя - ти мій!..

Усе забудь, все кинь, мені віддайся!..
І журливо так не позирай.
Розгадати серце - не старайся,
Весь йому віддайся - і кохай!

Я кохання не злічу, не змірю,
Захопило душу неземне!
Я кохаю - і кляну, і вірю...
Ах, життя, мій милий, чарівне!..

Ах, кохай мене, облиш  розраду,
Без журби всі сумніви розвій,
Без докорів, здогадів про зраду!
Що гадати, я твоя - ти мій!..');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1490505','Жити','Музика: Нікіта Гончаренко, Дмитро Димов Слова: Андрій Парфенов','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Люди повинні жити, а не воювати!
Не тримати в собі злість, а від душі кохати!
Будувати власній дім, а не сталеві грати,
І цінувати кожну мить, бо час любить минати!
Люди повинні жити, а не воювати!
Не тримати в собі злість, а від душі кохати!
Мандрувати по життю, щоб було що згадати,
Та відчувати добро й добро дарувати!

Боже, я знаю, що не можна такого бажати,
Але є, як є, і я мушу сказати,
Моє серце хоче миру, а душа відплати,
Й покарання для тих, хто прийшов вбивати!
Перехрещусь і попрошу добра для всього світу,
Для нетямущих - освіту,
Для тих, хто в темряві - світло,
Для тих, хто чути не хоче - почути і прозріти,
Що треба по-людськи жити!..

Приспів.

Години так біжать, їх не зупинити,
І цінна кожна мить, бо це можливість жити...
Хтось вражає цілі та не вражає душі,
І тоне в своїх бажаннях, хоча і на суші...
Я тебе молю, Боже, не дай мені стати,
Як ті, що зовсім поруч, вороги закляті,
Ті, хто мають очі, не бачучи нічого,
Люди, в яких не має нічого людського...
Добре, пробач, розумію ми не ті,
Не хочу, щоби хтось сказав,
Так ви такі ж як вони,
Я попрошу тільки сил, вистояти то,
Бо "Лиш боротись - значить жить!" -
Так казав Франко!

Приспів.','["pisni.org.ua", "cat:ato", "cat:zahalni-cinnosti", "Пісні російсько-української війни та АТО", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1490505'), datetime('now')),datetime('now'));
