в степу коло Гуляй-Поля...    Мелодія I');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_150101','Ой як файно мати жінку','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'1. Українські співанки. Упорядник Степан Налєпа. — Львів: Сполом, 2007. — 404 с.',NULL,'Маю років вже нівроку —
Двайцять штири і ще трохи,
Женитися тепер мушу,
Бо без жінки я ся мучу.

Приспів:
Ой! Як файно мати жінку,
Кожна має свою мінку:
До весілля — щебетуха,
По весіллю — крутить вуха.

Маю тепер файну дівку,
Возьму я си ї за жінку.
То таке, як голос з неба:
Буде жінка — то, що треба.

Приспів.

Катер маю вже з півроку,
Колька коле мене збоку.
Оженюсь — не буду впертий,
Бо без жінки можна вмерти.

Приспів.

Маю жінку: спить зі мною —
Не дає мені спокою;
То щипає, то лоскоче —
Чорт ї знає, чого хоче.

Приспів.

Маю жінку, маю діти,
Сам не знаю: де їж діти ?
Вчора було дев''ятеро,
А сьогодні десятеро !','["pisni.org.ua", "cat:dances", "cat:foxtrots", "cat:halycki", "cat:socialno-pobutovi", "cat:zhartivlyvi", "Пісні до танцю", "Фокстроти", "Пісні з Галичини", "Соціально-побутові пісні", "Жартівливі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_150101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_150101','Ой як файно мати жінку','Маю років вже нівроку —
Двайцять штири і ще трохи,
Женитися тепер мушу,
Бо без жінки я ся мучу.

