INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1503426','Мій брате','Музика: Джамала Слова: Джамала, Tatyana Milimko','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Мій брате, пишу тобі листа
Сказати, що не встигла я...
Зоря на небі вже зійшла,
Вона тепер з твоїм ім''ям...
А пам''ятаєш серпень на дворі?
Наші вечірки так обожнював пляж.
Рве душу Джексон у старій магнітолі,
Ти завжди тримав слово!
Ти був захист наш!

Приспів:
Я не забуду!.. Я не забуду тебе!..
Я не забуду!.. Я не забуду тебе!..

Мій друже, коли ти жартував,
Сміялись всі навколо!..
Мій брате, тебе любило море,
Та підкорялись гори!..
Наші розмови назавжди
Залишаться в спогадах,
Небесна варта тепер
Під твоїм крилом...
Пишу тобі, брате,
Але мені нестерпно гірко й боляче,
Залишишся в серці ти світлом!..

Приспів.

Час не лікує,
Він лише притамовує біль...
Час залишає в пам''яті
Найголовніше...
Я пишу лист, коштує він зусиль...
Пишу через сльози,
А у відповідь тиша...','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1503426'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1503426','Мій брате','Мій брате, пишу тобі листа
Сказати, що не встигла я...
Зоря на небі вже зійшла,
Вона тепер з твоїм ім''ям...
