INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1506707','Великдень настає','Музика: Ольга Маєвська Слова: Ольга Маєвська. Виконує: Ольга Маєвська','uk','ukraine_1991',NULL,NULL,'авторське подання',NULL,'Великдень настає,
Щастя в дім несе,
Світлу радість на гостину -
Хай радіє все!
Лунають всюди дзвони
І ангели з небес
Усіх нас сповіщають:
Христос Воскрес!

Приспів:
Великдень, Великдень -
Це велике свято!
Мир усім дарує він
І добра багато!
Ми разом святкуємо,
Христа величаємо,
І зі святом Великодня
Друзів привітаємо!

Все навкруги цвіте,
Веселка виграє,
Христа всі прославляють -
Свято настає!
Лунають всюди дзвони
І ангели з небес
Усіх нас сповіщають:
Христос Воскрес!

Приспів.

Христос Воскрес!','["pisni.org.ua", "cat:voskresni", "Воскресні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1506707'), datetime('now')),datetime('now'));
