INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1510000','Однокласниця','Музика: Володимир Гуменчук Слова: Мирослав Воньо','uk','ukraine_1991',NULL,NULL,'авторське подання','Пісню виконує Володимир Гуменчук (альбом: Полум''я кохання).','На сто доріг моя стежина розійшлася...
Про рідну школу пам''ять в серці я несу
Й про однокласницю, яку у третім класі
Закохано я смикав за косу...

Приспів:
А однокласниці завжди найчарівніші!
Я в цьому сотні раз переконався сам!
Нема дівчат на світі, щоб були гарніші,
І їх серця не підкоряються рокам!

З доріг далеких повернуся я додому,
Згадаю школу, де пройшла пора свята,
І однокласницю, якій на випускному
Я так безбожно цілував вуста!

Приспів.

Життя з роками робить все бистріші кроки.
Нізащо я цю пам''ять з серця не зітру,
Як однокласницю аж через тридцять років
Я цілував, як матір і сестру!
А однокласниці завжди найчарівніші!
Я в цьому сотні раз переконався сам!
Нема жінок на світі, щоб були миліші,
І їх серця не підкоряються рокам!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1510000'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1510000','Однокласниця','На сто доріг моя стежина розійшлася...
Про рідну школу пам''ять в серці я несу
Й про однокласницю, яку у третім класі
Закохано я смикав за косу...

Приспів:
