INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1512404','Жіноча дружба','Музика: Бажана Слова: Бажана','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сьогодні я з ним розставила крапки,
Із пам''яті стерла всі фото і згадки,
Подзвоню перша і скажу: Мені не дзвони!
SOS викликаю: Подруга, де ти?
Я вже в дорозі, ухвалим вендету!
Як добре, що в моєму житті є ти!

Приспів:
Давай до дна! Давай за любов!
Я ставлю крапку!
Давай до дна! А завтра життя
Почну все з початку!
Давай до дна за те, щоб прийшла
Любов на все життя!
Давай до дна за нас з тобою,
Подружка моя!

Ми просто вільні, а не одинокі,
Ой, не кажи, я сама в шоці!
На краще усе, своє від нас не піде!
Йому напишу, нехай зрозуміє
Кого загубив, хай потім жаліє!
А щастя моє я знаю, до мене йде!

Приспів.

Давай до дна за нас з тобою,
Подружка моя!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1512404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1512404','Жіноча дружба','Сьогодні я з ним розставила крапки,
Із пам''яті стерла всі фото і згадки,
Подзвоню перша і скажу: Мені не дзвони!
SOS викликаю: Подруга, де ти?
Я вже в дорозі, ухвалим вендету!
Як добре, що в моєму житті є ти!

Приспів:
Давай до дна! Давай за любов!
Я ставлю крапку!
Давай до дна! А завтра життя
Почну все з початку!
Давай до дна за те, щоб прийшла
Любов на все життя!
Давай до дна за нас з тобою,
Подружка моя!

Ми просто вільні, а не одинокі,
Ой, не кажи, я сама в шоці!
На краще усе, своє від нас не піде!
Йому напишу, нехай зрозуміє
Кого загубив, хай потім жаліє!
А щастя моє я знаю, до мене йде!

Приспів.

Давай до дна за нас з тобою,
Подружка моя!');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1512404_l1','pisniua_1512404','YouTube','https://www.youtube.com/watch?v=rOS7gjedVk8','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1522606','Весільні ладканки та коломийки','Українська народна пісня','uk','ukraine_1991',NULL,'2010','аудіозапис','с. Суходіл, Рожнятівський район, Івано-Франківська область. Оригінальна назва альбому: "Антология народной музыки: Украинская музыка" (2010).','Добрий вечір, дівочки, ми до вас,
Чи дасте нам молоду з межи вас?

Не високо сонінько над нами,
Ой, збирайсє, молода, і з нами.

Не жаль тобі, мій таточку, мене,
Бо ти не мав соромоти за мене.

Хоч я собі по ночи ходила,
То я чесно свій віночок зносила.

Ой, кувала зазуленька за двором,
Сиди собі, молода, за столом.

Товаришко моя люба, подарок би-м дала,
Бо вже я сі в своїй хаті невістки приждала.

Приждала-м невісточки з чорними й очима,
А вже двері й вдоперає моєми плечима.

Приждала-м сі невісточки, тепер мені добре,
Тепер мені лиш бракує костура тай торби.

Ой, костура із верби, торби із верети,
Питається добрі люде, - шо бабко берети?

Чому, коню, води не п''єш, чи дорогу чуєш?
Чому, сину, Василину, дома не ночуєш?

Ой, як мині й молодому й дома ночувати?
Кінь вороний, я молодий, ні з ким розмовляти.

Ой, музико, музиченько, як си добре граєш,
Пальці би ті покривило, як перебираєш.

Ой, музико, музиченько, чи ся гоноруєш?
Однов ногов замітаєш, а другов гальмуєш.

Ой, у лісі на горісі ворона скригоче,
Мамка мусит миски мити бо доня не хоче.','["pisni.org.ua", "cat:kolomyyky", "Коломийки"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1522606'), datetime('now')),datetime('now'));
