INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1519303','Уляно, Уляно, чого ходиш-блудиш','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','с. Петрівці Миргородського р-ну Полтавської області. Пісню виконує Фольклорний ансамбль "Божичі" (альбом: Вік любиш - не налюбишся).','- Уляно, Уляно,
Чого ходиш-блудиш,
Мабуть, ти, Уляно, й Уляно,
Ой, мого сина любиш,
Мабуть, ти, Уляно, й Уляно,
Ой, мого сина лю(биш).

- Як би не любила,
То б я й не ходила,
Через твого й сина Василя,
Ой, бистру річку брила,
Через твого й сина Василя,
Ой, бистру річку бри(ла).

Брила, брила річку
Да й не за замочилася,
Три годи Василя любила,
Ой, не налюбилася,
Три годи Василя любила,
Ой, не налюбила(ся).

Ой, на тому боці,
Василь траву косить,
А до його й Уляна, й Уляна,
Ой, дитину приносить,
А до його й Уляна, й Уляна,
Ой, дитину прино(сить).

- На тобі, Василю,
Маленьку дитину,
Як не возьмеш, Василю, й дитину,
Ой, на покіс покину,
Як не возьмеш, Василю, й дитину,
Ой, на покіс поки(ну).

- Дам тобі, Уляно,
Та й семеро овець,
Да й не кажи, Уляно, й, Уляно,
Що я - його й отець,
Да й не кажи й, Уляно, й, Уляно,
Ой, що я - його й о(тець).

Дам тобі, Уляно,
Ще й семеро хліба,
Да й зверни, ти й, Уляно, й, Уляно,
Ой, на старого діда,
Да й зверни, ти й, Уляно, й, Уляно,
Ой, на старого ді(да).','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1519303'), datetime('now')),datetime('now'));
