INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1516323','Страдальная мати','Українська народна пісня. Виконує: Божичі','uk','ukraine_before_1917',NULL,NULL,'аудіозапис','смт. Кобеляки Полтавської обл. (записано) с. Вівчарове Троїцького р-ну Луганської обл. (походження).','Страдальная мати під хрестом стояла,
Плакала, ридала, в сльозах промовляла:
Ой, сину, сину, за яку провину
Переносиш муки, тяжкую годину
На хресті?!?

Я ж тебе купала гіркими сльозами,
Я ж тебе ховала поміж ворогами,
А нині плачу, бо тебе я трачу,
Бо тебе, мій сину, скоро не побачу,
Сину мій...

Ти ж - моя надія, ти - мій світе ясний,
Гаснеш дуже швидко, в''янеш безучасно.
А хто зі мною буде, сиротою?!?
Щас одна я в світі, як билина стою,
Під хрестом...

Ти вєдь обіцявся всіх людей спасати,
І за це діждався безвинно вмирати
За рід лукавий, злобний і неправий,    |
Що зповнив на тобі свій засуд кровавий |
На хресті...                           | (2)','["pisni.org.ua", "cat:arkhiv-bozhychi", "Фольклорний архів анс. \"Божичі\""]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1516323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1516323','Страдальная мати','Страдальная мати під хрестом стояла,
Плакала, ридала, в сльозах промовляла:
Ой, сину, сину, за яку провину
Переносиш муки, тяжкую годину
На хресті?!?

Я ж тебе купала гіркими сльозами,
Я ж тебе ховала поміж ворогами,
А нині плачу, бо тебе я трачу,
Бо тебе, мій сину, скоро не побачу,
Сину мій...

Ти ж - моя надія, ти - мій світе ясний,
Гаснеш дуже швидко, в''янеш безучасно.
А хто зі мною буде, сиротою?!?
Щас одна я в світі, як билина стою,
Під хрестом...

Ти вєдь обіцявся всіх людей спасати,
І за це діждався безвинно вмирати
За рід лукавий, злобний і неправий,    |
Що зповнив на тобі свій засуд кровавий |
На хресті...                           | (2)');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1516323_l1','pisniua_1516323','YouTube','https://www.youtube.com/watch?v=xeGR3mOKXjM','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_15101','Ген, високо','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,'Пісня записана в с. Довжок (стара назва Кетроси), Ямпільського району, Вінницької обл.','4.С  8G4C8D8F  4.E8D  4C4E
Ген, високо, в темнім небі
4.D8C 4H8D8D2C4C 8D8E
Зірка засі - яла - а
4.F8E  4D4F  4.E8D 4C4E
Плила, плила поміж хмари
4.D8C 4H8D8D   2C4C8D8E  (2-й раз 2С2С)
Над   вертепом стала.

Мати сина породила,
В ясла положила.
Чистим сіном притрусила,
Пеленами вкрила.

Де колиска золотая,
Вороски шовкові?
Де перини для дитини
Мнягкі та пухові?

Прилетіли до шіпчини
Ангели крилаті.
Повклякали, заспівали
Божому дитяті.

То дитяточко маленьке
Сам Господь великий.
А що було з преждивіку,
То й буде до віку.

Архаїла Гавриїла
Сльози облили.
Щоб у цей день - Рожества Христова
Та й сади зацвили!

Цвітут сади-виногради,
Ще й рожеві квіти.
Радуються старі люди,
Ще й малії діти!

А ви, люди-християне,
Молітеся Богу!
Та й вдаряйте низькії поклони
В церквах до престолу!','["pisni.org.ua", "cat:christian", "cat:kolyadky", "cat:narodni", "cat:podilski", "Пісні на християнську тематику", "Колядки", "Народні пісні", "Пісні з Поділля"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_15101'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_15101','Ген, високо','4.С  8G4C8D8F  4.E8D  4C4E
Ген, високо, в темнім небі
4.D8C 4H8D8D2C4C 8D8E
Зірка засі - яла - а
4.F8E  4D4F  4.E8D 4C4E
