INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1531909','Колискова 2022','Музика: DOROFEEVA, Ivan Klymenko, Misha Katsurin, Stas Chornyi Слова: DOROFEEVA, Ivan Klymenko, Misha Katsurin','uk','ukraine_1991',NULL,'2022','авторське подання','Пісню виконує Nadya Dorofeeva.','Мати дитя колисала,    |
Поки за вікном палало, |
Щоб не бачило дитя те  |
Гармати!.. Гармати!..  | (2)

Чи принесе радість той ранок?..
Чи вип''ємо разом ще кави?.. -
Про це знає Бог - він драмер,
Що б''є, але не в тамтами.
Щось стукає, але не в двері,
Щось блимає - та не салюти,
Ведмедик улюблений Тедді
Твій допоможе заснути!..

Приспів:
Ой, так, ой, так, засинай, мій любий! -
Вона-вона йому проспівала.
Ой, так, ой, так, ніхто не розбудить,
Поки вона його колисала!..
Мати дитя колисала,
Поки за вікном палало,
Щоб не бачило дитя те
Гармати!.. Гармати!..  | (4)

Ой, на кота та воркота,
На дитину та й дрімота,
Котик буде воркотати,
Дитинонька буде спати...
Спати!..

Перемикай цей день,
Пульт невідомо де,
Але крізь цей вогонь
Доля нас веде!..
Перемикай цю ніч,
Наче холодний січень
В міцних обіймах не замете!..

Приспів.

Ой, на кота та воркота,
На дитину та й дрімота,
Котик буде воркотати,
Дитинонька буде спати...
Спати!..','["pisni.org.ua", "cat:socialno-pobutovi", "Соціально-побутові пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1531909'), datetime('now')),datetime('now'));
