INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1531606','Гімн місяцю','Музика: Дмитро Бортнянський Слова: Франц Герман Лаферм''єр','uk','ukraine_1991',NULL,NULL,'Бортнянський, Д. Вокальні твори [ноти] — Київ: Музична Україна, 1976 р.','Оригінал у французькій мові, публікований у 1793 році як: "Вісім пісень і романсів, присвячених Великій Княгині Єлизаветі Олексіївні". Переклад з французької: Борис Тен. Послухати мелодію та переглянути/завантажити ноти можна тут: https://musescore.com/user/56304587/scores/22320133','Чутливе серце зігріє
Не сонце — місячна тінь:
Коханців тайну леліє
Прозора й легка світлінь,
В ній ніжно любов їх мліє
І тоне чуттів глибінь.

В смутній годині розлуки
Та лагідь спокій дає,
Важкі полегшує муки,
Що серце ятрять моє,
Й надію замість розпуки
Душі моїй подає.

Коли безневинність боїться
Чуттям віддатись палким,
Вагається і страшиться
В пориві втонуть п''янкім,
Стидливість жадає вкриться
Серпанком світла блідим.

На небі місяць сіяє,
Пастушці стелеться путь
Туди, де квітом розмаю
Кохання стежки цвітуть,
Й красою її вінчає,
Якої вік не забуть.

O, ноче! Місячне світло
Відкрило радість мені,
Для нас у ньому розквітли
З Сільвією щастя дні,
І ревнощів муки зникли
В осяйливій тишині.','["pisni.org.ua", "cat:himny-marshi", "cat:romansy", "Гимни та марші", "Романси"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1531606'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1531606','Гімн місяцю','Чутливе серце зігріє
Не сонце — місячна тінь:
Коханців тайну леліє
Прозора й легка світлінь,
В ній ніжно любов їх мліє
І тоне чуттів глибінь.

