INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1533426','Поклоніться всі','Музика: Alla Chepikova Слова: Ангеліна Колядич','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Маленьке місто Вифлеєм,
Всі сплять, і тиша наповняє,
Здавалася звичайна ніч,
Та все ж не так!..
В цю ніч родився Божий Син,
Всім щастя він приніс і мир!
І хор із ангелів у небі заспівав!

Приспів:
Слава Богу і на землі мир,
В людях добра воля!
Нам родився Цар Спаситель,
Дивне немовля!
Поклоніться всі, бо він Один
Слави достойний і хвали!

Ісусу поклонитися
Поля лишили пастухи.
І за зорею мудреці
Несли дари.
В цю ніч родився Божий Син,
Всім щастя він приніс і мир!
І хор із ангелів у небі заспівав!

Приспів.

Поклоніться всі, бо він Один
Слави достойний і хвали!
Слави достойний і хвали!','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1533426'), datetime('now')),datetime('now'));
