INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1533127','Новорічна мандаринка','Музика: Віталій Лобач Слова: Віталій Лобач','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Мандаринка, ніби солодка,
Але є кислинка!
І старий рік
Залишиться на знімках,
Ми зачекалися Новий,
Я заховаю себе тобі
Під ялинку!

Наступає Новій рік -
Під спів годинника!
На порозі метушня,
Забіг по магазинчикам.
Наступає Новий рік -
Ми чекаєм на дива,
Що важливо - загадаєм,
Свято починається!
О-о-о! Світло ллється
Крізь сніжинки,
О-о-о! І шампанське
Вже відкривши,
Зібралася рідня,
Всім новинам новина -
Новий рік вже пролунав!

Приспів. (2)

З Новим роком!

Люди забажають свої мрії,
Щоб не покидали їх надії!
Щоб по-трохи всього додавалось,
І біда ніколи не верталась!
Ай-яй-яй! Зима снігом накриває,
Ай-яй-яй! І старий рік вже минає...
Без тривог і без турбот,
В Новий рік щоби все було!

Приспів.

З Новим роком! З Новим роком! | (6)

Мандаринка!','["pisni.org.ua", "cat:new-year", "Пісні про Новий Рік"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1533127'), datetime('now')),datetime('now'));
