INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1526505','Герої не вмирають','Музика: Валерій Судче Слова: Соломія Українець','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Хто видумав: Герої не вмирають!
Хай скаже сива мама чи вдова:
Кого щоночі у зірках шукають,
Чому вона живе, як нежива?..
Чому на цвинтарі чорні хустини,
І сироти стоять біля хреста...
Не треба їм, щоб був Героєм тато,
Живий прийшов, приїхав, обійняв!..

Герої не вмирають - скільки болю...
Душі щодня в Небесний стрій летять...
А скільки у степах, лісах і в полі
Вітром оспівані і без хреста лежать...
Вмирають! На війні щодня вмирають!
І навіть пам''ять про них нежива...
Минає час, Героїв забувають...
Біля могили мати і вдова...

Хто видумав: Герої не вмирають!
Хай скаже сива мама чи вдова:
Кого щоночі у зірках шукають,
Чому вона живе, як нежива?..
Чому на цвинтарі чорні хустини,
І сироти стоять біля хреста...
Не треба їм, щоб був Героєм тато,
Живий прийшов, приїхав, обійняв!..','["pisni.org.ua", "cat:devoted", "cat:pro-batkiv", "cat:pro-ditey", "cat:viyskovi", "cat:zahalni-cinnosti", "Пісні присвячені окремим особам", "Пісні про любов до батьків", "Пісні про любов до дітей", "Пісні на військову тематику", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1526505'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1526505','Герої не вмирають','Хто видумав: Герої не вмирають!
