INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1534303','Заколядуй моя країна','Музика: Назарій Гук (Julik) Слова: Назарій Гук (Julik)','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Зібралась вся родина
Вдома за столом,
Запах куті із медом
Гріє нас теплом!
Вже перша зірка сходить.
Свято знов прийшло:
Бог народився нині,
То ж славім Його!

Приспів:
Заколяду, моя країна,
Нехай співає вся родина
У ріднім колі за столом!
Ми переможемо над злом!
Хай лине пісня солов''їна
І прославляє Бога - сина!
Хай Ангел з неба шле добро,
Щоб ми перемогли все зло!

Хай буде все в нас
Добре, сили Бог дає!
І рідна Україна
Подолає все!
Різдвяна зірка в небі
Радість хай несе!
Тож жиймо, люди, в мирі,
Бо у нас все є!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1534303'), datetime('now')),datetime('now'));
