INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1536725','Злодій Грінч','Музика: Аркадій Войтюк Слова: Аркадій Войтюк. Виконує: Аркадій Войтюк','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Грінч! Грінч!

В темну-темну ніч
Обернувся день
І з''явився Грінч!
Грінч!
Боялись звірі лісові,
Бо крокував босоніж
По землі Грінч!
Тихо-тихо спуститься з гір
Дуже підступний зелений звір.
Вчора була ейфорія Різдва,
А сьогодні "клац",
І Різдва вже нема!

Приспів:
Злодій Грінч залізає в вікно,
Злодій Грінч викрадає Різдво!
Злодій Грінч, щастя не забирай,
Злодій Грінч, все, що вкрав -
Нам віддай!

Грінч! Грінч!

О, злодій Грінч, плаче дитя...
Невже у вас серця нема?!!
Й забриніла у Грінча сльоза:
Я не вмію інакше,
В мене просто натура така.

Приспів.

Злодій Грінч, Різдво нам віддай!','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1536725'), datetime('now')),datetime('now'));
