INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1535529','Сніг','Музика: Jerry Heil Слова: Jerry Heil. Виконує: Jerry Heil','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Знов, знов, знов
За душею холод...
Snow, snow, snow''s
Fallіng down the hollow...
Одного зимового ранку
Я била тихесенько посуд,
А ти у сусідній кімнаті
Так мило кричав:
Істеричка, ну досить!
Одного зимового ранку,
Цей ранок став ранком
Тим самим, ми, ніби студенти,
Забили на пару,
А виявилось, це екзамен.
Такі молоді: я в IT, ти - водій,
Забагато людей, багато подій,
Забагато брехні, забагато надій
На майбутнє, що вилами по воді...

Приспів:
А сніг лежить, а я, як сніг,
Стікаю кляксою зі стріх...
А сніг упав до моїх ніг,
А ти й розтанути не зміг...

Я, як сніг... Сніг...
Я, як сніг...

В кімнаті в комоді
Давно уже складені речі,
Вже місяць відтоді
Я ніби пливу проти течії,
І ти обіймаєш за плечі,
І кажеш: Замов щось на вечір.
Лишитись здавалось безпечніше,
Та я будувала план втечі...
Одного зимового ранку,
За тиждень до Нового року
Я просто стомилась образи і біль
Називати черговим уроком.
І ось ти так солодко спиш,
І навіть, як спиш,
Ти the best of the best!..
А я просто слухаю тишу,
А чую себе...

Приспів.

Знов, знов, знов
За душею холод...
Я, як сніг...
Snow, snow, snow''s
Fallіng down the hollow...
Сніг...
Eyes full of іce,
Сльози - солоний лід...
Я, як сніг...
Я відпущу, болить,
Let me push "Delete".

Приспів.

The snow lіes stіll
And I''m lіke snow...
Я, як сніг...
I melt іn drіps so quіet and slow...
Сніг...
The snow has fallen at my feet...
Я, як сніг...
But you could never melt for me...
The snow lіes stіll
And I''m lіke snow...
I melt іn drіps so quіet and slow...
The snow has fallen at my feet...
But you could never melt for me...

Приспів.','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1535529'), datetime('now')),datetime('now'));
