INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1536707','Радість Різдва','Музика: Tanya Navrotski Слова: Mariya Zvirid','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Радість Різдва вічно жива!
Нам народився Спаситель!
Ангелів хор, світлий мажор,
Небо для слави відкрите!

Приспів:
Невимовна краса Різдва,
Бо на землю Любов зійшла!
Слава Богу на висоті!
Мир і спокій усій землі!
В людях добра воля!

Ніч ця свята - прихід Христа -
Світу від Бога дарунок!
Мир, благодать благовістять
В дивних мелодіях струни.

Приспів.

Хай лине в день Різдва
Спасителю хвала!
Радійте, небеса, земля і люди!
Невимовна краса Різдва,
Бо на землю Любов зійшла!
Слава Богу на висоті!
Мир і спокій усій землі!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1536707'), datetime('now')),datetime('now'));
