INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_15404','Буквар','Музика: С. Козак Слова: О. Гаєцька','uk','ukraine_1991',NULL,NULL,'Музика С.Козака "Український шкільний пісенник". Випуск 4. Львів-2003',NULL,'Купи мені, матусенько,
Книжечку чудову,
Щоби краще   я  пізнала
Мою рідну мову.

Приспів:

Я  ту книжечку в крамниці
Вчора оглядала
І  сама вже слово "мама"
Голосно читала.

Там малюночки цікаві -
Пишні, кольорові.
"Буквар" зветься ота книжка
В нашій рідній мові.','["pisni.org.ua", "cat:pisni-pro-movy", "Пісні про рідну мову"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_15404'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_15404','Буквар','Купи мені, матусенько,
Книжечку чудову,
Щоби краще   я  пізнала
Мою рідну мову.

Приспів:

