Ми з України — сучасної вільної Спарти!

Приспів.');
INSERT OR REPLACE INTO song_links (id,song_id,title,url,kind,version_id,sort_order) VALUES ('pisniua_1538828_l1','pisniua_1538828','YouTube','https://www.youtube.com/watch?v=PuR0nEmoh10','video',NULL,1);
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1537000','Зірка','Музика: ROXOLANA Слова: ROXOLANA','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Засвітила зірка на небі,
Як гірко, не треба,
Не бери близько
До серця всі проблеми!
Там зірка на небі,
В обійми йди теплі!
Та й не бери близько
До серця всі проблеми!

Тиха ніч, зоряний шлях,
Всі зібрались по хатах,
І морози у вікні не лякають
Нас з тобою у ці дні!
Тихо так, чути лиш дзвін,
Що летить із дому у дім.
Як не встиг, не страшно,
Утім, загадай, що на душі!
Нехай радість
Прийде до нас всіх!
Хай світло світить у тобі!
Хай буде все, як хочеш ти!
Так, як хочеш ти!

Приспів.

Іди в мої обійми,
Тут тепло, як ніколи!
Спокійно, наче вдома,
А хуртовини за вікном...
Іди в мої обійми!
Ти можеш тут собою
Побути, скільки хочеш,
І не забудь бажання
Загадати! Ага!
Нехай радість
Прийде до нас всіх!
Хай світло світить у тобі!
Хай буде все, як хочеш ти!
Так, як хочеш ти!

Приспів.','["pisni.org.ua", "cat:suchasni-pisni-rizdvo", "Сучасні пісні про Різдвяні свята"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1537000'), datetime('now')),datetime('now'));
