INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1560707','Вітер вольний','Музика: Андрій Кравченко Слова: Андрій Кравченко','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'А я вийду в поле,
Стану вітром вольним!

Знаю силу правди,
Знаю смак поразки,
Та душа жива,
Хоч давно брела...
І життя рубало мене
Без підказки,
Я стояв, як камінь,
Не схилив чола!..

Приспів:
А я вийду в поле,
Стану вітром вольним
Та на повні груди,
Щоб не чули люди!
Ах, болить душа,
Болить не спіша,
Болить потихеньку
Моє серденько...
Моє серденько...

І не раз я падав —
Та вставав від болю!
Сивина на скронях —
Це як оберіг.
Розривали вітри
На широкім полі,
Був на дні не раз,
Але честь зберіг!..

Приспів.

А я вийду в поле,
Стану вітром вольним
Та на повні груди...

Приспів.','["pisni.org.ua", "cat:zahalni-cinnosti", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1560707'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_1560707','Вітер вольний','А я вийду в поле,
Стану вітром вольним!

Знаю силу правди,
Знаю смак поразки,
Та душа жива,
Хоч давно брела...
І життя рубало мене
Без підказки,
Я стояв, як камінь,
Не схилив чола!..

Приспів:
А я вийду в поле,
Стану вітром вольним
Та на повні груди,
Щоб не чули люди!
Ах, болить душа,
Болить не спіша,
Болить потихеньку
Моє серденько...
Моє серденько...

І не раз я падав —
Та вставав від болю!
Сивина на скронях —
Це як оберіг.
Розривали вітри
На широкім полі,
