INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1558323','Вітрила','Музика: MELOVIN, Vitalii Telezyn Слова: MELOVIN, Nataliia Dzenkiv','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Вітрила!..

Коли від всіх тікаю,
Турботи забуваю,
Навколо очі самоти...
Тобі я прошепочу,
Що знов відчути хочу,
Як разом із тобою ми!..
Ті два дні, як цілий рік,
Лиш вино і море втіх!..
Десь не вдома я прокинувся,
Знов згадав я, що ти є,
Дощ пройшов, і я знайшов тебе!..

Приспів:
Ти — мої вітрила, музика моя!
Невагомі крила підіймають в небо!
Дві частини серця — разом ти і я!
І мене не буде, і нема без тебе!
Без тебе нема!..

Не знаю, але вірю,
Душа плекає мрію,
Що шлях до тебе приведе!..
Земля летить все швидше,
За мить твоє обличчя
Мій погляд в натовпі знайде!..
Я тебе намалював,
Ніби все про тебе знав,
І наперед всі кроки відгадав.
Поклав перед воротами
Закритими, я тебе поклав...

Приспів.

І мене не буде...  |
І мене не буде...  |
І мене не буде...  |
І нема без тебе... | (2)

Мені так треба, так треба
Бути там, де зараз ти!..
Чи сісти в поїзд, зникнути
Від тебе - так треба!..
Те почуття росте й росте..
Для чого я знайшла тебе?..
Для чого я знайшов тебе?..','["pisni.org.ua", "cat:devoted", "cat:zahalni-cinnosti", "Пісні присвячені окремим особам", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1558323'), datetime('now')),datetime('now'));
