INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1555606','Півонії','Музика: Ivan Klymenko Слова: Ivan Klymenko','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Давай!.. Давай!..

Я - той спогад, що не забудеться!
Я - той шрам, що не загоїться!
Я, як тінь — її не торкнутися!
Не забудеш ніколи риси мого лиця!
Я - той спогад, що не забудеться!
Я - та мрія, що не може здійснитися!
Я, як фільм, що в голові крутиться!
Я - та ціль, за яку треба битися!

Приспів:
І ми знов в агонії,
На підлозі півонії,
Віддалися бажанню
І зливаємось в симфонію!..
Знов в агонії,
На підлозі півонії,
Віддалися бажанню
І зливаємось в симфонію!..
Давай!.. Давай!.. Давай!.. | (4)

Я - той секрет, що від тебе приховують!
Я - ті очі, що в себе закохують!
Я - та загадка, що зводить з розуму!
Я - той вибір, що змінює твоє життя!
Я - той секрет, що від тебе приховують!
Той урок, який точно засвоюють!
Я - та думка, що не дає спокою!
Я - та сама ніч, що тебе не відпуска!

Приспів.','["pisni.org.ua", "cat:devoted", "Пісні присвячені окремим особам"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1555606'), datetime('now')),datetime('now'));
