INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1563404','Коломийка','Музика: Євген Коваленко Слова: народні. Виконує: Кобза','uk','ukraine_before_1917',NULL,NULL,'авторське подання',NULL,'Ой, яка ти, чічка, файна,
