INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_15725','Від зими до зими','(Дванадцять місяців). Музика: Степан Козак Слова: Федір Петров','uk','ukraine_1991',NULL,NULL,'"Український шкільний пісенник. Випуск 4" (Львів - 2003)',NULL,'Січень січе,
Лютий лютує,
березень плаче,
квітень квітує.

Травень під ноги
стеле травицю,
червень складає
сіно в копиці.

Липень медовий
бджілок чарує.
Серпень чудовий
булки дарує.

Вересень трусить
груші в садочку,
жовтень гаптує
клену сорочку.

Йде листопад,
застеля килими.
Грудень надходить -
початок зими.
Ля...
Ля...
Грудень надходить -
початок зими.','["pisni.org.ua", "cat:dytyachi", "Дитячі пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_15725'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_15725','Від зими до зими','Січень січе,
