початок зими.');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1568505','Рідна Україно','Музика: Олександр Соколов Слова: Юрій Братиця','uk','ukraine_1991',NULL,NULL,'авторське подання (Олександр Соколов)','Пісню виконує Олена Червінчук.','Вийду, подивлюсь у вечірнє небо,
Світить ясно місяць, і зоря зійшла!
Я заплющу очі, помолюсь за тебе,
Рідна Україно, батьківська земля!..

Приспів:
Тільки Україна, дорогенька ненька,
Заспопоїть серце й  ніжно пригорне!
У гаю зеленім, у свого гніздечка,
Заспіває пташка, і печаль мине.

Я тепер далеко від рідного краю,
Живу на чужині вже багато літ.
За тебе молюся, для тебе співаю,
Про рідну країну, український рід.

Приспів.

Не такі тут ночі і не ті світанки,
З вечора й до ранку серденько щемить,
А чужа країна не загоїть рани,
Не ізцілить душу, що весь час сльозить...

Приспів.','["pisni.org.ua", "cat:emigration", "Пісні про еміґрацію"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1568505'), datetime('now')),datetime('now'));
