INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1566426','Ти поселилась у душі','Музика: Ірина Войтичук Слова: Ірина Войтичук','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Я цілую тебе очима,
Знаю кожен твій рух і дотик.
Пів життя уже за плечима,
А ти - досі мій наркотик...

Приспів:
Ти поселилась у душі і там живеш,
Думки мої перебираєш, шаленієш!..
Букети ніжності мені несеш,
Ти моїм серцем володієш!..

Там на небі високо за хмарами
Людям долі Бог роздавав,
Заселяв світ красивими парами,
І тебе мені подарував!..

Приспів. (2)','["pisni.org.ua", "cat:devoted", "cat:zahalni-cinnosti", "Пісні присвячені окремим особам", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1566426'), datetime('now')),datetime('now'));
