INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1582909','Христос воскрес!','Музика: Олена Риковська Слова: Віра Ворскло','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Сонце ллє тепло з небес,
