INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1568220','Чому','Музика: Антон Кукрі Слова: Володимир Дантес','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Приспів:
Чому мені вона сниться?..
Чому її хочеться?..
Чому не розлюбиться?..
Чому?.. Чому?.. Чому?..

Така, як вона,
Не для тебе, старий! -
Усі говорили мені.

