INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_160606','Нестримним потоком, чота за чотою','Українська народна пісня','uk','ukr_ssr_1919_1991',NULL,NULL,'1. Літопис УПА. Т. 25. — С. 427.','Anrzej: Текст доповнений і виправлений за джерелом 1.','Нестримним потоком, чота за чотою
Ідуть України сини,
Далекі від смутку, не близькі з журбою,
Несуть в серці радість вони.

Це "Сірі вовки" — ми залізнії чоти,
Боїв не страшний для нас вир.
У славному рейді, в орлиному льоті
Нас "Бистрий" веде командир.

Ідем ми на поклик народу до бою,
Нас кличуть далекі віки.
І запал несем, і відвагу з собою,
Незламні ми "Сірі вовки".

В Затуринськім лісі німоти, як зливи,
Повстанців хотіли розбить.
Та"Бистрий" побідно звідсіля нас вивів,
Бо "Сірих вовків" не зломить!

Під Львовом громили комуну уперто,
Були і над рідним Збручем.
Підем ми на Київ, хоч би навіть вмерти,
Із гордим свободи кличем.

На нас посилає комуна гармати,
На нас посила літаки,
Та серця палкого й вогнем не зламати,
Незламні ми "Сірі вовки".

І ми переможем, Вкраїни повстанці,
Бо з нами іде наш народ.
Вкраїну ми нашу, як сонце уранці,
Підіймем до щастя висот.    Голос 1','["pisni.org.ua", "cat:himny-marshi", "cat:istorychni", "cat:povstanski", "cat:suspilno-politychni", "Гимни та марші", "Історичні пісні", "Повстанські пісні", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_160606'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_160606','Нестримним потоком, чота за чотою','Нестримним потоком, чота за чотою
