INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_1583505','Лети','Музика: Анна Мегега Слова: Анна Мегега','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Якби я мала крила,
Злетіла високо за хмари!
Якби я мав вітрила,
Розправив їх у раз!
Та одному несила
В польоті дихати вітрами,
Лише коли двоє нас,
Світ зіграє джаз!
Глибоко вдихай!
Серцю довіряй!
Мріям двері відкривай!

Приспів:
Давай! Палай!
Зможеш свого ти досягти!
Твердо прямуєш до мети!
Бажай! Пірнай!
Тільки не бійся висоти!
Лети!

В день, коли здійсниться мрія,
Я буду поруч! В тебе вірю!
В час коли у хвилі здійснень
Зникне течія...
Я з тобою буду поряд!
Вхопи у натовпі мій погляд!
Друзі ми лише, коли
В щасті і біді!

Приспів.

Серед тисячі доріг
Оберемо ту, що веде до мрії!
Серед тисячі думок
Ми знайдемо свою!

Приспів.

Лети! Лети! Лети!','["pisni.org.ua", "cat:druzhba", "Пісні про дружбу"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_1583505'), datetime('now')),datetime('now'));
