INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_164220','Україна мила','Музика: Євген Шантир Слова: Євген Шантир. Виконує: Євген Шантир','uk','ukraine_before_1917',NULL,NULL,NULL,'Збірка пісень "КОРАБЛИК"','Україна мила - історичний шлях
Твій лежав в не рівних і тяжких боях,
Україна вільна - хай летять роки,
Всім твоїм героям - слава на віки!

Україна мила - в небі залюбки
Над тобою линуть білі голубки,
Україно ненька - ти одна така,
Безкорисно-щедра для життя ріка!

Україна мила - квітка у росі,
Ніжна і велична у своїй красі,
Україна - пісня про вишневий сад,
Про любов козацьку, юність і дівчат!

Україна мила - золоті хліба,
На твоїх просторах йде ще боротьба,
Україна рідна й серцю дорога,
Хай тобою править мудрості рука!','["pisni.org.ua", "cat:bardivski", "cat:kozacki", "cat:romansy", "cat:suspilno-politychni", "cat:zahalni-cinnosti", "Бардівські пісні", "Козацькі пісні", "Романси", "Суспільно-політичні пісні", "Пісні про загальнолюдські цінності"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_164220'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_164220','Україна мила','Україна мила - історичний шлях
Твій лежав в не рівних і тяжких боях,
Україна вільна - хай летять роки,
Всім твоїм героям - слава на віки!

Україна мила - в небі залюбки
Над тобою линуть білі голубки,
Україно ненька - ти одна така,
Безкорисно-щедра для життя ріка!

Україна мила - квітка у росі,
Ніжна і велична у своїй красі,
Україна - пісня про вишневий сад,
Про любов козацьку, юність і дівчат!

Україна мила - золоті хліба,
На твоїх просторах йде ще боротьба,
Україна рідна й серцю дорога,
Хай тобою править мудрості рука!');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_16000','Присвята Галицькому полку січових стрільців','Музика: Ігор Жук Слова: Ігор Жук. Виконує: Ігор Жук','uk','ukraine_1991',NULL,NULL,'1. Аудіозапис пісні "УСС". 2. http://bards.ru/archives/author.php?id=129','Основний текст взято з джерела [2]. Уточнено й доповнено за джерелом [1]. Акорди підібрано на слух, подано спрощено. Тональність ориґінальна. У пісні використано мотиви з відомої стрілецької пісні "Ой, у лузі червона калина": 1) "Вступ" - грається на мотив, що відповідає тексту: "А ми тую червону калину підіймемо, А ми нашу славну Україну, гей-гей, розвеселимо!" 2) "Програш 1" - варіація на ту ж тему, що і "Вступ". 3) "Програш 2" - грається на мотив, що відповідає тексту: "Ой, у лузі червона калина похилилася, Чогось наша славна Україна зажурилася. А ми тую червону калину підіймемо, А ми нашу славну Україну, гей-гей, розвеселимо!" Підбір акордів: bohdanko@pisni.org.ua','Вступ:  G

Низько схилилась калина, ніби молиться Богу,
Вітер за нами несе чи то пісню, чи то тугу...
Мамо, не треба, - не йдіть нас виглядати на дорогу,
Ой, ще не скоро нам коників пасти коло Бугу.

Програш 1:  C G E Am

Чути нам, чути, як рідний голос нас додому кличе;
Видно нам, видно біду, що наступає від Любліна.
Мамо, ми мусим бути тут, бо ми стрільці святої Січі;
Мамо, не майте нам за зле, бо тут так само - Україна.

Програш 1.

Хмарами круки злітаються з Поділля і з Полісся,
З Білої Церкви удосвіта на Фастів виступаєм.
Доля на долю, як шабля на шаблю, піднялися;
Хлопці, до бою! - ми свій полк докупи в небі позбираєм...

Програш 1.

Мало нас, мало, нас замало, аби край оборонити -
Тільки й надії - на шаблю, на серце і на Бога...
В Києві дзвони мовчать, бо нема об чім дзвонити -
Нашої віри нема, а чужа їм не підмога.

Програш 1.

Низько схилилась калина, ніби молиться Богу,
Вітер за нами несе чи то пісню, чи то тугу...
Мамо, не плачте, не йдіть нас виглядати на дорогу -  |
Ой, ще не скоро нам коників пасти коло Бугу!..       | (x2)

Програш 2:
М-м-м...
М-м-м...
А ми тую червону калину підіймемо,
А ми нашу славну Україну, гей-гей, розвеселимо!

Фінал:  C H Am','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_16000'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_16000','Присвята Галицькому полку січових стрільців','Вступ:  G

Низько схилилась калина, ніби молиться Богу,
Вітер за нами несе чи то пісню, чи то тугу...
Мамо, не треба, - не йдіть нас виглядати на дорогу,
Ой, ще не скоро нам коників пасти коло Бугу.

Програш 1:  C G E Am

Чути нам, чути, як рідний голос нас додому кличе;
Видно нам, видно біду, що наступає від Любліна.
Мамо, ми мусим бути тут, бо ми стрільці святої Січі;
Мамо, не майте нам за зле, бо тут так само - Україна.

Програш 1.

Хмарами круки злітаються з Поділля і з Полісся,
З Білої Церкви удосвіта на Фастів виступаєм.
Доля на долю, як шабля на шаблю, піднялися;
Хлопці, до бою! - ми свій полк докупи в небі позбираєм...

Програш 1.

Мало нас, мало, нас замало, аби край оборонити -
Тільки й надії - на шаблю, на серце і на Бога...
В Києві дзвони мовчать, бо нема об чім дзвонити -
Нашої віри нема, а чужа їм не підмога.

Програш 1.

Низько схилилась калина, ніби молиться Богу,
Вітер за нами несе чи то пісню, чи то тугу...
Мамо, не плачте, не йдіть нас виглядати на дорогу -  |
Ой, ще не скоро нам коників пасти коло Бугу!..       | (x2)

Програш 2:
М-м-м...
М-м-м...
А ми тую червону калину підіймемо,
А ми нашу славну Україну, гей-гей, розвеселимо!

Фінал:  C H Am');
INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_16303','Треба йти до осені','Музика: Олександр Білаш Слова: Степан Пушик','uk','ukraine_1991',NULL,NULL,'О. Білаш "Любисток" Київ "музична Україна" 1970',NULL,'Сіножаті скосяться,
І пшениця вижнеться,
Плотогонів Черемош пронесе.
Дзвонить осінь в Косові,       |
Дзвонить осінь в Вижниці,      | (2)
Перестиглі яблука нам несе.    |

Яблунева осене,
Що ж ти в росах росишся?
Де ж ти щастя, осене, роздаєш?
І гуляти хочеться,             |
І женитись хочеться,           | (2)
І дівчат в Карпатах не стає.   |

По багряній осені
Черемош, як шабелька,
І роса посивіла на мороз.
Переспілі яблука,              |
Дзвонять стиглі яблука,        | (2)
Осінь теж очікує чогось.       |

Сіножаті скосяться,
І пшениця вижнеться,
Листячком засипляться сади.
Може мила в Косові,            |
Може мила в Вижниці,           | (2)
Треба йти до осені, щоб знайти.|','["pisni.org.ua", "cat:krasa-pryrody", "Пісні про красу природи"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_16303'), datetime('now')),datetime('now'));
