INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_164202','Заспівай мені, Львове, востаннє','(Останній бал). Музика: Наталя Криничанка Слова: Наталя Криничанка. Виконує: Наталя Криничанка','uk','ukraine_1991',NULL,NULL,'Запис концерту в Києві 26 березня 2008 р.',NULL,'Заспівай, заспівай мені, Львове, востаннє -
Щось так довго і тяжко триває фінал.
Третій день за вікном вже пустої кав''ярні
Чорні коні везуть попелюшок на бал.

Заспівай, заспівай мені, Львове, сумної -
Вже птахи лопотять під дахами крильми.
Я прийму твої скарги усі до одної
І розділить нас ніч назавжди ворітьми.

Ти не плач, не пускай блискавиці за мною,
Не жени своїх левів мені навздогін.
Я повернусь на мить у портреті святою,
Як чергова окраса для замкових стін.

Вже за північ давно, оніміли гітари,
Черевичок розбився, кришталь затонкий.
Так галантно до танцю ведуть комісари,
Для останнього танцю і Львів затісний.

Заспівай, заспівай мені, Львове, востаннє -
Щось так довго і тяжко триває фінал.
Третій день за вікном вже пустої кав''ярні
Чорні коні везуть попелюшок на бал.','["pisni.org.ua", "cat:bardivski", "cat:istorychni", "cat:lviv", "Бардівські пісні", "Історичні пісні", "Пісні про Львів"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_164202'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_164202','Заспівай мені, Львове, востаннє','Заспівай, заспівай мені, Львове, востаннє -
