INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_163000','Я жінка','Музика: Неля Франчук. Виконує: Неля Франчук','uk','ukraine_1991',NULL,NULL,'1. http://ilink.com.ua/forum/showthread.php?p=58379 - текст 2. Аудіо-диск (демо)',NULL,'Я жінка. Я травина. Я роса.
Я без кохання - мов калина на морозі.
Як чорний шовк, м''яка моя коса,
Як дикий мед горенять мої сльози.

Я жінка. Я вродилася такою.
Це задля тебе в мене руки білі,
І голос плине тихою водою,
І материнством квітне моє тіло.

Я жінка. Я співуча, як струна.
Ти лиш торкни - і я озвуся синьо.
Тебе чекаючи, була віки одна
І хочу народити тобі сина.

Я жінка. Я травина. Я роса.
Залиш мене. Вернись до мене знову.
З любові народилася краса-
Народжувать і жить мені в любові.

Я жінка. Я травина. Я роса.
Я без кохання- мов калина на морозі.
Як чорний шовк, м''яка моя коса,
Як дикий мед горенять мої сльози.    Аудіо (короткий фрагмент, 32 kbps)','["pisni.org.ua", "cat:bardivski", "Бардівські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_163000'), datetime('now')),datetime('now'));
