INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_16606','Зеленая дібровонька','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,'Бібліотека поета. Народна Лірика.',NULL,'Зеленая та дібровонька,
Чого в тебе так пеньків много?
Чого в тебе так пеньків много,
Зеленого ані одного?
Та всі такі, що рубатися,
А нікому розвиватися.
Молодая та Марусино,
Чого в тебе так батьків много,
Чого в тебе так батьків много,
А рідного ні одного?
Та всі такі, що напитися,
А нікому зажуритися.','["pisni.org.ua", "cat:vesilni", "Весільні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_16606'), datetime('now')),datetime('now'));
