INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_160909','Да давай, мати, давай','Українська народна пісня. Виконує: Раїса Цапун','uk','ukraine_1991',NULL,'2002','Надала Раїса Цапун','*Всі в''язки виконуються за взірцем першої. Записано 2002 р. Р. Цапун від Домініки Савич в с. Нобель Зарічненського р-ну Рівненської області. Діалектизми: кросна - ткацький верстат.','Да давай, мати, давай, гой,
Да давай мати, давай,
Меншиї ни зоставляй.*

Меншая ни стараласа, гой, |(2)
На печи витягалася.

На печи кросна ткала, гой |(2)
На полицу ноги клала.

На полицу ноги клала, гой |(2)
Із полици хліба крала.

Давай, мати, рогожу, гой  |(2)
