INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_171127','Нічка темненькая','Українська народна пісня','uk','ukraine_before_1917',NULL,NULL,NULL,NULL,'Нічка така темненькая боюсь до дому йти,
А милий мій розсердився не хоче провести.
А потім став тай подумав тай каже - проведу,
А я йому відповіла - сама до дому йду.

Приходжу я до домоньку тай стукаю у вікно
Мати моя старенькая не спить давним-давно.
Доню моя рідненькая де ж ти всю ніч була?
Чому очка заплакані розплетена коса?

Мамо моя рідненькая в подружки я була
Косу мою русявую подружка розплела.
Доню моя, рідненькая, іди з мого двора
Шукай собі чорнявого що звів тебе з ума.','["pisni.org.ua", "cat:all-ukraine", "Загальноукраїнські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_171127'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_171127','Нічка темненькая','Нічка така темненькая боюсь до дому йти,
А милий мій розсердився не хоче провести.
А потім став тай подумав тай каже - проведу,
А я йому відповіла - сама до дому йду.

Приходжу я до домоньку тай стукаю у вікно
Мати моя старенькая не спить давним-давно.
Доню моя рідненькая де ж ти всю ніч була?
