INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_164828','Гламур','Музика: Андрій Кузьменко Слова: Андрій Кузьменко. Виконує: Скрябін','uk','ukraine_1991',NULL,NULL,'аудіозапис',NULL,'Двері відкриваються, всьо починається,
Столики ламаються і місця нема.
Лампи ледве блимають, дівчата кліпають,
Хлопці їх пощипують і просять вина.
Пафосні, напудрені, чучуть обкурені,
Скучно роздивляються на світлі бокал.
Дами з депутатами майже, як з татами
Плавно направляються у віповський зал.

Приспів:
Мур, мур, мур, ми любим гламур,
Напшикаєм духами і зробим педікюр.
Мур, мур, мур, ми любим гламур,
Всьо гниле сховаєм під майку від кутюр.

Блєском і помадами сидять намазані
Тимчасові подруги серйозних мужчин.
Пальці з манікюрами, а дури дурами -
Їх життя: машина, фітнесклуб, магазин.
Руки з телефонами тонкими, новими,
Скучними розмовами - малишка мур, мур.
Мускули накачані, гроші потрачені,
Всьо навколо схвачено - ми любим гламур.

Приспів. (3)','["pisni.org.ua", "cat:suspilno-politychni", "Суспільно-політичні пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_164828'), datetime('now')),datetime('now'));
