INSERT OR REPLACE INTO songs (id,title,subtitle,lang,country,period,year,source,notes,lyrics,tags_json,lang_locked,status,created_at,updated_at) VALUES ('pisniua_166323','Вечірнє сонце','Музика: Ольга Богомолець Слова: Ліна Костенко. Виконує: Ольга Богомолець, Оксана Муха','uk','ukraine_1991',NULL,NULL,'альбом "Kairos"',NULL,'Вечірнє сонце, дякую за день,
Вечірнє сонце, дякую за втому,
За тих лісів просвітлений едем,
І за волошку в житті золотому.

За твій світанок, і за твій зеніт,
І за мої обпечені зеніти,
За те, що завтра буде зеленіть,
За те, що вчора встигло одзвеніти.

За небо в небі, за дитячий смiх,
За те, що можу і за те, що мушу.
Вечірнє сонце, дякую за тих,
Котрі нічим не осквернили душу.

За те, що завтра жде своїх натхнень,
Що десь у світі кров ще не пролито.
Вечірнє сонце, дякую за день,
За цю потребу пісні, як молитви.','["pisni.org.ua", "cat:bardivski", "cat:philosophic", "Бардівські пісні", "Філософські пісні"]',1,'published',COALESCE((SELECT created_at FROM songs WHERE id='pisniua_166323'), datetime('now')),datetime('now'));
INSERT OR REPLACE INTO songs_fts(song_id,title,lyrics) VALUES ('pisniua_166323','Вечірнє сонце','Вечірнє сонце, дякую за день,
